def test_provider_smoke_defaults_defer_to_configured_kokoro_voice():
    assert ProviderSmokeRunRequest().voice is None
    assert ProviderSmokeRunRequest().include_gemma is False
    assert AutonomousStudioPassRequest().provider_smoke_voice is None


def test_worker_requests_default_to_non_gemma_provider_path():
    run_id = uuid4()
    assert AgentWorkerRunRequest(run_id=run_id).use_gemma is False
    assert AgentWorkerCycleRequest(run_id=run_id).use_gemma is False
    assert RunResumeRequest().use_gemma is False
    assert AutonomousStudioPassRequest().use_gemma is False
    assert WorkerProfile(run_id=run_id, name="Default worker").use_gemma is False
    assert WorkerProfileCreate(name="Default worker").use_gemma is False
    assert AutopilotLaunchRequest().use_gemma is False


def _contains_string_value_prefix(value, prefix: str) -> bool:
    if isinstance(value, str):
        return value.startswith(prefix)
    if isinstance(value, dict):
        return any(
            _contains_string_value_prefix(item, prefix) for item in value.values()
        )
    if isinstance(value, list):
        return any(_contains_string_value_prefix(item, prefix) for item in value)
    return False


class FakeStore:
    def __init__(self):
        self.run = RunState(goal="Build a source-backed reel")
        self.runs = {self.run.run_id: self.run}
        self.events: list[RunEvent] = []
        self.agent_messages = []
        self.turns = []
        self.sources = []
        self.claims = []
        self.artifacts = []
        self.guardrail_audits = []
        self.run_checkpoints = []
        self.realtime_sessions = []
        self.feedback = []
        self.memories = []
        self.worker_profiles = []
        self.retrieval_quality_results = []
        self.retrieval_candidates = []
        self.retrieval_rerank_decisions = []
        self.knowledge_graph_nodes = []
        self.knowledge_graph_edges = []
        self.retrieval_evaluations = []
        self.status_updates: list[RunStatus] = []

    async def create_run(self, run):
        self.run = run
        self.runs[run.run_id] = run
        return run

    async def get_run(self, run_id):
        return self.runs.get(run_id)

    async def append_event(self, event):
        event.event_id = len(self.events) + 1
        self.events.append(event)
        return event

    async def append_event_if_absent(self, event, *, idempotency_key):
        if not idempotency_key.strip():
            raise ValueError("idempotency_key is required")
        for existing in self.events:
            if (
                existing.run_id == event.run_id
                and existing.event_type == event.event_type
                and existing.payload.get("event_idempotency_key") == idempotency_key
            ):
                return existing
        event.payload = {
            **event.payload,
            "event_idempotency_key": idempotency_key,
        }
        return await self.append_event(event)

    async def find_event_by_voice_agent_event_uid(
        self,
        run_id,
        event_type,
        voice_agent_event_uid,
    ):
        for event in reversed(self.events):
            if (
                event.run_id == run_id
                and event.event_type == event_type
                and event.payload.get("voice_agent_event_uid")
                == voice_agent_event_uid
            ):
                return event
        return None

    async def update_run_status(self, run_id, status):
        self.status_updates.append(status)
        run = self.runs.get(run_id)
        if run is not None:
            run.status = status
            if self.run.run_id == run_id:
                self.run = run

    async def record_conversation_turn(self, turn):
        self.turns.append(turn)
        return turn

    async def update_conversation_turn(self, turn):
        for index, existing in enumerate(self.turns):
            if existing.turn_id == turn.turn_id and existing.run_id == turn.run_id:
                self.turns[index] = turn
                return turn
        return None

    async def promote_voice_user_transcript_if_pending(
        self,
        turn,
        *,
        voice_turn_id,
    ):
        existing = await self.find_voice_agent_conversation_turn(
            turn.run_id,
            speaker="user",
            voice_turn_id=voice_turn_id,
        )
        if existing is None:
            return None
        if existing.metadata.get("transcript_status") == "final":
            return None
        if turn.transcript == "Live audio turn committed; transcript pending.":
            return None
        merged_metadata = dict(existing.metadata)
        merged_metadata.update(
            {key: value for key, value in turn.metadata.items() if value is not None}
        )
        merged_metadata.update(
            {
                "transcript_status": "final",
                "transcript_promoted_from_pending": True,
                "transcript_promoted_event_id": turn.metadata.get(
                    "voice_agent_event_id"
                ),
                "transcript_source": "voice_user_turn_committed",
            }
        )
        promoted = existing.model_copy(
            update={
                "transcript": turn.transcript,
                "audio_uri": turn.audio_uri or existing.audio_uri,
                "metadata": merged_metadata,
            }
        )
        return await self.update_conversation_turn(promoted)

    async def list_conversation_turns(self, run_id, limit=100):
        return [turn for turn in self.turns if turn.run_id == run_id][:limit]

    async def list_recent_conversation_turns(self, run_id, limit=100):
        return [
            turn for turn in reversed(self.turns) if turn.run_id == run_id
        ][:limit]

    async def find_voice_agent_conversation_turn(
        self,
        run_id,
        *,
        speaker,
        voice_turn_id=None,
        response_id=None,
    ):
        for turn in reversed(self.turns):
            if turn.run_id != run_id or turn.speaker != speaker:
                continue
            metadata = turn.metadata or {}
            if voice_turn_id and metadata.get("voice_agent_turn_id") == voice_turn_id:
                return turn
            if response_id and metadata.get("voice_agent_response_id") == response_id:
                return turn
        return None

    async def record_voice_agent_conversation_turn_if_absent(
        self,
        turn,
        *,
        voice_turn_id=None,
        response_id=None,
    ):
        existing = await self.find_voice_agent_conversation_turn(
            turn.run_id,
            speaker=turn.speaker,
            voice_turn_id=voice_turn_id,
            response_id=response_id,
        )
        if existing is not None:
            return None
        self.turns.append(turn)
        return turn

    async def record_realtime_session(self, session):
        self.realtime_sessions.append(session)
        return session

    async def get_realtime_session(self, realtime_session_id):
        for session in self.realtime_sessions:
            if session.realtime_session_id == realtime_session_id:
                return session
        return None

    async def list_realtime_sessions(self, run_id):
        return [
            session for session in self.realtime_sessions if session.run_id == run_id
        ]

    async def update_realtime_session_status(self, realtime_session_id, status):
        session = await self.get_realtime_session(realtime_session_id)
        if session is None:
            return None
        session.status = status
        return session

    async def list_events(self, run_id, limit=100, after_event_id=None, latest=False):
        events = [
            event
            for event in self.events
            if event.run_id == run_id
            and (
                after_event_id is None
                or (event.event_id is not None and event.event_id > after_event_id)
            )
        ]
        if latest and after_event_id is None:
            return events[-limit:]
        return events[:limit]

    async def list_events_by_type(
        self,
        run_id,
        event_type,
        limit=100,
        latest=False,
    ):
        events = [
            event
            for event in self.events
            if event.run_id == run_id and event.event_type == event_type
        ]
        if latest:
            return events[-limit:]
        return events[:limit]

    async def record_run_checkpoint(self, checkpoint):
        self.run_checkpoints.append(checkpoint)
        return checkpoint

    async def list_run_checkpoints(self, run_id, limit=25):
        return [
            checkpoint
            for checkpoint in self.run_checkpoints
            if checkpoint.run_id == run_id
        ][:limit]

    async def record_agent_message(self, message):
        ensure_message_accepted_trace(message)
        for index, existing in enumerate(self.agent_messages):
            if existing.message_id == message.message_id:
                self.agent_messages[index] = message
                return message
        self.agent_messages.append(message)
        return message

    async def record_agent_message_if_absent(self, message):
        ensure_message_accepted_trace(message)
        for existing in self.agent_messages:
            if existing.message_id == message.message_id:
                return None
        self.agent_messages.append(message)
        return message

    async def update_agent_message_payload(self, message_id, payload, *, updated_at=None):
        for index, message in enumerate(self.agent_messages):
            if message.message_id == message_id:
                updated = message.model_copy(
                    update={
                        "payload": payload,
                        "updated_at": updated_at or datetime.now(timezone.utc),
                    }
                )
                self.agent_messages[index] = updated
                return updated
        return None

    async def list_agent_messages(
        self,
        run_id,
        agent_id=None,
        direction="all",
        status=None,
        limit=200,
    ):
        messages = self.agent_messages
        if agent_id and direction == "inbox":
            messages = [
                message
                for message in messages
                if message.recipient_agent_id == agent_id
            ]
        elif agent_id and direction == "outbox":
            messages = [
                message for message in messages if message.sender_agent_id == agent_id
            ]
        elif agent_id:
            messages = [
                message
                for message in messages
                if message.sender_agent_id == agent_id
                or message.recipient_agent_id == agent_id
            ]
        if status:
            messages = [message for message in messages if message.status == status]
        return messages[:limit]

    async def get_agent_message(self, message_id):
        for message in self.agent_messages:
            if message.message_id == message_id:
                return message
        return None

    async def try_claim_agent_message(self, message_id, *, agent_id):
        message = await self.get_agent_message(message_id)
        messages_by_id = {
            existing.message_id: existing for existing in self.agent_messages
        }
        if (
            message is None
            or message.recipient_agent_id != agent_id
            or message.status != AgentTaskStatus.ACCEPTED
            or message.attempt_count >= message.max_attempts
            or any(
                messages_by_id.get(dependency_id) is None
                or messages_by_id[dependency_id].status
                != AgentTaskStatus.COMPLETED
                for dependency_id in message.depends_on_message_ids
            )
        ):
            return None
        message.status = AgentTaskStatus.CLAIMED
        message.claimed_by_agent_id = agent_id
        message.attempt_count += 1
        message.result = {}
        message.error = None
        append_handoff_trace(
            message,
            actor=agent_id,
            action="claimed",
            status=AgentTaskStatus.CLAIMED,
            notes="Worker atomically claimed task for durable execution.",
            metadata={"message_id": str(message_id)},
        )
        return message

    async def recover_stale_agent_messages(
        self,
        run_id,
        *,
        stale_before,
        statuses,
        agent_id=None,
        limit=25,
        recovery_actor="agent-harness-engineer",
    ):
        recovered = []
        for message in sorted(self.agent_messages, key=lambda item: item.updated_at):
            if len(recovered) >= limit:
                break
            if message.run_id != run_id:
                continue
            if agent_id is not None and message.recipient_agent_id != agent_id:
                continue
            if message.status not in set(statuses):
                continue
            if message.updated_at >= stale_before:
                continue
            previous_status = message.status
            previous_claimed_by_agent_id = message.claimed_by_agent_id
            previous_updated_at = message.updated_at
            message.status = AgentTaskStatus.ACCEPTED
            message.claimed_by_agent_id = None
            message.result = {
                **message.result,
                "stale_recovery": {
                    "recovered_by": recovery_actor,
                    "previous_status": previous_status.value,
                    "previous_claimed_by_agent_id": previous_claimed_by_agent_id,
                    "previous_updated_at": previous_updated_at.isoformat(),
                },
            }
            message.error = None
            message.updated_at = datetime.now(timezone.utc)
            append_handoff_trace(
                message,
                actor=recovery_actor,
                action="stale_recovered",
                status=AgentTaskStatus.ACCEPTED,
                notes="Recovered stale claimed/in-progress task for reprocessing.",
                metadata={"stale_before": stale_before.isoformat()},
            )
            recovered.append(
                {
                    "message": message,
                    "from_status": previous_status,
                    "previous_claimed_by_agent_id": previous_claimed_by_agent_id,
                    "previous_updated_at": previous_updated_at,
                }
            )
        return recovered

    async def block_exhausted_agent_messages(
        self,
        run_id,
        *,
        agent_id=None,
        limit=25,
        recovery_actor="agent-harness-engineer",
    ):
        blocked = []
        for message in sorted(self.agent_messages, key=lambda item: item.updated_at):
            if len(blocked) >= limit:
                break
            if message.run_id != run_id:
                continue
            if agent_id is not None and message.recipient_agent_id != agent_id:
                continue
            if message.status != AgentTaskStatus.ACCEPTED:
                continue
            if message.attempt_count < message.max_attempts:
                continue
            message.status = AgentTaskStatus.BLOCKED
            if message.claimed_by_agent_id is None:
                message.claimed_by_agent_id = message.recipient_agent_id
            message.result = {
                **message.result,
                "retry_policy": {
                    "blocked_by": recovery_actor,
                    "attempt_count": message.attempt_count,
                    "max_attempts": message.max_attempts,
                },
            }
            message.error = "A2A task exhausted retry attempts."
            message.updated_at = datetime.now(timezone.utc)
            append_handoff_trace(
                message,
                actor=recovery_actor,
                action="retry_exhausted_blocked",
                status=AgentTaskStatus.BLOCKED,
                notes="Blocked task after durable retry attempts were exhausted.",
            )
            blocked.append(message)
        return blocked

    async def update_agent_message_status(
        self,
        message_id,
        status,
        agent_id,
        result=None,
        notes=None,
        error=None,
    ):
        message = await self.get_agent_message(message_id)
        if message is None:
            return None
        message.status = status
        if message.claimed_by_agent_id is None:
            message.claimed_by_agent_id = agent_id
        message.result = result or {}
        message.error = error
        append_handoff_trace(
            message,
            actor=agent_id,
            action="status_updated",
            status=status,
            notes=notes or error,
            metadata={"message_id": str(message_id), "has_result": bool(result)},
        )
        return message

    async def authorize_agent_message_retry(
        self,
        message_id,
        *,
        agent_id,
        reason,
        reset_attempt_count=True,
        max_attempts=None,
    ):
        message = await self.get_agent_message(message_id)
        if message is None:
            return None
        message.status = AgentTaskStatus.ACCEPTED
        message.claimed_by_agent_id = None
        if reset_attempt_count:
            message.attempt_count = 0
        if max_attempts is not None:
            message.max_attempts = max_attempts
        message.result = {
            **message.result,
            "retry_authorization": {
                "authorized_by": agent_id,
                "reason": reason,
                "reset_attempt_count": reset_attempt_count,
                "authorized_max_attempts": max_attempts,
            },
        }
        message.error = None
        message.updated_at = datetime.now(timezone.utc)
        append_handoff_trace(
            message,
            actor=agent_id,
            action="retry_authorized",
            status=AgentTaskStatus.ACCEPTED,
            notes=reason,
            metadata={
                "reset_attempt_count": reset_attempt_count,
                "authorized_max_attempts": max_attempts,
            },
        )
        return message

    async def repair_agent_message_dependencies(
        self,
        message_id,
        *,
        agent_id,
        remove_dependency_message_ids,
        reason,
    ):
        message = await self.get_agent_message(message_id)
        if message is None:
            return None
        requested_dependency_ids = set(remove_dependency_message_ids)
        removed_dependency_ids = [
            dependency_id
            for dependency_id in message.depends_on_message_ids
            if dependency_id in requested_dependency_ids
        ]
        if not removed_dependency_ids:
            return message
        removed_dependency_id_set = set(removed_dependency_ids)
        remaining_dependency_ids = [
            dependency_id
            for dependency_id in message.depends_on_message_ids
            if dependency_id not in removed_dependency_id_set
        ]
        message.depends_on_message_ids = remaining_dependency_ids
        if message.status == AgentTaskStatus.ACCEPTED:
            message.claimed_by_agent_id = None
        message.result = {
            **message.result,
            "dependency_repair": {
                "repaired_by": agent_id,
                "reason": reason,
                "removed_dependency_message_ids": [
                    str(dependency_id) for dependency_id in removed_dependency_ids
                ],
                "remaining_dependency_message_ids": [
                    str(dependency_id) for dependency_id in remaining_dependency_ids
                ],
                "repaired_at": datetime.now(timezone.utc).isoformat(),
            },
        }
        message.updated_at = datetime.now(timezone.utc)
        append_handoff_trace(
            message,
            actor=agent_id,
            action="dependencies_repaired",
            status=message.status,
            notes=reason,
            metadata={
                "removed_dependency_message_ids": [
                    str(dependency_id) for dependency_id in removed_dependency_ids
                ],
                "remaining_dependency_message_ids": [
                    str(dependency_id) for dependency_id in remaining_dependency_ids
                ],
            },
        )
        return message

    async def record_feedback(self, feedback):
        for index, existing in enumerate(self.feedback):
            if existing.feedback_id == feedback.feedback_id:
                self.feedback[index] = feedback
                return feedback
        self.feedback.append(feedback)
        self.run.feedback_item_ids.append(feedback.feedback_id)
        return feedback

    async def record_feedback_if_absent(self, feedback):
        for existing in self.feedback:
            if existing.feedback_id == feedback.feedback_id:
                return None
        self.feedback.append(feedback)
        self.run.feedback_item_ids.append(feedback.feedback_id)
        return feedback

    async def get_feedback(self, feedback_id):
        for feedback in self.feedback:
            if feedback.feedback_id == feedback_id:
                return feedback
        return None

    async def list_feedback(self, run_id, status=None):
        feedback_items = [
            feedback for feedback in self.feedback if feedback.run_id == run_id
        ]
        if status:
            feedback_items = [
                feedback for feedback in feedback_items if feedback.status == status
            ]
        return feedback_items

    async def update_feedback_status(
        self,
        feedback_id,
        status,
        resolver,
        resolution_notes=None,
    ):
        feedback = await self.get_feedback(feedback_id)
        if feedback is None:
            return None
        feedback.status = status
        feedback.resolved_by = resolver
        feedback.resolution_notes = resolution_notes
        if status in {FeedbackStatus.RESOLVED, FeedbackStatus.REJECTED}:
            feedback.resolved_at = datetime.now(timezone.utc)
        feedback.updated_at = datetime.now(timezone.utc)
        return feedback

    async def record_source(self, source):
        self.sources.append(source)
        self.run.source_record_ids.append(source.source_id)
        return source

    async def list_sources(self, run_id):
        return self.sources

    async def record_claim(self, claim):
        self.claims.append(claim)
        return claim

    async def list_claims(self, run_id):
        return self.claims

    async def update_claim(self, claim):
        for index, existing in enumerate(self.claims):
            if existing.claim_id == claim.claim_id:
                self.claims[index] = claim
                return claim
        return None

    async def record_artifact(self, artifact):
        self.artifacts.append(artifact)
        self.run.artifact_ids.append(artifact.artifact_id)
        return artifact

    async def record_artifact_if_absent(self, artifact):
        for existing in self.artifacts:
            if existing.artifact_id == artifact.artifact_id:
                return None
        self.artifacts.append(artifact)
        self.run.artifact_ids.append(artifact.artifact_id)
        return artifact

    async def list_artifacts(self, run_id):
        return self.artifacts

    async def update_artifact(self, artifact):
        for index, existing in enumerate(self.artifacts):
            if existing.artifact_id == artifact.artifact_id:
                self.artifacts[index] = artifact
                return artifact
        return None

    async def record_retrieval_quality_result(self, result):
        self.retrieval_quality_results.append(result)
        self.retrieval_candidates.extend(result.candidates)
        self.retrieval_rerank_decisions.extend(
            {
                "candidate_id": candidate.candidate_id,
                "accepted_for_context": candidate.accepted_for_context,
                "rerank_score": candidate.rerank_score,
                "reranker": candidate.reranker,
                "reason": candidate.rerank_reason,
            }
            for candidate in result.candidates
        )
        self.knowledge_graph_nodes.extend(result.graph_coverage)
        self.knowledge_graph_edges.extend(
            {
                "from_node_id": entry.node_id,
                "to_node_id": f"source:{source_id}",
                "relationship": (
                    "supported_by"
                    if entry.coverage_status == "covered"
                    else "candidate_evidence"
                ),
                "confidence": 1.0 if entry.coverage_status == "covered" else 0.35,
            }
            for entry in result.graph_coverage
            if entry.node_type == "claim"
            for source_id in entry.source_ids
        )
        self.retrieval_evaluations.append(
            {
                "topic": result.topic,
                "status": result.status.value,
                "candidate_count": result.candidate_count,
                "accepted_candidate_count": result.accepted_candidate_count,
            }
        )

    async def record_guardrail_audit(self, audit):
        self.guardrail_audits.append(audit)
        return audit

    async def list_guardrail_audits(self, run_id, artifact_id=None):
        audits = self.guardrail_audits
        if artifact_id:
            audits = [audit for audit in audits if audit.artifact_id == artifact_id]
        return audits

    async def record_memory(self, memory):
        self.memories.append(memory)
        return memory

    async def list_memories(self, agent_id=None, run_id=None):
        memories = self.memories
        if agent_id:
            memories = [memory for memory in memories if memory.agent_id == agent_id]
        if run_id:
            memories = [memory for memory in memories if memory.run_id == run_id]
        return memories

    async def search_memories(
        self,
        agent_id=None,
        run_id=None,
        include_global_memories=True,
        query_embedding=None,
        limit=10,
    ):
        memories = self.memories
        if agent_id:
            memories = [memory for memory in memories if memory.agent_id == agent_id]
        if run_id and include_global_memories:
            memories = [
                memory for memory in memories if memory.run_id in {run_id, None}
            ]
        elif run_id:
            memories = [memory for memory in memories if memory.run_id == run_id]
        scored = [
            (_memory, _distance(query_embedding, _memory.embedding))
            for _memory in memories
        ]
        scored.sort(key=lambda item: (item[1] is None, item[1] or 0.0))
        return scored[:limit]

    async def record_worker_profile(self, profile):
        self.worker_profiles.append(profile)
        return profile

    async def list_worker_profiles(self, run_id):
        return [profile for profile in self.worker_profiles if profile.run_id == run_id]

    async def list_due_worker_profiles(self, limit=25, run_id=None, execution_mode=None):
        now = datetime.now(timezone.utc)
        due_profiles = []
        for profile in self.worker_profiles:
            if run_id is not None and profile.run_id != run_id:
                continue
            if execution_mode is not None and profile.execution_mode != execution_mode:
                continue
            if profile.status != WorkerProfileStatus.ACTIVE:
                continue
            if (
                profile.heartbeat_lease_until is not None
                and profile.heartbeat_lease_until > now
            ):
                continue
            if profile.last_heartbeat_at is None:
                due_profiles.append(profile)
                continue
            elapsed = (now - profile.last_heartbeat_at).total_seconds()
            if elapsed >= profile.poll_interval_seconds:
                due_profiles.append(profile)
        return due_profiles[:limit]

    async def get_worker_profile(self, profile_id):
        for profile in self.worker_profiles:
            if profile.profile_id == profile_id:
                return profile
        return None

    async def update_worker_profile_status(self, profile_id, status):
        profile = await self.get_worker_profile(profile_id)
        if profile is None:
            return None
        profile.status = status
        return profile

    async def try_claim_worker_profile_heartbeat(
        self,
        profile_id,
        *,
        claimed_by,
        lease_seconds,
    ):
        profile = await self.get_worker_profile(profile_id)
        if profile is None or profile.status != WorkerProfileStatus.ACTIVE:
            return None
        now = datetime.now(timezone.utc)
        if profile.heartbeat_lease_until and profile.heartbeat_lease_until > now:
            return None
        profile.heartbeat_claimed_at = now
        profile.heartbeat_claimed_by = claimed_by
        profile.heartbeat_lease_until = now + timedelta(seconds=lease_seconds)
        return profile

    async def record_worker_profile_heartbeat(self, profile_id):
        profile = await self.get_worker_profile(profile_id)
        if profile is None:
            return None
        profile.last_heartbeat_at = datetime.now(timezone.utc)
        profile.heartbeat_claimed_at = None
        profile.heartbeat_claimed_by = None
        profile.heartbeat_lease_until = None
        return profile


