def _record_test_retrieval_quality_ledger(
    store,
    *,
    accepted_source_ids,
    rejected_source_ids=None,
    topic="accepted retrieval evidence",
):
    rejected_source_ids = rejected_source_ids or []
    source_by_id = {source.source_id: source for source in store.sources}
    candidates = []
    for rank, source_id in enumerate(
        [*accepted_source_ids, *rejected_source_ids],
        start=1,
    ):
        source = source_by_id[source_id]
        accepted = source_id in set(accepted_source_ids)
        candidates.append(
            {
                "candidate_id": f"source:{source.source_id}",
                "source_id": str(source.source_id),
                "citation_id": source.citation_id,
                "title": source.title,
                "url": str(source.url),
                "fused_rank": rank,
                "rerank_score": 0.95 if accepted else 0.24,
                "reranker": "test_reranker",
                "rerank_reason": (
                    "accepted test evidence"
                    if accepted
                    else "not accepted for context"
                ),
                "accepted_for_context": accepted,
                "precision_risks": [] if accepted else ["low precision"],
                "recall_risks": [],
                "coverage_topics": [topic] if accepted else [],
            }
        )
    artifact = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.RETRIEVAL_QUALITY_LEDGER,
        title="Retrieval quality ledger",
        uri="artifact://runs/test/retrieval-quality-ledger",
        content={
            "status": "ready" if accepted_source_ids else "blocked",
            "topic": topic,
            "candidate_count": len(candidates),
            "accepted_candidate_count": len(accepted_source_ids),
            "reranked_candidate_count": len(candidates),
            "graph_node_count": len(candidates),
            "precision_risk_count": len(rejected_source_ids),
            "recall_gap_count": 0 if accepted_source_ids else 1,
            "coverage_gap_count": 0,
            "recommended_queries": [],
            "summary": "Test retrieval evidence ledger.",
            "candidates": candidates,
        },
        provenance={"workflow": "retrieval_quality_ledger_v1"},
        source_ids=list(accepted_source_ids),
    )
    asyncio.run(store.record_artifact(artifact))
    return artifact


def _distance(query_embedding, memory_embedding):
    if not query_embedding or not memory_embedding:
        return None
    return sum(
        (float(query_value) - float(memory_value)) ** 2
        for query_value, memory_value in zip(query_embedding, memory_embedding)
    ) ** 0.5


