def test_a2a_retry_and_dependency_events_redact_task_type_and_reason_without_real_database():
    store = FakeStore()
    fake_hf_token = "hf_" + ("l" * 30)
    fake_tavily_key = "tvly-" + ("m" * 30)
    bearer = "Bearer " + ("n" * 30)
    retry_message = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="intent-router",
        recipient_agent_id="content-strategist",
        task_type=f"retry_content {bearer}",
        status=AgentTaskStatus.BLOCKED,
        result={"retry_policy": {"attempt_count": 3, "max_attempts": 3}},
        attempt_count=3,
        max_attempts=3,
        error="blocked before retry",
    )
    dependency = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="content-strategist",
        recipient_agent_id="web-research-agent",
        task_type="dependency source",
        status=AgentTaskStatus.ACCEPTED,
    )
    repair_message = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="web-research-agent",
        recipient_agent_id="claim-verification-agent",
        task_type=f"repair_claim {fake_tavily_key}",
        depends_on_message_ids=[dependency.message_id],
        status=AgentTaskStatus.ACCEPTED,
    )
    asyncio.run(store.record_agent_message(retry_message))
    asyncio.run(store.record_agent_message(dependency))
    asyncio.run(store.record_agent_message(repair_message))

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        retry_response = client.post(
            f"/api/a2a/messages/{retry_message.message_id}/retry",
            json={
                "agent_id": "agent-harness-engineer",
                "reason": f"retry reason includes {fake_hf_token} and {bearer}",
                "reset_attempt_count": True,
                "max_attempts": 4,
            },
        )
        repair_response = client.post(
            f"/api/a2a/messages/{repair_message.message_id}/dependencies/repair",
            json={
                "agent_id": "agent-harness-engineer",
                "remove_dependency_message_ids": [str(dependency.message_id)],
                "reason": f"repair reason includes {fake_tavily_key} and {bearer}",
            },
        )
    finally:
        app.dependency_overrides.clear()

    assert retry_response.status_code == 200
    assert repair_response.status_code == 200
    retry_event = next(
        event
        for event in store.events
        if event.event_type == "agent_message_retry_authorized"
    )
    repair_event = next(
        event
        for event in store.events
        if event.event_type == "agent_message_dependencies_repaired"
    )
    serialized_events = json.dumps([retry_event.payload, repair_event.payload])

    assert retry_event.payload["message_id"] == str(retry_message.message_id)
    assert retry_event.payload["previous_attempt_count"] == 3
    assert retry_event.payload["attempt_count"] == 0
    assert repair_event.payload["message_id"] == str(repair_message.message_id)
    assert repair_event.payload["removed_dependency_message_ids"] == [
        str(dependency.message_id)
    ]
    assert fake_hf_token not in serialized_events
    assert fake_tavily_key not in serialized_events
    assert bearer not in serialized_events
    assert "hf_[redacted]" in serialized_events
    assert "tvly-[redacted]" in serialized_events
    assert "Bearer [redacted]" in serialized_events


