        feedback = payload["feedback"]
        metadata = feedback["metadata"]
        assert feedback["target_agent_id"] == "content-strategist"
        assert metadata["target_artifact_selection"] == "latest_publishable_artifacts"
        assert metadata["target_artifact_count"] == 1
