def test_realtime_session_endpoint_returns_client_secret_and_logs_sanitized_event():
    store = FakeStore()

    async def override_store():
        return store

    async def override_realtime_provider_factory():
        return lambda provider=None: FakeRealtimeProvider()

    app.dependency_overrides[get_store] = override_store
    app.dependency_overrides[
        get_realtime_provider_factory
    ] = override_realtime_provider_factory
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/realtime-session",
            json={
                "provider": "openai_realtime",
                "voice": "marin",
                "instructions": "Keep the dialogue natural.",
            },
        )

        assert response.status_code == 200
        payload = response.json()
        assert payload["provider"] == "openai_realtime"
        assert payload["realtime_session_id"]
        assert payload["client_secret"] == "client-secret-value"
        assert payload["websocket_url"] == "wss://realtime.test/session"
        assert payload["transport"]["framework"] == "livekit"
        assert payload["transport"]["url"] == "ws://livekit.test"
        assert payload["transport"]["room_name"] == "test-livekit-room"
        assert payload["transport"]["token"] == "livekit-token-value"
        assert payload["transport"]["token_persisted"] is False
        assert payload["event_id"] == store.events[-1].event_id
        assert len(store.realtime_sessions) == 1
        assert store.realtime_sessions[0].provider == "openai_realtime"
        assert store.realtime_sessions[0].provider_session_id == "rt-test-session"
        assert store.realtime_sessions[0].has_client_secret is True
        assert store.realtime_sessions[0].has_websocket_url is True
        assert store.realtime_sessions[0].transport_framework == "livekit"
        assert store.realtime_sessions[0].room_name == "test-livekit-room"
        assert store.realtime_sessions[0].participant_identity == "creator-test"
        assert store.realtime_sessions[0].agent_participant_identity == (
            "gemma4-kokoro-agent-test"
        )
        assert store.realtime_sessions[0].has_transport_token is True
        assert store.realtime_sessions[0].context_window_turns == 4
        assert store.realtime_sessions[0].summarize_after_turns == 3
        assert store.realtime_sessions[0].metadata["model"] == "test-realtime-model"
        assert store.realtime_sessions[0].metadata["transport"]["token"] is None
        assert store.realtime_sessions[0].metadata["transport"]["has_token"] is True
        assert store.realtime_sessions[0].metadata["latency_class"] == (
            "realtime_interrupt"
        )
        assert store.realtime_sessions[0].metadata["smoke_proof_status"] == (
            "provider_backed"
        )
        assert store.realtime_sessions[0].metadata["provider_latency_ms"] >= 0

        event = store.events[-1]
        assert event.event_type == "realtime_session_created"
        assert event.payload["realtime_session_id"] == payload["realtime_session_id"]
        assert event.payload["has_client_secret"] is True
        assert event.payload["has_websocket_url"] is True
        assert event.payload["transport"]["framework"] == "livekit"
        assert event.payload["transport"]["token"] is None
        assert event.payload["transport"]["has_token"] is True
        assert event.payload["metadata"]["model"] == "test-realtime-model"
        assert "token" not in event.payload["metadata"]
        assert event.payload["latency_class"] == "realtime_interrupt"
        assert event.payload["smoke_proof_status"] == "provider_backed"
        assert event.payload["provider_latency_ms"] >= 0
        assert "client-secret-value" not in str(event.payload)
        assert "livekit-token-value" not in str(event.payload)
        assert "do-not-log-token" not in str(event.payload)

        sessions_response = client.get(
            f"/api/runs/{store.run.run_id}/realtime-sessions"
        )
        assert sessions_response.status_code == 200
        assert sessions_response.json()["sessions"][0]["realtime_session_id"] == payload[
            "realtime_session_id"
        ]

        turn_response = client.post(
            f"/api/realtime-sessions/{payload['realtime_session_id']}/turns",
            json={
                "transcript": "Create a source-backed voice turn about realtime agents.",
                "topic": "realtime agents",
                "assets": [
                    {
                        "asset_uri": "artifact://uploads/realtime-screen.png",
                        "modality": "screenshot",
                        "description": "Realtime cockpit screenshot",
                    }
                ],
                "route_turn": True,
                "require_human_feedback": False,
            },
        )
        assert turn_response.status_code == 200
        turn_payload = turn_response.json()
        assert turn_payload["routed_result"]["routed_intent"] == "route_task"
        assert turn_payload["routed_result"]["run_id"] == str(store.run.run_id)
        assert turn_payload["routed_result"]["response_turn_id"]
        assert turn_payload["brief_task_message_id"]
        assert len(turn_payload["routed_result"]["artifact_ids"]) == 2
        assert turn_payload["routed_result"]["multimodal_intake"]["asset_count"] == 1
        brief_task = next(
            message
            for message in store.agent_messages
            if str(message.message_id) == turn_payload["brief_task_message_id"]
        )
        assert brief_task.recipient_agent_id == "realtime-conversation-host"
        assert brief_task.task_type == "summarize_realtime_turn_context"
        assert brief_task.payload["workflow"] == "realtime_turn_followup_v1"
        assert brief_task.payload["realtime_session_id"] == payload[
            "realtime_session_id"
        ]
        assert brief_task.payload["response_turn_id"] == turn_payload[
            "routed_result"
        ]["response_turn_id"]
        assert brief_task.payload["asset_count"] == 1
        assert store.turns[-1].metadata["realtime_session_id"] == payload[
            "realtime_session_id"
        ]
        assert store.turns[-1].speaker == "assistant"
        assert store.turns[-1].metadata["responds_to_turn_id"] == str(
            store.turns[-2].turn_id
        )
        assert store.events[-1].event_type == "realtime_turn_routed"
        assert store.events[-1].payload["provider"] == "openai_realtime"
        assert store.events[-1].payload["latency_class"] == "realtime_interrupt"
        assert store.events[-1].payload["smoke_proof_status"] == "provider_backed"
        assert store.events[-1].payload["response_turn_id"] == turn_payload[
            "routed_result"
        ]["response_turn_id"]
        assert store.events[-1].payload["response_text"] == turn_payload[
            "routed_result"
        ]["response_text"]
        assert "realtime_conversation_brief_task_created" in [
            event.event_type for event in store.events
        ]
        assert store.artifacts[-2].artifact_type == ArtifactType.MULTIMODAL_INTAKE_LEDGER
        handoff = store.artifacts[-1]
        assert handoff.artifact_type == ArtifactType.CONVERSATION_HANDOFF
        assert handoff.content["format"] == "conversation_handoff_packet"
        assert handoff.content["routing"]["attached_asset_count"] == 1
        assert handoff.content["user_turn"]["metadata"]["realtime_session_id"] == (
            payload["realtime_session_id"]
        )
        assert handoff.content["assistant_reply"]["metadata"]["responds_to_turn_id"]
        assert "conversation_handoff_recorded" in [
            event.event_type for event in store.events
        ]

        end_response = client.post(
            f"/api/realtime-sessions/{payload['realtime_session_id']}/status",
            json={"status": "ended", "reason": "test complete"},
        )
        assert end_response.status_code == 200
        assert end_response.json()["status"] == "ended"
        assert store.events[-1].event_type == "realtime_session_status_updated"

        stream_response = client.get(
            f"/api/runs/{store.run.run_id}/events/stream?once=true"
        )
        assert stream_response.status_code == 200
        assert "event: realtime_session_created" in stream_response.text
        assert "client-secret-value" not in stream_response.text
        assert "livekit-token-value" not in stream_response.text

        for index in range(125):
            asyncio.run(
                store.append_event(
                    RunEvent(
                        run_id=store.run.run_id,
                        event_type="cursor_probe",
                        actor="observability-agent",
                        payload={"index": index},
                    )
                )
            )
        event_cursor_response = client.get(
            f"/api/runs/{store.run.run_id}/events?after_event_id=120&limit=10"
        )
        assert event_cursor_response.status_code == 200
        cursor_events = event_cursor_response.json()["events"]
        assert cursor_events[0]["event_id"] == 121
        assert len(cursor_events) == 10

        stream_cursor_response = client.get(
            f"/api/runs/{store.run.run_id}/events/stream?once=true&after_event_id=120"
        )
        assert stream_cursor_response.status_code == 200
        assert "id: 121" in stream_cursor_response.text
        assert "id: 130" in stream_cursor_response.text
    finally:
        app.dependency_overrides.clear()


def test_voice_setup_proof_endpoint_records_artifact_and_timeline_event():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/voice-setup-proof",
            json={
                "action": "check_setup",
                "status": "blocked",
                "provider": "gemma4_realtime",
                "transport_framework": "livekit",
                "readiness_status": "blocked",
                "livekit_process_status": "running",
                "voice_agent_process_status": "stopped",
                "primary_blocker": {
                    "id": "Gemma/Kokoro agent",
                    "label": "Gemma/Kokoro agent",
                    "status": "blocked",
                    "detail": "HF_TOKEN is missing.",
                    "next_action": "Start Gemma/Kokoro agent",
                    "required": True,
                },
                "steps": [
                    {
                        "id": "LiveKit transport",
                        "label": "LiveKit transport",
                        "status": "ready",
                        "detail": "Local LiveKit transport is running.",
                        "required": True,
                    },
                    {
                        "id": "Gemma/Kokoro agent",
                        "label": "Gemma/Kokoro agent",
                        "status": "blocked",
                        "detail": "HF_TOKEN is missing.",
                        "next_action": "Start Gemma/Kokoro agent",
                        "required": True,
                    },
                ],
                "event_summary": "Voice setup check recorded: Gemma/Kokoro agent needs attention.",
                "metadata": {
                    "action_source": "check_setup",
                    "secret_candidate": "not-a-secret",
                },
                "record_artifact": True,
            },
        )

        assert response.status_code == 200
        payload = response.json()
        assert payload["run_id"] == str(store.run.run_id)
        assert payload["action"] == "check_setup"
        assert payload["status"] == "blocked"
        assert payload["artifact_id"]
        assert payload["event_id"] == store.events[-1].event_id
        assert payload["summary"].startswith("Voice setup check recorded")

        artifact = store.artifacts[-1]
        assert artifact.artifact_type == ArtifactType.VOICE_SETUP_PROOF
        assert artifact.content["workflow"] == "voice_setup_proof_v1"
        assert artifact.content["action"] == "check_setup"
        assert artifact.content["primary_blocker"]["label"] == "Gemma/Kokoro agent"
        assert artifact.content["steps"][0]["label"] == "LiveKit transport"
        assert artifact.provenance["workflow"] == "voice_setup_proof_v1"
        assert artifact.provenance["actor"] == "realtime-conversation-host"

        event = store.events[-1]
        assert event.event_type == "voice_setup_proof_recorded"
        assert event.actor == "realtime-conversation-host"
        assert event.payload["artifact_id"] == payload["artifact_id"]
        assert event.payload["provider"] == "gemma4_realtime"
        assert event.payload["transport_framework"] == "livekit"
        assert event.payload["primary_blocker"]["status"] == "blocked"

        missing_response = client.post(
            f"/api/runs/{uuid4()}/voice-setup-proof",
            json={"action": "check_setup", "status": "failed"},
        )
        assert missing_response.status_code == 404
    finally:
        app.dependency_overrides.clear()


def test_realtime_session_endpoint_records_configuration_failure():
    store = FakeStore()

    async def override_store():
        return store

    async def override_realtime_provider_factory():
        return lambda provider=None: FailingRealtimeProvider()

    app.dependency_overrides[get_store] = override_store
    app.dependency_overrides[
        get_realtime_provider_factory
    ] = override_realtime_provider_factory
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/realtime-session",
            json={"provider": "openai_realtime"},
        )

        assert response.status_code == 503
        assert response.json()["detail"] == "REALTIME_KEY is not configured."
        assert store.events[-1].event_type == "realtime_session_configuration_failed"
        assert store.events[-1].payload["latency_class"] == "realtime_interrupt"
        assert store.events[-1].payload["smoke_proof_status"] == "configuration_failed"
        assert store.events[-1].payload["provider_latency_ms"] >= 0
    finally:
        app.dependency_overrides.clear()


def test_realtime_session_endpoint_redacts_configuration_failure_reason():
    store = FakeStore()
    leaky_bearer = "Bearer " + ("H" * 24)
    leaky_hf = "hf_" + ("I" * 24)
    leaky_tavily = "tvly-" + ("J" * 24)

    async def override_store():
        return store

    async def override_realtime_provider_factory():
        return lambda provider=None: LeakyFailingRealtimeProvider()

    app.dependency_overrides[get_store] = override_store
    app.dependency_overrides[
        get_realtime_provider_factory
    ] = override_realtime_provider_factory
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/realtime-session",
            json={"provider": "gemma4_realtime"},
        )

        assert response.status_code == 503
        detail = response.json()["detail"]
        assert "Bearer [redacted]" in detail
        assert "hf_[redacted]" in detail
        assert "tvly-[redacted]" in detail
        serialized = json.dumps(
            {
                "response": response.json(),
                "events": [event.model_dump(mode="json") for event in store.events],
            }
        )
        assert leaky_bearer not in serialized
        assert leaky_hf not in serialized
        assert leaky_tavily not in serialized
        assert store.events[-1].event_type == "realtime_session_configuration_failed"
        assert store.events[-1].payload["reason"] == detail
    finally:
        app.dependency_overrides.clear()


def test_realtime_session_dry_run_creates_local_rehearsal_without_provider_secret():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/realtime-session",
            json={
                "provider": "openai_realtime",
                "voice": "marin",
                "dry_run": True,
                "instructions": "Rehearse a natural back-and-forth dialogue.",
                "metadata": {"audio_mode": "speech_to_speech", "cockpit": True},
            },
        )

        assert response.status_code == 200
        payload = response.json()
        assert payload["provider"] == "local_realtime_rehearsal"
        assert payload["client_secret"] is None
        assert payload["websocket_url"] is None
        assert payload["metadata"]["dry_run"] is True
        assert payload["metadata"]["not_provider_backed"] is True
        assert payload["metadata"]["provider_under_test"] == "openai_realtime"
        assert payload["metadata"]["latency_class"] == "realtime_interrupt"
        assert payload["metadata"]["smoke_proof_status"] == "rehearsal_only"
        assert len(store.realtime_sessions) == 1
        session = store.realtime_sessions[0]
        assert session.provider == "local_realtime_rehearsal"
        assert session.has_client_secret is False
        assert session.has_websocket_url is False
        assert session.metadata["dry_run"] is True
        assert session.metadata["latency_class"] == "realtime_interrupt"
        assert session.metadata["smoke_proof_status"] == "rehearsal_only"
        assert store.events[-1].event_type == "realtime_rehearsal_session_created"

        turn_response = client.post(
            f"/api/realtime-sessions/{payload['realtime_session_id']}/turns",
            json={
                "transcript": "Talk with me naturally about source-backed reels.",
                "topic": "source-backed reels",
                "route_turn": True,
                "require_human_feedback": False,
            },
        )
        assert turn_response.status_code == 200
        assert turn_response.json()["spoken_response"]["provider"] == (
            "local_realtime_rehearsal"
        )
        assert turn_response.json()["spoken_response"]["metadata"][
            "latency_class"
        ] == "realtime_interrupt"
        assert turn_response.json()["spoken_response"]["metadata"][
            "smoke_proof_status"
        ] == "rehearsal_only"

        ledger_response = client.post(
            f"/api/runs/{store.run.run_id}/realtime-dialogue-ledger",
            json={"record_artifact": True, "event_limit": 100, "turn_limit": 20},
        )
        assert ledger_response.status_code == 200
        ledger = ledger_response.json()
        assert ledger["session_count"] == 1
        assert ledger["sessions"][0]["provider"] == "local_realtime_rehearsal"
        assert ArtifactType.REALTIME_DIALOGUE_LEDGER in [
            artifact.artifact_type for artifact in store.artifacts
        ]
    finally:
        app.dependency_overrides.clear()


