def test_realtime_voice_events_feed_correlated_timing_ledger():
    store = FakeStore()

    async def override_store():
        return store

    session = RealtimeSessionRecord(
        run_id=store.run.run_id,
        provider="gemma4_realtime",
        provider_session_id="gemma4-livekit-api-session",
        voice="af_heart",
        instructions="Use Gemma 4 audio understanding and Kokoro speech.",
        transport_framework="livekit",
        room_name="agent-studio-test",
        agent_participant_identity="gemma4-kokoro-agent-test",
    )
    asyncio.run(store.record_realtime_session(session))

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        started = datetime(2026, 5, 18, 12, 0, tzinfo=timezone.utc)

        def post_event(event_type, offset_ms, payload):
            response = client.post(
                f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
                json={
                    "event_type": event_type,
                    "payload": payload,
                    "agent_created_at": (
                        started + timedelta(milliseconds=offset_ms)
                    ).isoformat(),
                    "source": "test_livekit_data_channel",
                },
            )
            assert response.status_code == 200
            assert response.json()["event_type"] == event_type
            assert response.json()["event_id"]

        post_event(
            "gemma_kokoro_voice_agent_ready",
            0,
            {
                "room_name": "agent-studio-test",
                "client_secret": "must-not-persist",
                "transport": {"token": "must-not-persist"},
            },
        )
        post_event(
            "voice_agent_media_bridge_ready",
            20,
            {
                "participant_identity": "creator",
                "media_bridge": "livekit_audio_track_to_rust_voice_edge",
                "voice_edge_enabled": True,
                "voice_edge_process_mode": "persistent_jsonl",
            },
        )
        post_event("voice_user_speech_started", 50, {})
        post_event(
            "voice_user_turn_committed",
            400,
            {
                "turn_id": "turn-1",
                "audio_duration_ms": 350,
                "windowing": "rust_voice_edge_vad_silence",
            },
        )
        post_event(
            "gemma_kokoro_voice_turn_started",
            420,
            {"turn_id": "turn-1", "response_id": "response-1"},
        )
        post_event(
            "gemma_generation_started",
            500,
            {"turn_id": "turn-1", "response_id": "response-1"},
        )
        post_event(
            "assistant_text_delta",
            620,
            {"turn_id": "turn-1", "response_id": "response-1", "delta_chars": 9},
        )
        post_event(
            "assistant_audio_chunk_published",
            880,
            {"turn_id": "turn-1", "response_id": "response-1", "bytes": 6400},
        )
        post_event(
            "voice_edge_cancellation_acknowledged",
            1000,
            {"turn_id": "turn-1", "response_id": "response-1"},
        )
        post_event(
            "gemma_kokoro_voice_turn_cancelled",
            1038,
            {"turn_id": "turn-1", "response_id": "response-1"},
        )

        assert "must-not-persist" not in str(store.events[0].payload)
        assert store.events[0].payload["voice_agent_event_source"] == (
            "test_livekit_data_channel"
        )
        assert store.events[0].payload["transport_framework"] == "livekit"

        ledger_response = client.post(
            f"/api/runs/{store.run.run_id}/realtime-voice-timing-ledger",
            json={"record_artifact": True, "event_limit": 100},
        )
        assert ledger_response.status_code == 200
        ledger = ledger_response.json()
        assert ledger["status"] == "ready"
        stages = {stage["stage_id"]: stage for stage in ledger["stages"]}
        assert stages["livekit_audio_track_bridge"]["status"] == "measured"
        assert stages["end_of_turn_to_agent_turn"]["latency_ms"] == 20
        assert stages["first_audio_out"]["latency_ms"] == 380
        assert stages["barge_in_to_audio_stop"]["latency_ms"] == 38
        assert ledger["turns"][0]["turn_commit_to_agent_turn_ms"] == 20
        assert ArtifactType.REALTIME_VOICE_TIMING_LEDGER in [
            artifact.artifact_type for artifact in store.artifacts
        ]
    finally:
        app.dependency_overrides.clear()


def test_realtime_voice_event_uid_deduplicates_agent_and_browser_paths():
    store = FakeStore()

    async def override_store():
        return store

    session = RealtimeSessionRecord(
        run_id=store.run.run_id,
        provider="gemma4_realtime",
        provider_session_id="gemma4-livekit-api-session",
        voice="af_heart",
        instructions="Use Gemma 4 audio understanding and Kokoro speech.",
        transport_framework="livekit",
        room_name="agent-studio-test",
        agent_participant_identity="gemma4-kokoro-agent-test",
    )
    asyncio.run(store.record_realtime_session(session))

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        turn_id = str(uuid4())
        uid = "voice-event-agent-browser-1"
        first = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "voice_user_turn_committed",
                "voice_agent_event_uid": uid,
                "payload": {
                    "voice_agent_event_uid": uid,
                    "turn_id": turn_id,
                    "audio_duration_ms": 420,
                    "audio_bytes": 13440,
                    "windowing": "rust_voice_edge_vad_silence",
                },
                "source": "livekit_agent_http_sink",
            },
        )
        duplicate = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "voice_user_turn_committed",
                "voice_agent_event_uid": uid,
                "payload": {
                    "voice_agent_event_uid": uid,
                    "turn_id": turn_id,
                    "audio_duration_ms": 420,
                    "audio_bytes": 13440,
                    "windowing": "rust_voice_edge_vad_silence",
                },
                "source": "next_livekit_data_channel",
            },
        )

        assert first.status_code == 200
        assert duplicate.status_code == 200
        assert duplicate.json()["event_id"] == first.json()["event_id"]
        assert duplicate.json()["materialized_turn_id"] == first.json()["materialized_turn_id"]
        assert duplicate.json()["followup_task_message_id"] is None
        assert len(
            [
                event
                for event in store.events
                if event.event_type == "voice_user_turn_committed"
            ]
        ) == 1
        assert len(store.turns) == 1
        assert store.events[-1].payload["voice_agent_event_uid"] == uid

        assistant_uid = "voice-event-agent-browser-2"
        assistant_first = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "assistant_response_completed",
                "voice_agent_event_uid": assistant_uid,
                "payload": {
                    "voice_agent_event_uid": assistant_uid,
                    "turn_id": turn_id,
                    "response_id": "voice-response-agent-browser-1",
                    "assistant_text": "I can turn that into a reel.",
                    "assistant_text_chars": 28,
                    "audio_chunk_count": 2,
                },
                "source": "livekit_agent_http_sink",
            },
        )
        assistant_duplicate = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "assistant_response_completed",
                "voice_agent_event_uid": assistant_uid,
                "payload": {
                    "voice_agent_event_uid": assistant_uid,
                    "turn_id": turn_id,
                    "response_id": "voice-response-agent-browser-1",
                    "assistant_text": "I can turn that into a reel.",
                    "assistant_text_chars": 28,
                    "audio_chunk_count": 2,
                },
                "source": "next_livekit_data_channel",
            },
        )

        assert assistant_first.status_code == 200
        assert assistant_duplicate.status_code == 200
        assert assistant_first.json()["followup_task_message_id"]
        assert assistant_duplicate.json()["event_id"] == assistant_first.json()["event_id"]
        assert assistant_duplicate.json()["materialized_turn_id"] == (
            assistant_first.json()["materialized_turn_id"]
        )
        assert assistant_duplicate.json()["followup_task_message_id"] == (
            assistant_first.json()["followup_task_message_id"]
        )
        assert assistant_duplicate.json()["followup_kind"] == "realtime_turn_context"
        assert len(
            [
                event
                for event in store.events
                if event.event_type == "assistant_response_completed"
            ]
        ) == 1
        assert len(store.agent_messages) == 1
    finally:
        app.dependency_overrides.clear()


