def test_realtime_voice_events_materialize_run_dialogue_turns():
    store = FakeStore()

    async def override_store():
        return store

    session = RealtimeSessionRecord(
        run_id=store.run.run_id,
        provider="gemma4_realtime",
        provider_session_id="gemma4-livekit-api-session",
        voice="af_heart",
        instructions="Use Gemma 4 audio understanding and Kokoro speech.",
        transport_framework="livekit",
        room_name="agent-studio-test",
        agent_participant_identity="gemma4-kokoro-agent-test",
    )
    asyncio.run(store.record_realtime_session(session))

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        turn_id = str(uuid4())
        for index in range(125):
            store.turns.append(
                ConversationTurn(
                    run_id=store.run.run_id,
                    speaker="user",
                    modality="text",
                    transcript=f"older turn {index}",
                )
            )

        user_response = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "voice_user_turn_committed",
                "payload": {
                    "turn_id": turn_id,
                    "audio_duration_ms": 420,
                    "audio_bytes": 13440,
                    "audio_artifact_uri": "artifact://voice-audio/run/session/turn.pcm",
                    "audio_artifact_relative_path": "voice-audio/run/session/turn.pcm",
                    "audio_artifact_sha256": "abc123",
                    "audio_artifact_bytes": 13440,
                    "audio_artifact_persisted": True,
                    "windowing": "rust_voice_edge_vad_silence",
                },
                "source": "test_livekit_data_channel",
            },
        )
        assert user_response.status_code == 200
        user_payload = user_response.json()
        assert user_payload["materialized_turn_id"] == turn_id
        assert user_payload["materialized_speaker"] == "user"

        assistant_response = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "assistant_response_completed",
                "payload": {
                    "turn_id": turn_id,
                    "response_id": "voice-response-1",
                    "assistant_text": "I can turn that into a source-backed reel.",
                    "assistant_text_chars": 42,
                    "audio_chunk_count": 3,
                    "livekit_audio_track_id": "livekit-audio-test",
                },
                "source": "test_livekit_data_channel",
            },
        )
        assert assistant_response.status_code == 200
        assistant_payload = assistant_response.json()
        assert assistant_payload["materialized_speaker"] == "assistant"
        assert assistant_payload["followup_task_message_id"]
        assert assistant_payload["followup_kind"] == "realtime_turn_context"
        assert assistant_payload["followup_worker_agent_ids"] == []
        assert assistant_payload["followup_worker_use_gemma"] is None
        followup_task = next(
            message
            for message in store.agent_messages
            if str(message.message_id) == assistant_payload["followup_task_message_id"]
        )
        assert followup_task.recipient_agent_id == "realtime-conversation-host"
        assert followup_task.task_type == "summarize_realtime_turn_context"
        assert followup_task.payload["workflow"] == (
            "realtime_voice_agent_event_followup_v1"
        )
        assert followup_task.payload["source_turn_id"] == turn_id
        assert followup_task.payload["voice_agent_response_id"] == "voice-response-1"
        assert followup_task.payload["transcript_status"] == "pending_user_transcript"
        assert followup_task.payload["routing_policy"] == (
            "summarize_or_route_without_treating_raw_audio_as_verified_text"
        )
        assert followup_task.payload["transcript_excerpt"] == (
            "I can turn that into a source-backed reel."
        )
        followup_event_count = sum(
            event.event_type == "realtime_voice_agent_followup_task_created"
            for event in store.events
        )
        accepted_message_event_count = sum(
            event.event_type == "agent_message_accepted" for event in store.events
        )

        duplicate_response = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "assistant_response_completed",
                "payload": {
                    "turn_id": turn_id,
                    "response_id": "voice-response-1",
                    "assistant_text": "Duplicate response should not create another turn.",
                },
                "source": "test_livekit_data_channel",
            },
        )
        assert duplicate_response.status_code == 200
        assert duplicate_response.json()["materialized_turn_id"] is None
        assert duplicate_response.json()["followup_task_message_id"] is None
        assert sum(
            event.event_type == "realtime_voice_agent_followup_task_created"
            for event in store.events
        ) == followup_event_count
        assert (
            sum(event.event_type == "agent_message_accepted" for event in store.events)
            == accepted_message_event_count
        )

        missing_id_response = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "voice_user_turn_committed",
                "payload": {"audio_duration_ms": 100},
                "source": "test_livekit_data_channel",
            },
        )
        assert missing_id_response.status_code == 200
        assert missing_id_response.json()["materialized_turn_id"] is None

        malformed_id_response = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "voice_user_turn_committed",
                "payload": {"turn_id": "not-a-uuid", "audio_duration_ms": 100},
                "source": "test_livekit_data_channel",
            },
        )
        assert malformed_id_response.status_code == 200
        assert malformed_id_response.json()["materialized_turn_id"] is None

        assert len(store.turns) == 127
        user_turn, assistant_turn = store.turns[-2:]
        assert user_turn.speaker == "user"
        assert user_turn.modality == "voice"
        assert user_turn.transcript == "Live audio turn committed; transcript pending."
        assert user_turn.metadata["voice_agent_turn_id"] == turn_id
        assert user_turn.metadata["transcript_status"] == "pending"
        assert user_turn.metadata["audio_duration_ms"] == 420
        assert user_turn.audio_uri == "artifact://voice-audio/run/session/turn.pcm"
        assert user_turn.metadata["audio_artifact_uri"] == (
            "artifact://voice-audio/run/session/turn.pcm"
        )
        assert user_turn.metadata["audio_artifact_relative_path"] == (
            "voice-audio/run/session/turn.pcm"
        )
        assert user_turn.metadata["audio_artifact_sha256"] == "abc123"
        assert user_turn.metadata["audio_artifact_bytes"] == 13440
        assert user_turn.metadata["audio_artifact_persisted"] is True
        assert assistant_turn.speaker == "assistant"
        assert assistant_turn.transcript == "I can turn that into a source-backed reel."
        assert assistant_turn.metadata["voice_agent_response_id"] == "voice-response-1"
        assert assistant_turn.metadata["responds_to_voice_turn_id"] == turn_id
        assert assistant_turn.metadata["audio_chunk_count"] == 3
        assert followup_task.payload["response_turn_id"] == str(assistant_turn.turn_id)
        assert len(store.agent_messages) == 1
        assert "realtime_voice_agent_followup_task_created" in [
            event.event_type for event in store.events
        ]
    finally:
        app.dependency_overrides.clear()


def test_realtime_voice_event_followup_recovers_after_materialized_retry():
    store = FakeStore()

    async def override_store():
        return store

    session = RealtimeSessionRecord(
        run_id=store.run.run_id,
        provider="gemma4_realtime",
        provider_session_id="gemma4-livekit-api-session",
        voice="af_heart",
        instructions="Use Gemma 4 audio understanding and Kokoro speech.",
        transport_framework="livekit",
        room_name="agent-studio-test",
    )
    asyncio.run(store.record_realtime_session(session))
    turn_id = str(uuid4())
    existing_assistant_turn = ConversationTurn(
        run_id=store.run.run_id,
        speaker="assistant",
        modality="voice",
        transcript="Recovered assistant reply after a retry.",
        metadata={
            "realtime_session_id": str(session.realtime_session_id),
            "voice_agent_turn_id": turn_id,
            "voice_agent_response_id": "voice-response-retry",
            "responds_to_voice_turn_id": turn_id,
            "voice_agent_event_type": "assistant_response_completed",
            "source": "livekit_voice_agent_event",
        },
    )
    asyncio.run(
        store.record_voice_agent_conversation_turn_if_absent(
            existing_assistant_turn,
            response_id="voice-response-retry",
        )
    )

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        retry_response = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "assistant_response_completed",
                "payload": {
                    "turn_id": turn_id,
                    "response_id": "voice-response-retry",
                    "assistant_text": "Retried response text should not duplicate turns.",
                },
                "source": "test_livekit_data_channel",
            },
        )
        assert retry_response.status_code == 200
        retry_payload = retry_response.json()
        assert retry_payload["materialized_turn_id"] is None
        assert retry_payload["followup_task_message_id"]
        assert len(store.turns) == 1
        assert len(store.agent_messages) == 1
        followup_task = store.agent_messages[0]
        assert followup_task.payload["voice_agent_response_id"] == (
            "voice-response-retry"
        )
        assert followup_task.payload["response_turn_id"] == str(
            existing_assistant_turn.turn_id
        )
        assert followup_task.payload["transcript_excerpt"] == (
            "Recovered assistant reply after a retry."
        )

        duplicate_retry_response = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/voice-events",
            json={
                "event_type": "assistant_response_completed",
                "payload": {
                    "turn_id": turn_id,
                    "response_id": "voice-response-retry",
                    "assistant_text": "Another retry should not duplicate follow-up.",
                },
                "source": "test_livekit_data_channel",
            },
        )
        assert duplicate_retry_response.status_code == 200
        assert duplicate_retry_response.json()["materialized_turn_id"] is None
        assert duplicate_retry_response.json()["followup_task_message_id"] is None
        assert len(store.agent_messages) == 1
        assert [
            event.event_type for event in store.events
        ].count("realtime_voice_agent_followup_task_created") == 1
        assert [
            event.event_type for event in store.events
        ].count("agent_message_accepted") == 1
    finally:
        app.dependency_overrides.clear()


def test_realtime_session_endpoint_recursively_redacts_durable_provider_metadata_variants():
    store = FakeStore()
    leak_values = [
        "v1.transport-binding-leak",
        "transport-client-secret-leak",
        "metadata-client-secret-leak",
        "metadata-api-key-leak",
        "metadata-session-token-leak",
        "metadata-signed-url-leak",
        "Bearer " + ("B" * 24),
        "hf_" + ("C" * 24),
        "tvly-" + ("D" * 24),
        "livekit-token-value",
        "client-secret-value",
    ]

    async def override_store():
        return store

    async def override_realtime_provider_factory():
        return lambda provider=None: LeakyRealtimeProvider()

    app.dependency_overrides[get_store] = override_store
    app.dependency_overrides[
        get_realtime_provider_factory
    ] = override_realtime_provider_factory
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/realtime-session",
            json={
                "provider": "openai_realtime",
                "voice": "marin",
                "instructions": "Keep the dialogue natural.",
            },
        )

        assert response.status_code == 200
        payload = response.json()
        assert payload["metadata"]["model"] == "test-realtime-model"
        assert payload["metadata"]["notes"] == [
            "safe metadata note",
            "tvly-[redacted]",
        ]
        session = store.realtime_sessions[0]
        assert session.metadata["transport"]["token"] is None
        assert session.metadata["transport"]["has_token"] is True
        assert session.metadata["transport"]["metadata"]["transport_probe"] is True
        durable_surfaces = {
            "events": [event.model_dump(mode="json") for event in store.events],
            "sessions": [
                session.model_dump(mode="json")
                for session in store.realtime_sessions
            ],
        }
        serialized = json.dumps(durable_surfaces)
        for leak_value in leak_values:
            assert leak_value not in serialized
        assert "Bearer [redacted]" in serialized
        assert "hf_[redacted]" in serialized
        assert "tvly-[redacted]" in serialized
    finally:
        app.dependency_overrides.clear()


def test_realtime_session_control_records_durable_interrupt_and_ledger_resolution():
    store = FakeStore()

    async def override_store():
        return store

    session = RealtimeSessionRecord(
        run_id=store.run.run_id,
        provider="openai_realtime",
        provider_session_id="rt-control-session",
        voice="marin",
        instructions="Keep spoken output interruptible.",
        has_client_secret=True,
    )
    asyncio.run(store.record_realtime_session(session))

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        control_response = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/control",
            json={
                "action": "interrupt",
                "reason": "User stopped the spoken reply.",
                "cancel_gemma": True,
                "clear_kokoro_buffers": True,
                "stop_livekit_audio": True,
                "interrupted_response_id": "response-123",
                "client_audio_timestamp_ms": 4242,
                "create_followup_task": True,
                "metadata": {"surface": "cockpit"},
            },
        )
        assert control_response.status_code == 200
        control_payload = control_response.json()
        assert control_payload["action"] == "interrupt"
        assert control_payload["event_id"]
        assert control_payload["followup_task_message_id"]
        control_task = next(
            message
            for message in store.agent_messages
            if str(message.message_id) == control_payload["followup_task_message_id"]
        )
        assert control_task.task_type == "handle_realtime_session_control"
        assert control_task.payload["workflow"] == "realtime_session_control_v1"
        assert control_task.payload["action"] == "interrupt"
        assert control_task.payload["cancellation_contract"]["cancel_gemma"] is True
        assert control_task.payload["cancellation_contract"][
            "clear_kokoro_buffers"
        ] is True
        assert control_task.payload["cancellation_contract"][
            "stop_livekit_audio"
        ] is True
        assert control_task.payload["cancellation_contract"][
            "interrupted_response_id"
        ] == "response-123"
        assert control_task.payload["cancellation_contract"][
            "client_audio_timestamp_ms"
        ] == 4242
        assert store.events[-1].event_type == "realtime_session_control_recorded"
        assert store.events[-1].payload["followup_task_message_id"] == (
            control_payload["followup_task_message_id"]
        )
        assert store.events[-1].payload["cancel_gemma"] is True
        assert store.events[-1].payload["clear_kokoro_buffers"] is True
        assert store.events[-1].payload["stop_livekit_audio"] is True

        turn_response = client.post(
            f"/api/realtime-sessions/{session.realtime_session_id}/turns",
            json={
                "transcript": "Stop that and answer with a shorter explanation.",
                "route_turn": False,
                "create_realtime_brief_task": False,
                "interrupted": True,
            },
        )
        assert turn_response.status_code == 200
        turn_payload = turn_response.json()
        assert turn_payload["conversation_turn"]["metadata"][
            "interruption_control_event_id"
        ] == control_payload["event_id"]
        assert store.events[-1].payload["interruption_control_event_id"] == (
            control_payload["event_id"]
        )

        ledger_response = client.post(
            f"/api/runs/{store.run.run_id}/realtime-dialogue-ledger",
            json={"record_artifact": False, "event_limit": 100, "turn_limit": 20},
        )
        assert ledger_response.status_code == 200
        ledger = ledger_response.json()
        assert ledger["control_event_count"] == 1
        assert ledger["control_action_counts"]["interrupt"] == 1
        assert ledger["unresolved_control_event_ids"] == []
        assert ledger["control_events"][0]["event_id"] == control_payload["event_id"]
        assert ledger["control_events"][0]["resolved_by_turn_id"] == (
            turn_payload["conversation_turn"]["turn_id"]
        )
        assert ledger["followup_tasks"][0]["task_type"] == (
            "handle_realtime_session_control"
        )
    finally:
        app.dependency_overrides.clear()


