def test_local_secret_file_endpoint_writes_hf_token_without_echoing_value(
    tmp_path: Path, monkeypatch: pytest.MonkeyPatch
):
    monkeypatch.setattr("all_about_llms.app.PROJECT_ROOT", tmp_path)
    existing_secret_dir = tmp_path / ".secrets"
    existing_secret_dir.mkdir()
    os.chmod(existing_secret_dir, 0o777)
    token_file = existing_secret_dir / "hf_token"
    tavily_file = tmp_path / "new-secrets" / "tavily_api_key"
    secret_value = "secret-hf-token-local-setup"
    tavily_secret_value = "secret-tavily-key-local-setup"
    settings = Settings(
        environment="local",
        hf_token=None,
        hf_token_file=token_file,
        tavily_api_key=None,
        tavily_api_key_file=tavily_file,
    )

    app.dependency_overrides[get_settings] = lambda: settings
    try:
        client = TestClient(app)
        response = client.post(
            "/api/local-secret-files",
            json={"env_name": "HF_TOKEN", "secret_value": secret_value},
        )
        assert response.status_code == 200
        payload = response.json()
        serialized = json.dumps(payload)
        assert secret_value not in serialized
        assert payload["env_name"] == "HF_TOKEN"
        assert payload["file_env_name"] == "HF_TOKEN_FILE"
        assert payload["status"] == "loaded"
        assert payload["configured"] is True
        assert payload["path"] == str(token_file)
        assert token_file.read_text(encoding="utf-8") == f"{secret_value}\n"
        assert token_file.stat().st_mode & 0o777 == 0o600
        assert existing_secret_dir.stat().st_mode & 0o777 == 0o700
        tavily_response = client.post(
            "/api/local-secret-files",
            json={
                "env_name": "TAVILY_API_KEY",
                "secret_value": tavily_secret_value,
            },
        )
        assert tavily_response.status_code == 200
        assert tavily_secret_value not in json.dumps(tavily_response.json())
        assert tavily_file.read_text(encoding="utf-8") == f"{tavily_secret_value}\n"
        assert tavily_file.stat().st_mode & 0o777 == 0o600
        assert tavily_file.parent.stat().st_mode & 0o777 == 0o700

        readiness = client.get("/api/provider-readiness").json()
        gemma = next(
            provider
            for provider in readiness["providers"]
            if provider["provider_id"] == "gemma4-primary"
        )
        tavily = next(
            provider
            for provider in readiness["providers"]
            if provider["provider_id"] == "tavily-search"
        )
        assert gemma["secret_files"][0]["status"] == "loaded"
        assert tavily["secret_files"][0]["status"] == "loaded"
        assert secret_value not in json.dumps(readiness)
        assert tavily_secret_value not in json.dumps(readiness)
    finally:
        app.dependency_overrides.clear()


def test_local_secret_file_endpoint_writes_livekit_credentials_without_echoing_values(
    tmp_path: Path,
):
    api_key_file = tmp_path / "livekit_api_key"
    api_secret_file = tmp_path / "livekit_api_secret"
    livekit_key = "livekit-local-key"
    livekit_secret = "livekit-local-secret"
    settings = Settings(
        environment="local",
        openrouter_livekit_url="ws://127.0.0.1:7880",
        livekit_api_key=None,
        livekit_api_key_file=api_key_file,
        livekit_api_secret=None,
        livekit_api_secret_file=api_secret_file,
    )

    app.dependency_overrides[get_settings] = lambda: settings
    try:
        client = TestClient(app)
        key_response = client.post(
            "/api/local-secret-files",
            json={"env_name": "LIVEKIT_API_KEY", "secret_value": livekit_key},
        )
        secret_response = client.post(
            "/api/local-secret-files",
            json={
                "env_name": "LIVEKIT_API_SECRET",
                "secret_value": livekit_secret,
            },
        )

        assert key_response.status_code == 200
        assert secret_response.status_code == 200
        assert livekit_key not in json.dumps(key_response.json())
        assert livekit_secret not in json.dumps(secret_response.json())
        assert api_key_file.read_text(encoding="utf-8") == f"{livekit_key}\n"
        assert api_secret_file.read_text(encoding="utf-8") == f"{livekit_secret}\n"
        assert api_key_file.stat().st_mode & 0o777 == 0o600
        assert api_secret_file.stat().st_mode & 0o777 == 0o600

        readiness = client.get("/api/provider-readiness").json()
        realtime = next(
            provider
            for provider in readiness["providers"]
            if provider["provider_id"] == "openrouter-livekit"
        )
        secret_statuses = {
            secret_file["env_name"]: secret_file
            for secret_file in realtime["secret_files"]
        }
        assert realtime["status"] == "ready"
        assert "LIVEKIT_API_KEY" in realtime["configured_env"]
        assert "LIVEKIT_API_SECRET" in realtime["configured_env"]
        assert secret_statuses["LIVEKIT_API_KEY"]["status"] == "loaded"
        assert secret_statuses["LIVEKIT_API_SECRET"]["status"] == "loaded"
        assert livekit_key not in json.dumps(readiness)
        assert livekit_secret not in json.dumps(readiness)
    finally:
        app.dependency_overrides.clear()


def test_local_secret_file_endpoint_writes_publication_tokens_for_publish_readiness(
    tmp_path: Path,
    monkeypatch: pytest.MonkeyPatch,
):
    for env_name in (
        "INSTAGRAM_ACCESS_TOKEN",
        "INSTAGRAM_ACCESS_TOKEN_FILE",
        "LINKEDIN_ACCESS_TOKEN",
        "LINKEDIN_ACCESS_TOKEN_FILE",
    ):
        monkeypatch.delenv(env_name, raising=False)

    instagram_file = tmp_path / "instagram_access_token"
    linkedin_file = tmp_path / "linkedin_access_token"
    instagram_secret = "instagram-local-secret"
    linkedin_secret = "linkedin-local-secret"
    settings = Settings(
        environment="local",
        instagram_access_token=None,
        instagram_access_token_file=instagram_file,
        linkedin_access_token=None,
        linkedin_access_token_file=linkedin_file,
    )
    store = FakeStore()
    now = datetime.now(timezone.utc)
    source = SourceRecord(
        run_id=store.run.run_id,
        citation_id="S1",
        title="Official publishing policy source",
        url="https://example.com/publishing-policy",
        publisher="Example",
        published_at=now,
        metadata={"source_type": "official_documentation"},
    )
    claim = ClaimRecord(
        run_id=store.run.run_id,
        claim_text="Local publication secret files should support readiness.",
        support_status=ClaimSupportStatus.SUPPORTED,
        source_ids=[source.source_id],
    )
    artifact = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.SOCIAL_PACKAGE,
        title="Distribution package",
        uri="artifact://distribution-package",
        content={
            "platforms": [
                {"platform": "instagram_post"},
                {"platform": "linkedin"},
            ],
            "claim_ids": [str(claim.claim_id)],
            "source_dependencies": [{"source_id": str(source.source_id)}],
        },
        provenance={
            "workflow": "distribution_package_v1",
            "model_provider": "huggingface",
            "model_id": "google/gemma-4-E4B-it",
            "prompt_input": "Create a source-backed channel package.",
            "claim_ids": [str(claim.claim_id)],
        },
        source_ids=[source.source_id],
        reviewer_decisions=[
            {
                "reviewer_agent_id": "editor-in-chief",
                "status": ReviewDecisionStatus.APPROVED.value,
            }
        ],
        revision_history=[
            {"actor": "platform-optimization-agent", "note": "Created package."}
        ],
    )
    store.sources = [source]
    store.claims = [claim]
    store.artifacts = [artifact]
    store.guardrail_audits = [
        GuardrailAuditRecord(
            run_id=store.run.run_id,
            artifact_id=artifact.artifact_id,
            status=GuardrailAuditStatus.APPROVED,
            source_coverage=1.0,
            claim_count=1,
            supported_claim_ids=[claim.claim_id],
            notes="Approved for channel smoke testing.",
        )
    ]

    async def override_store():
        return store

    app.dependency_overrides[get_settings] = lambda: settings
    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        missing_response = client.post(
            f"/api/runs/{store.run.run_id}/publish-readiness",
            json={
                "open_feedback_gate": False,
                "check_publish_channel_readiness": True,
            },
        )
        assert missing_response.status_code == 200
        assert "missing_publish_channel_credentials" in (
            missing_response.json()["blocking_issues"]
        )

        instagram_response = client.post(
            "/api/local-secret-files",
            json={
                "env_name": "INSTAGRAM_ACCESS_TOKEN",
                "secret_value": instagram_secret,
            },
        )
        linkedin_response = client.post(
            "/api/local-secret-files",
            json={
                "env_name": "LINKEDIN_ACCESS_TOKEN",
                "secret_value": linkedin_secret,
            },
        )
        assert instagram_response.status_code == 200
        assert linkedin_response.status_code == 200
        assert instagram_secret not in json.dumps(instagram_response.json())
        assert linkedin_secret not in json.dumps(linkedin_response.json())
        assert instagram_file.read_text(encoding="utf-8") == f"{instagram_secret}\n"
        assert linkedin_file.read_text(encoding="utf-8") == f"{linkedin_secret}\n"

        ready_response = client.post(
            f"/api/runs/{store.run.run_id}/publish-readiness",
            json={
                "open_feedback_gate": False,
                "check_publish_channel_readiness": True,
            },
        )
        assert ready_response.status_code == 200
        payload = ready_response.json()
        assert payload["status"] == "needs_review"
        assert payload["blocking_issues"] == [
            "publish_channel_policy_review_required"
        ]
        assert {
            check["platform"]: check["credential_status"]
            for check in payload["publish_channel_checks"]
        } == {"instagram_post": "configured", "linkedin": "configured"}
        serialized = json.dumps(payload)
        assert instagram_secret not in serialized
        assert linkedin_secret not in serialized
    finally:
        app.dependency_overrides.clear()


