    api_secret_file.write_text("livekit-file-secret\n", encoding="utf-8")

    settings = Settings(
        openrouter_livekit_url="ws://127.0.0.1:7880",
        openrouter_api_key="openrouter-test-key",
        livekit_api_key_file=api_key_file,
        livekit_api_secret_file=api_secret_file,
    )

    readiness = build_provider_readiness(settings)
    providers = {
        provider.provider_id: provider for provider in readiness.providers
    }
    realtime = providers["openrouter-livekit"]
    secret_statuses = {
        secret_file.env_name: secret_file for secret_file in realtime.secret_files
    }

