def test_local_provider_config_endpoint_writes_voice_urls_without_echoing_values(
    tmp_path: Path,
):
    config_file = tmp_path / "local_provider_config.json"
    gemma_url = "https://hf.test/gemma-e4b"
    livekit_url = "ws://127.0.0.1:7880"
    kokoro_url = "https://hf.test/kokoro"
    settings = Settings(
        environment="local",
        hf_token="secret-hf-token",
        local_provider_config_file=config_file,
        gemma4_multimodal_endpoint_url=None,
        openrouter_livekit_url=None,
        kokoro_tts_endpoint_url=None,
    )

    app.dependency_overrides[get_settings] = lambda: settings
    try:
        client = TestClient(app)
        for env_name, config_value in [
            ("GEMMA4_MULTIMODAL_ENDPOINT_URL", gemma_url),
            ("OPENROUTER_LIVEKIT_URL", livekit_url),
            ("KOKORO_TTS_ENDPOINT_URL", kokoro_url),
        ]:
            response = client.post(
                "/api/local-provider-config",
                json={"env_name": env_name, "config_value": config_value},
            )
            assert response.status_code == 200
            serialized = json.dumps(response.json())
            assert config_value not in serialized
            assert response.json()["env_name"] == env_name
            assert response.json()["status"] == "configured"

        saved_config = json.loads(config_file.read_text(encoding="utf-8"))
        assert saved_config == {
            "GEMMA4_MULTIMODAL_ENDPOINT_URL": gemma_url,
            "OPENROUTER_LIVEKIT_URL": livekit_url,
            "KOKORO_TTS_ENDPOINT_URL": kokoro_url,
        }
        assert config_file.stat().st_mode & 0o777 == 0o600

        readiness = client.get("/api/provider-readiness").json()
        providers = {
            provider["provider_id"]: provider for provider in readiness["providers"]
        }
        assert providers["gemma4-multimodal"]["status"] == "ready"
        assert providers["openrouter-livekit"]["endpoint_configured"] is True
        assert gemma_url not in json.dumps(readiness)
        assert livekit_url not in json.dumps(readiness)
        assert kokoro_url not in json.dumps(readiness)
    finally:
        app.dependency_overrides.clear()


