def test_local_livekit_dev_config_serializes_with_livekit_secret_file_write(
    tmp_path: Path,
    monkeypatch,
):
    config_file = tmp_path / "local_provider_config.json"
    api_key_file = tmp_path / "livekit_api_key"
    api_secret_file = tmp_path / "livekit_api_secret"
    settings = Settings(
        environment="local",
        local_provider_config_file=config_file,
        gemma4_realtime_livekit_url=None,
        livekit_api_key=None,
        livekit_api_key_file=api_key_file,
        livekit_api_secret=None,
        livekit_api_secret_file=api_secret_file,
    )
    conflict_checked = Event()
    release_dev_write = Event()

    def pause_after_dev_conflict_check(
        current_config: dict[str, str],
        key_path: Path,
        secret_path: Path,
    ) -> list[str]:
        conflict_checked.set()
        release_dev_write.wait(timeout=1)
        return []

    monkeypatch.setattr(
        "all_about_llms.app._local_livekit_dev_file_conflicts",
        pause_after_dev_conflict_check,
    )

    def post_dev_defaults():
        with TestClient(app) as client:
            return client.post("/api/local-livekit-dev-config")

    def post_livekit_key():
        with TestClient(app) as client:
            return client.post(
                "/api/local-secret-files",
                json={
                    "env_name": "LIVEKIT_API_KEY",
                    "secret_value": "production-livekit-key",
                },
            )

    app.dependency_overrides[get_settings] = lambda: settings
    try:
        with ThreadPoolExecutor(max_workers=2) as executor:
            dev_future = executor.submit(post_dev_defaults)
            assert conflict_checked.wait(timeout=3)
            key_future = executor.submit(post_livekit_key)
            time.sleep(0.1)
            release_dev_write.set()
            dev_response = dev_future.result(timeout=5)
            key_response = key_future.result(timeout=5)

        assert dev_response.status_code == 200
        assert key_response.status_code == 200
        assert api_key_file.read_text(encoding="utf-8") == "production-livekit-key\n"
        assert api_secret_file.read_text(encoding="utf-8") == "secret\n"
        assert json.loads(config_file.read_text(encoding="utf-8")) == {
            "OPENROUTER_LIVEKIT_URL": "ws://127.0.0.1:7880"
        }
    finally:
        release_dev_write.set()
        app.dependency_overrides.clear()


