def test_provider_next_actions_prefer_secret_file_setup_for_missing_secret_values(
    tmp_path: Path,
    monkeypatch,
):
    monkeypatch.delenv("HF_TOKEN", raising=False)
    monkeypatch.delenv("HF_TOKEN_FILE", raising=False)
    monkeypatch.delenv("TAVILY_API_KEY", raising=False)
    monkeypatch.delenv("TAVILY_API_KEY_FILE", raising=False)
    missing_token_file = tmp_path / "missing_hf_token"
    empty_tavily_file = tmp_path / "tavily_api_key"
    empty_tavily_file.write_text("   \n", encoding="utf-8")

    settings = Settings(
        _env_file=None,
        hf_token_file=missing_token_file,
        tavily_api_key_file=empty_tavily_file,
        web_search_provider="tavily",
    )

    readiness = build_provider_readiness(settings)
    providers = {
        provider.provider_id: provider for provider in readiness.providers
    }

    assert providers["gemma4-primary"].secret_files[0].status == "missing"
    assert providers["gemma4-primary"].next_actions[0] == (
        f"Create {missing_token_file} with the HF_TOKEN value, or set HF_TOKEN "
        "directly for this process."
    )
    assert "Set HF_TOKEN in .env" not in " ".join(
        providers["gemma4-primary"].next_actions
    )
    assert providers["tavily-search"].secret_files[0].status == "empty"
    assert providers["tavily-search"].next_actions[0] == (
        f"Put the TAVILY_API_KEY value in {empty_tavily_file}, or set "
        "TAVILY_API_KEY directly for this process."
    )
    assert "Set TAVILY_API_KEY in .env" not in " ".join(
        providers["tavily-search"].next_actions
    )


