def test_voice_runtime_readiness_reports_blocked_non_secret_state(monkeypatch):
    monkeypatch.setattr(
        "all_about_llms.voice_agent.readiness._module_available",
        lambda module_name: False,
    )

    def override_settings():
        return _isolated_voice_runtime_settings()

    app.dependency_overrides[get_settings] = override_settings
    try:
        client = TestClient(app)
        response = client.get("/api/voice-runtime-readiness")

        assert response.status_code == 200
        payload = response.json()
        checks = {check["check_id"]: check for check in payload["checks"]}
        assert payload["status"] == "blocked"
        assert payload["preflight_agent"] is False
        assert checks["livekit-transport"]["status"] == "blocked"
        assert "LIVEKIT_API_KEY" in checks["livekit-transport"]["missing_env"]
        assert checks["livekit-agent-participant"]["status"] == "blocked"
        assert "run-voice-agent" in " ".join(
            checks["livekit-agent-participant"]["next_actions"]
        )
        assert checks["voice-agent-backend-event-sink"]["required"] is False
        assert checks["voice-agent-backend-event-sink"]["status"] == "ready"
        assert checks["voice-agent-backend-event-sink"]["metadata"]["enabled"] is True
        assert checks["gemma-audio-reasoning"]["status"] == "blocked"
        assert "HF_TOKEN" in checks["gemma-audio-reasoning"]["missing_env"]
        assert "secret-livekit-key" not in str(payload)
        assert "secret-hf-token" not in str(payload)
    finally:
        app.dependency_overrides.clear()


def test_voice_runtime_readiness_allows_openrouter_text_turn_dialogue_without_multimodal_endpoint():
    def override_settings():
        return _isolated_voice_runtime_settings(
            openrouter_api_key="secret-openrouter-key",
            gemma4_multimodal_endpoint_url=None,
            gemma4_realtime_reasoning_model="deepseek/deepseek-v4-flash",
            gemma4_realtime_audio_input_model="deepseek/deepseek-v4-flash",
        )

    app.dependency_overrides[get_settings] = override_settings
    try:
        client = TestClient(app)
        response = client.get("/api/voice-runtime-readiness")

        assert response.status_code == 200
        payload = response.json()
        checks = {check["check_id"]: check for check in payload["checks"]}
        reasoning = checks["openrouter-live-dialogue-reasoning"]
        assert reasoning["status"] == "ready"
        assert reasoning["label"] == "OpenRouter live dialogue reasoning"
        assert reasoning["missing_env"] == []
        assert "GEMMA4_MULTIMODAL_ENDPOINT_URL" not in reasoning["missing_env"]
        assert reasoning["metadata"]["voice_reasoning_provider"] == "openrouter"
        assert reasoning["metadata"]["openrouter_chat_completions_configured"] is True
        assert reasoning["metadata"]["audio_input_model"] == (
            "deepseek/deepseek-v4-flash"
        )
        assert reasoning["metadata"]["reasoning_model"] == (
            "deepseek/deepseek-v4-flash"
        )
        assert reasoning["evidence"] == [
            "OpenRouter API key and chat endpoint are configured."
        ]
        native_audio = checks["gemma-audio-reasoning"]
        assert native_audio["required"] is False
        assert native_audio["status"] == "blocked"
        assert "HF_TOKEN" in native_audio["missing_env"]
        assert "GEMMA4_MULTIMODAL_ENDPOINT_URL" in native_audio["missing_env"]
        assert "HF_TOKEN" not in " ".join(payload["next_actions"])
        assert "GEMMA4_MULTIMODAL_ENDPOINT_URL" not in " ".join(
            payload["next_actions"]
        )
        assert "secret-openrouter-key" not in str(payload)
    finally:
        app.dependency_overrides.clear()


