    try:
        client = TestClient(app)
        response = client.get("/api/voice-runtime-readiness")
        assert response.status_code == 200
        hosted = {
            check["check_id"]: check for check in response.json()["checks"]
        }["kokoro-tts"]
        assert hosted["status"] == "ready"
        assert hosted["evidence"] == ["Hosted Kokoro endpoint is configured."]
        assert hosted["metadata"]["kokoro_provider"] == "huggingface_kokoro"
        assert hosted["metadata"]["kokoro_transport"] == "hf_endpoint"
        assert hosted["metadata"]["kokoro_endpoint_configured"] is True
        assert hosted["metadata"]["kokoro_endpoint_supplied"] is True
        assert hosted["metadata"]["kokoro_endpoint_error"] is None
        assert hosted["metadata"]["kokoro_local_package_available"] is True
    finally:
        app.dependency_overrides.clear()

    def local_settings():
        return Settings(kokoro_tts_endpoint_url=" ")

    app.dependency_overrides[get_settings] = local_settings
    try:
        client = TestClient(app)
        response = client.get("/api/voice-runtime-readiness")
        assert response.status_code == 200
        local = {
            check["check_id"]: check for check in response.json()["checks"]
        }["kokoro-tts"]
        assert local["status"] == "ready"
        assert local["evidence"] == ["Local Kokoro package is importable."]
        assert local["metadata"]["kokoro_provider"] == "local_kokoro"
        assert local["metadata"]["kokoro_transport"] == "local_package"
        assert local["metadata"]["kokoro_endpoint_configured"] is False
        assert local["metadata"]["kokoro_endpoint_supplied"] is False
        assert local["metadata"]["kokoro_endpoint_error"] is None
        assert local["metadata"]["kokoro_local_package_available"] is True
    finally:
        app.dependency_overrides.clear()

