def test_voice_agent_process_endpoints_surface_local_supervisor_state():
    supervisor = FakeVoiceAgentSupervisor()

    async def override_supervisor():
        return supervisor

    app.dependency_overrides[get_voice_agent_supervisor] = override_supervisor
    try:
        client = TestClient(app)
        status_response = client.get("/api/voice-agent-process")
        assert status_response.status_code == 200
        status_payload = status_response.json()
        assert status_payload["status"] == "stopped"
        assert status_payload["running"] is False
        assert "run-voice-agent" in " ".join(status_payload["command"])

        start_response = client.post(
            "/api/voice-agent-process/start",
            json={"dev": True, "unregistered": True, "force_restart": True},
        )
        assert start_response.status_code == 200
        start_payload = start_response.json()
        assert start_payload["status"] == "running"
        assert start_payload["running"] is True
        assert start_payload["pid"] == 4321
        assert supervisor.started_with.dev is True
        assert supervisor.started_with.unregistered is True
        assert supervisor.started_with.force_restart is True
        assert "secret" not in str(start_payload).lower()

        stop_response = client.post("/api/voice-agent-process/stop")
        assert stop_response.status_code == 200
        stop_payload = stop_response.json()
        assert stop_payload["status"] == "exited"
        assert stop_payload["returncode"] == 0
        assert supervisor.stopped is True
    finally:
        app.dependency_overrides.clear()


