def test_livekit_preflight_timeout_setting_is_validated():
    with pytest.raises(ValidationError, match="must be positive"):
        Settings(livekit_connectivity_preflight_timeout_seconds=0)
    with pytest.raises(ValidationError, match="must be <= 30"):
        Settings(livekit_connectivity_preflight_timeout_seconds=31)
    with pytest.raises(ValidationError, match="must be finite"):
        Settings(livekit_connectivity_preflight_timeout_seconds="nan")


