def test_provider_smoke_status_contracts_are_typed_and_serialized_as_strings():
    step = ProviderSmokeStepResult(
        step_id="local-postgres-pgvector",
        provider_id="postgres-pgvector",
        provider_type="durable_store",
        title="Load durable run state",
        status="passed",
    )
    readiness = ProviderReadinessResult(
        default_realtime_provider="gemma4_realtime",
        selected_web_search_provider="tavily",
        providers=[],
        summary="No provider readiness needed for contract test.",
    )
    result = ProviderSmokeRunResult(
        run_id=uuid4(),
        status="needs_live_smoke",
        execute_live_calls=False,
        provider_readiness=readiness,
        step_count=1,
        passed_count=1,
        blocked_count=0,
        failed_count=0,
        not_run_count=0,
        tool_boundary_count=0,
        steps=[step],
        summary="Provider smoke is needs_live_smoke.",
    )

    assert step.status == ProviderSmokeStepStatus.PASSED
    assert result.status == ProviderSmokeRunStatus.NEEDS_LIVE_SMOKE
    assert result.model_dump(mode="json")["status"] == "needs_live_smoke"
    assert result.model_dump(mode="json")["steps"][0]["status"] == "passed"
    with pytest.raises(ValidationError):
        ProviderSmokeStepResult(
            step_id="bad-step",
            provider_id="bad-provider",
            provider_type="bad",
            title="Bad step",
            status="degraded",
        )
    with pytest.raises(ValidationError):
        ProviderSmokeRunResult(
            run_id=uuid4(),
            status="degraded",
            execute_live_calls=False,
            provider_readiness=readiness,
            step_count=0,
            passed_count=0,
            blocked_count=0,
            failed_count=0,
            not_run_count=0,
            tool_boundary_count=0,
            summary="Bad run status.",
        )


