def test_realtime_dialogue_ledger_tracks_turns_interruptions_and_followups():
    store = FakeStore()

    async def override_store():
        return store

    session = RealtimeSessionRecord(
        run_id=store.run.run_id,
        provider="openai_realtime",
        provider_session_id="rt-session-1",
        voice="marin",
        instructions="Keep the dialogue interruptible.",
        has_client_secret=True,
    )
    asyncio.run(store.record_realtime_session(session))
    user_turn = ConversationTurn(
        run_id=store.run.run_id,
        speaker="user",
        modality="voice",
        transcript="Pause that and explain the source ledger first.",
        metadata={
            "realtime_session_id": str(session.realtime_session_id),
            "provider": session.provider,
            "provider_session_id": session.provider_session_id,
            "audio_mode": session.audio_mode,
            "interrupted": True,
        },
    )
    asyncio.run(store.record_conversation_turn(user_turn))
    assistant_turn = ConversationTurn(
        run_id=store.run.run_id,
        speaker="assistant",
        modality="voice",
        transcript="Paused. I will explain the source ledger first.",
        metadata={
            "realtime_session_id": str(session.realtime_session_id),
            "provider": session.provider,
            "provider_session_id": session.provider_session_id,
            "audio_mode": session.audio_mode,
            "interrupted": True,
            "responds_to_turn_id": str(user_turn.turn_id),
            "response_kind": "dialogue_ack",
        },
    )
    asyncio.run(store.record_conversation_turn(assistant_turn))
    followup = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="realtime-conversation-host",
        recipient_agent_id="realtime-conversation-host",
        task_type="summarize_realtime_turn_context",
        payload={
            "workflow": "realtime_turn_followup_v1",
            "source_turn_id": str(user_turn.turn_id),
            "response_turn_id": str(assistant_turn.turn_id),
            "interrupted": True,
        },
    )
    asyncio.run(store.record_agent_message(followup))
    asyncio.run(
        store.record_feedback(
            FeedbackItem(
                run_id=store.run.run_id,
                target_agent_id="realtime-conversation-host",
                feedback_text="Make sure interruptions stop speech cleanly.",
            )
        )
    )
    asyncio.run(
        store.append_event(
            RunEvent(
                run_id=store.run.run_id,
                event_type="realtime_turn_routed",
                actor="realtime-conversation-host",
                payload={
                    "realtime_session_id": str(session.realtime_session_id),
                    "turn_id": str(user_turn.turn_id),
                    "response_turn_id": str(assistant_turn.turn_id),
                    "interrupted": True,
                },
            )
        )
    )

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/realtime-dialogue-ledger",
            json={"record_artifact": True, "event_limit": 100, "turn_limit": 20},
        )

        assert response.status_code == 200
        payload = response.json()
        assert payload["status"] == "needs_attention"
        assert payload["session_count"] == 1
        assert payload["active_session_count"] == 1
        assert payload["turn_count"] == 2
        assert payload["voice_turn_count"] == 2
        assert payload["interrupted_turn_count"] == 2
        assert payload["assistant_response_turn_count"] == 1
        assert payload["unanswered_user_turn_ids"] == []
        assert payload["unacknowledged_interruption_turn_ids"] == []
        assert payload["pending_followup_task_ids"] == [str(followup.message_id)]
        assert payload["open_feedback_count"] == 1
        assert payload["sessions"][0]["turn_count"] == 2
        assert payload["turns"][0]["response_turn_id"] == str(assistant_turn.turn_id)
        assert payload["followup_tasks"][0]["source_turn_id"] == str(user_turn.turn_id)
        assert any(
            "Realtime Conversation Host worker" in action
            for action in payload["recommended_next_actions"]
        )
        assert store.artifacts[-1].artifact_type == ArtifactType.REALTIME_DIALOGUE_LEDGER
        assert store.artifacts[-1].provenance["workflow"] == (
            "realtime_dialogue_ledger_v1"
        )
        assert store.events[-1].event_type == "realtime_dialogue_ledger_built"
        assert store.events[-1].payload["pending_followup_task_count"] == 1
    finally:
        app.dependency_overrides.clear()


