def test_provider_smoke_routes_missing_config_to_inference_specialist_once(
    tmp_path,
    monkeypatch,
):
    store = FakeStore()
    hf_secret_file = tmp_path / "hf_token"
    tavily_secret_file = tmp_path / "tavily_api_key"
    secret_value = "secret-hf-token"

    monkeypatch.setattr(
        "all_about_llms.voice_agent.kokoro.kokoro_local_package_available",
        lambda: False,
    )

    async def override_store():
        return store

    def override_settings():
        return Settings(
            _env_file=None,
            local_provider_config_file=None,
            hf_token=secret_value,
            hf_token_file=hf_secret_file,
            gemma4_primary_endpoint_url=None,
            gemma4_multimodal_endpoint_url=None,
            openrouter_api_key=None,
            openrouter_api_key_file=None,
            openrouter_livekit_url=None,
            gemma4_realtime_livekit_url=None,
            livekit_api_key=None,
            livekit_api_key_file=None,
            livekit_api_secret=None,
            livekit_api_secret_file=None,
            tavily_api_key=None,
            tavily_api_key_file=tavily_secret_file,
            kokoro_tts_endpoint_url=None,
        )

    app.dependency_overrides[get_store] = override_store
    app.dependency_overrides[get_settings] = override_settings
    try:
        client = TestClient(app)
        request = {"record_artifact": True, "execute_live_calls": False}

        first = client.post(
            f"/api/runs/{store.run.run_id}/provider-smoke",
            json=request,
        )
        second = client.post(
            f"/api/runs/{store.run.run_id}/provider-smoke",
            json=request,
        )

        assert first.status_code == 200
        assert second.status_code == 200
        first_payload = first.json()
        assert first_payload["status"] == "blocked"
        followup_ids = first_payload[
            "provider_configuration_followup_message_ids"
        ]
        assert len(followup_ids) == 1
        assert second.json()["provider_configuration_followup_message_ids"] == (
            followup_ids
        )

        assert len(store.agent_messages) == 1
        message = store.agent_messages[0]
        assert str(message.message_id) == followup_ids[0]
        assert message.sender_agent_id == "observability-agent"
        assert message.recipient_agent_id == "inference-systems-engineer"
        assert message.task_type == "review_provider_configuration_blockers"
        assert message.payload["workflow"] == (
            "provider_smoke_configuration_followup_v1"
        )
        assert message.payload["provider_smoke_status"] == "blocked"
        assert message.payload["ledger_artifact_id"] == (
            first_payload["ledger_artifact_id"]
        )
        assert message.payload["blocked_step_count"] >= 3
        blocked_steps = {
            step["step_id"]: step for step in message.payload["blocked_steps"]
        }
        assert "selected-realtime-smoke" in blocked_steps
        assert "gemma-kokoro-voice-streaming-smoke" in blocked_steps
        assert "selected-web-search-smoke" in blocked_steps
        assert blocked_steps["selected-web-search-smoke"]["secret_files"] == [
            {
                "env_name": "TAVILY_API_KEY",
                "file_env_name": "TAVILY_API_KEY_FILE",
                "status": "missing",
                "configured": False,
                "path": str(tavily_secret_file),
                "detail": "TAVILY_API_KEY_FILE points to a missing file.",
            }
        ]
        assert "web-research-agent" in message.payload[
            "recommended_worker_agent_ids"
        ]
        assert message.payload["recommended_worker_use_gemma"] is False
        assert "Do not request, echo, or persist secret values" in (
            message.payload["required_action"]
        )

        serialized_message = json.dumps(message.model_dump(mode="json"))
        assert secret_value not in serialized_message
        assert "secret-hf-token" not in json.dumps(
            [event.model_dump(mode="json") for event in store.events]
        )

        accepted_events = [
            event
            for event in store.events
            if event.event_type == "agent_message_accepted"
            and event.payload.get("task_type")
            == "review_provider_configuration_blockers"
        ]
        followup_events = [
            event
            for event in store.events
            if event.event_type
            == "provider_smoke_configuration_followup_task_created"
        ]
        assert len(accepted_events) == 1
        assert len(followup_events) == 1
        assert followup_events[0].payload["message_id"] == followup_ids[0]
        assert followup_events[0].payload["blocked_step_count"] >= 3
    finally:
        app.dependency_overrides.clear()


def test_provider_smoke_redacts_provider_exception_in_followup_surfaces():
    store = FakeStore()
    leaky_bearer = "Bearer " + ("C" * 24)
    leaky_hf = "hf_" + ("A" * 24)
    leaky_tavily = "tvly-" + ("B" * 24)

    class LeakySearchProvider:
        async def search(self, request):
            raise ProviderConfigurationError(
                "Search failed with "
                f"{leaky_bearer}, {leaky_hf}, and {leaky_tavily}"
            )

    async def override_store():
        return store

    async def override_services():
        return ContentWorkflowServices(search_provider=LeakySearchProvider())

    def override_settings():
        return Settings(
            _env_file=None,
            tavily_api_key="configured-tavily-key",
            web_search_provider="tavily",
        )

    app.dependency_overrides[get_store] = override_store
    app.dependency_overrides[get_content_workflow_services] = override_services
    app.dependency_overrides[get_settings] = override_settings
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/provider-smoke",
            json={
                "record_artifact": True,
                "execute_live_calls": True,
                "include_gemma": False,
                "include_realtime": False,
                "include_web_search": True,
                "include_reranker": False,
                "include_imagegen_boundary": False,
            },
        )

        assert response.status_code == 200
        payload = response.json()
        assert payload["provider_configuration_followup_message_ids"]
        serialized = json.dumps(
            {
                "response": payload,
                "artifacts": [
                    artifact.model_dump(mode="json") for artifact in store.artifacts
                ],
                "messages": [
                    message.model_dump(mode="json")
                    for message in store.agent_messages
                ],
                "events": [event.model_dump(mode="json") for event in store.events],
            }
        )
        assert leaky_bearer not in serialized
        assert leaky_hf not in serialized
        assert leaky_tavily not in serialized
        assert "Bearer [redacted]" in serialized
        assert "hf_[redacted]" in serialized
        assert "tvly-[redacted]" in serialized
    finally:
        app.dependency_overrides.clear()


def test_provider_smoke_followup_replay_converges_after_artifact_write_failure(
    tmp_path,
    monkeypatch,
):
    class ProviderSmokeArtifactFailOnceStore(FakeStore):
        def __init__(self):
            super().__init__()
            self.fail_next_provider_smoke_artifact = True

        async def record_artifact(self, artifact):
            if (
                artifact.artifact_type == ArtifactType.PROVIDER_SMOKE_LEDGER
                and self.fail_next_provider_smoke_artifact
            ):
                self.fail_next_provider_smoke_artifact = False
                raise RuntimeError("provider smoke artifact store offline")
            return await super().record_artifact(artifact)

        async def record_artifact_if_absent(self, artifact):
            if (
                artifact.artifact_type == ArtifactType.PROVIDER_SMOKE_LEDGER
                and self.fail_next_provider_smoke_artifact
            ):
                self.fail_next_provider_smoke_artifact = False
                raise RuntimeError("provider smoke artifact store offline")
            return await super().record_artifact_if_absent(artifact)

    store = ProviderSmokeArtifactFailOnceStore()
    tavily_secret_file = tmp_path / "tavily_api_key"

    monkeypatch.setattr(
        "all_about_llms.voice_agent.kokoro.kokoro_local_package_available",
        lambda: False,
    )

    async def override_store():
        return store

    def override_settings():
        return Settings(
            _env_file=None,
            hf_token=None,
            hf_token_file=tmp_path / "hf_token",
            gemma4_primary_endpoint_url=None,
            gemma4_multimodal_endpoint_url=None,
            gemma4_realtime_livekit_url=None,
            livekit_api_key=None,
            livekit_api_secret=None,
            tavily_api_key=None,
            tavily_api_key_file=tavily_secret_file,
            kokoro_tts_endpoint_url=None,
        )

    app.dependency_overrides[get_store] = override_store
    app.dependency_overrides[get_settings] = override_settings
    try:
        client = TestClient(app, raise_server_exceptions=False)
        request = {"record_artifact": True, "execute_live_calls": False}

        first = client.post(
            f"/api/runs/{store.run.run_id}/provider-smoke",
            json=request,
        )
        assert first.status_code == 500
        assert len(store.agent_messages) == 1
        first_message = store.agent_messages[0]
        first_ledger_artifact_id = first_message.payload["ledger_artifact_id"]
        assert not any(
            str(artifact.artifact_id) == first_ledger_artifact_id
            for artifact in store.artifacts
        )

        second = client.post(
            f"/api/runs/{store.run.run_id}/provider-smoke",
            json=request,
        )

        assert second.status_code == 200
        payload = second.json()
        assert payload["ledger_artifact_id"] == first_ledger_artifact_id
        assert payload["provider_configuration_followup_message_ids"] == [
            str(first_message.message_id)
        ]
        assert len(store.agent_messages) == 1
        assert store.agent_messages[0].payload["ledger_artifact_id"] == (
            payload["ledger_artifact_id"]
        )
        assert any(
            str(artifact.artifact_id) == payload["ledger_artifact_id"]
            for artifact in store.artifacts
        )
        accepted_events = [
            event
            for event in store.events
            if event.event_type == "agent_message_accepted"
            and event.payload.get("task_type")
            == "review_provider_configuration_blockers"
        ]
        followup_events = [
            event
            for event in store.events
            if event.event_type
            == "provider_smoke_configuration_followup_task_created"
        ]
        assert len(accepted_events) == 1
        assert len(followup_events) == 1
    finally:
        app.dependency_overrides.clear()


