def test_provider_smoke_recursively_redacts_realtime_provider_secret_key_variants(
    monkeypatch,
):
    store = FakeStore()
    list_bearer = "Bearer " + ("D" * 24)
    list_hf = "hf_" + ("B" * 24)
    list_tavily = "tvly-" + ("C" * 24)
    leak_values = [
        "v1.camel-binding-token-leak",
        "binding-token-leak",
        "livekit-token-leak",
        "access-token-leak",
        "client-secret-leak",
        "signed-url-leak",
        "api-key-leak",
        "private-key-leak",
        "session-token-leak",
        "websocket-url-leak",
        "Bearer " + ("A" * 24),
        list_bearer,
        list_hf,
        list_tavily,
    ]

    class LeakyValidBindingProvider:
        async def create_session(self, request):
            room_name = "test-livekit-room"
            participant_identity = "creator-test"
            agent_identity = "gemma4-kokoro-agent-test"
