def test_runtime_health_ledger_records_postgres_and_checkpoint_boundaries():
    store = FakeStore()
    asyncio.run(
        store.append_event(
            RunEvent(
                run_id=store.run.run_id,
                event_type="run_checkpoint_recorded",
                actor="agent-harness-engineer",
                payload={"checkpoint_kind": "operator_preflight"},
            )
        )
    )

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/runtime-health-ledger",
            json={
                "record_artifact": True,
                "event_limit": 50,
                "include_static_checks": True,
                "include_run_evidence": True,
                "include_voice_edge_benchmark": False,
            },
        )

        assert response.status_code == 200
        payload = response.json()
        assert payload["status"] == "degraded"
        assert payload["blocked_count"] == 0
        assert payload["unknown_count"] >= 1
        assert payload["ready_count"] >= 7
        check_ids = {check["check_id"] for check in payload["checks"]}
        assert {
            "application-store-api",
            "event-log-runtime-evidence",
            "live-postgres-runtime-evidence",
            "langgraph-checkpoint-runtime-evidence",
            "postgres-application-schema",
            "pgvector-memory-schema",
            "docker-compose-postgres-service",
            "langgraph-postgres-checkpointer",
            "no-sqlite-runtime-boundary",
        } <= check_ids
        assert "voice-edge-local-benchmark" not in check_ids
        live_check = next(
            check
            for check in payload["checks"]
            if check["check_id"] == "live-postgres-runtime-evidence"
        )
        assert live_check["status"] == "unknown"
        assert "does not execute Docker" in " ".join(live_check["evidence"])
        assert payload["ledger_artifact_id"]
        assert store.artifacts[-1].artifact_type == ArtifactType.RUNTIME_HEALTH_LEDGER
        assert store.artifacts[-1].provenance["workflow"] == "runtime_health_ledger_v1"
        assert (
            store.artifacts[-1].provenance["include_voice_edge_benchmark"] is False
        )
        assert store.artifacts[-1].content["blocked_count"] == 0
        assert store.events[-1].event_type == "runtime_health_ledger_built"
        assert store.events[-1].payload["unknown_count"] >= 1
    finally:
        app.dependency_overrides.clear()


