def test_retrieval_quality_ledger_blocks_single_query_single_retriever_cluster():
    store = FakeStore()
    now = datetime.now(timezone.utc)
    for citation_id, title, url, rank in (
        (
            "1",
            "Provider architecture source",
            "https://example-a.com/provider-architecture",
            1,
        ),
        (
            "2",
            "Provider operations source",
            "https://example-b.com/provider-operations",
            2,
        ),
    ):
        asyncio.run(
            store.record_source(
                SourceRecord(
                    run_id=store.run.run_id,
                    citation_id=citation_id,
                    title=title,
                    url=url,
                    publisher="Example",
                    published_at=now - timedelta(days=7),
                    metadata={
                        "source_type": "official_documentation",
                        "search_query": "gemma voice agent architecture",
                        "retriever": "web_search",
                        "search_rank": rank,
                        "snippet": f"{title} discusses Gemma voice agents.",
                    },
                )
            )
        )

    result = asyncio.run(
        RetrievalQualityLedgerWorkflow(store).build(
            store.run.run_id,
            RetrievalQualityLedgerRequest(
                topic="gemma voice agent architecture",
                min_accepted_sources=2,
                require_graph_coverage=True,
                record_artifact=True,
            ),
        )
    )

    assert result.accepted_candidate_count == 2
    assert result.status == RetrievalQualityStatus.NEEDS_MORE_RECALL
    assert result.recall_gap_count >= 1
    diversity_gaps = [
        entry
        for entry in result.graph_coverage
        if entry.node_type == "retrieval_diversity"
        and entry.coverage_status == "gap"
    ]
    assert len(diversity_gaps) == 1
    assert diversity_gaps[0].node_id == "retrieval_diversity:query_retriever"
    assert "single query and retriever" in diversity_gaps[0].notes
    assert all(
        "single_query_single_retriever_cluster" in candidate.recall_risks
        for candidate in result.candidates
        if candidate.accepted_for_context
    )
    assert any(
        query == "gemma voice agent architecture independent corroborating sources"
        for query in result.recommended_queries
    )
    assert store.retrieval_quality_results[-1].recall_gap_count >= 1


def test_retrieval_quality_ledger_blocks_unproven_query_retriever_diversity():
    store = FakeStore()
    now = datetime.now(timezone.utc)
    source_with_metadata = SourceRecord(
        run_id=store.run.run_id,
        citation_id="1",
        title="Gemma voice architecture source",
        url="https://example-a.com/gemma-voice",
        publisher="Example",
        published_at=now - timedelta(days=4),
        metadata={
            "source_type": "official_documentation",
            "search_query": "gemma voice architecture",
            "retriever": "web_search",
            "search_rank": 1,
            "snippet": "Gemma voice architecture evidence.",
        },
    )
    source_missing_metadata = SourceRecord(
        run_id=store.run.run_id,
        citation_id="2",
        title="Gemma voice operations source",
        url="https://example-b.com/gemma-voice-ops",
        publisher="Example",
        published_at=now - timedelta(days=3),
        metadata={
            "source_type": "official_documentation",
            "search_rank": 2,
            "snippet": "Gemma voice operations evidence.",
        },
    )
    asyncio.run(store.record_source(source_with_metadata))
    asyncio.run(store.record_source(source_missing_metadata))

    result = asyncio.run(
        RetrievalQualityLedgerWorkflow(store).build(
            store.run.run_id,
            RetrievalQualityLedgerRequest(
                topic="gemma voice architecture",
                min_accepted_sources=2,
                record_artifact=True,
            ),
        )
    )

    assert result.accepted_candidate_count == 2
    assert result.status == RetrievalQualityStatus.NEEDS_MORE_RECALL
    gap = next(
        entry
        for entry in result.graph_coverage
        if entry.node_id == "retrieval_diversity:metadata"
    )
    assert gap.coverage_status == "gap"
    assert "query or retriever metadata" in gap.notes
    risky_candidate = next(
        candidate
        for candidate in result.candidates
        if candidate.source_id == source_missing_metadata.source_id
    )
    assert "missing_search_query" in risky_candidate.recall_risks
    assert "unknown_retriever" in risky_candidate.recall_risks
    assert "unproven_query_retriever_diversity" in risky_candidate.recall_risks


