def test_non_ready_retrieval_quality_blocks_claim_verification_and_publish_readiness():
    store = FakeStore()
    now = datetime.now(timezone.utc)
    sources = []
    for citation_id, title, url, rank in (
        (
            "1",
            "Clustered source one",
            "https://example-a.com/clustered-one",
            1,
        ),
        (
            "2",
            "Clustered source two",
            "https://example-b.com/clustered-two",
            2,
        ),
    ):
        source = SourceRecord(
            run_id=store.run.run_id,
            citation_id=citation_id,
            title=title,
            url=url,
            publisher="Example",
            published_at=now - timedelta(days=5),
            metadata={
                "source_type": "official_documentation",
                "search_query": "clustered retrieval proof",
                "retriever": "web_search",
                "search_rank": rank,
                "snippet": f"{title} has clustered retrieval evidence.",
            },
        )
        asyncio.run(store.record_source(source))
        sources.append(source)
    claim = ClaimRecord(
        run_id=store.run.run_id,
        claim_text="Clustered retrieval evidence should not pass publish gates.",
        support_status=ClaimSupportStatus.SUPPORTED,
        source_ids=[source.source_id for source in sources],
        reviewer_agent_id="claim-verification-agent",
    )
    asyncio.run(store.record_claim(claim))
    artifact = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.POST,
        title="Clustered retrieval post",
        uri="artifact://clustered-retrieval-post",
        content={
            "text": "Clustered retrieval evidence should not pass publish gates.",
            "claim_ids": [str(claim.claim_id)],
        },
        source_ids=[source.source_id for source in sources],
        provenance={
            "claim_ids": [str(claim.claim_id)],
            "model_provider": "huggingface",
            "model": "google/gemma-4-E4B-it",
        },
    )
    asyncio.run(store.record_artifact(artifact))
    ledger = asyncio.run(
        RetrievalQualityLedgerWorkflow(store).build(
            store.run.run_id,
            RetrievalQualityLedgerRequest(
                topic="clustered retrieval proof",
                min_accepted_sources=2,
                record_artifact=True,
            ),
        )
    )
    assert ledger.status == RetrievalQualityStatus.NEEDS_MORE_RECALL
    message = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="source-ledger-agent",
        recipient_agent_id="claim-verification-agent",
        task_type="verify_source_refresh_claims",
        payload={"topic": "clustered retrieval proof"},
    )
    asyncio.run(store.record_agent_message(message))

    worker_result = asyncio.run(
        AgentWorker(store).run(
            "claim-verification-agent",
            AgentWorkerRunRequest(
                run_id=store.run.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )
    assert worker_result.processed_tasks[0].generation_mode == (
        "claim_verification_worker"
    )
    assert message.result["retrieval_evidence_required"] is True
    assert str(claim.claim_id) in message.result[
        "missing_accepted_retrieval_claim_ids"
    ]
    assert store.claims[0].support_status == ClaimSupportStatus.UNSUPPORTED

    readiness = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(open_feedback_gate=False),
        )
    )
    assert readiness.status == PublishReadinessStatus.BLOCKED
    assert "retrieval_quality_not_ready" in readiness.blocking_issues
    assert "unsupported_claims" in readiness.blocking_issues


def test_needs_rerank_ledger_with_clean_accepted_sources_supports_claim_but_blocks_publish():
    store = FakeStore()
    now = datetime.now(timezone.utc)
    accepted_sources = []
    for citation_id, title, url, query, retriever in (
        (
            "1",
            "Accepted official source",
            "https://example-a.com/accepted",
            "accepted source official evidence",
            "web_search",
        ),
        (
            "2",
            "Accepted dense source",
            "https://example-b.com/accepted",
            "accepted source implementation evidence",
            "dense_pgvector",
        ),
    ):
        source = SourceRecord(
            run_id=store.run.run_id,
            citation_id=citation_id,
            title=title,
            url=url,
            publisher="Example",
            published_at=now - timedelta(days=2),
            metadata={
                "source_type": "official_documentation",
                "search_query": query,
                "retriever": retriever,
                "search_rank": 1,
                "snippet": f"{title} supports the claim.",
            },
        )
        asyncio.run(store.record_source(source))
        accepted_sources.append(source)
    rejected_source = SourceRecord(
        run_id=store.run.run_id,
        citation_id="3",
        title="Rejected weak source",
        url="https://example-c.com/rejected",
        publisher=None,
        published_at=None,
        metadata={
            "source_type": "web_search_result",
            "search_query": "accepted source broad weak blog",
            "retriever": "web_search",
            "search_rank": 3,
        },
    )
    asyncio.run(store.record_source(rejected_source))
    claim = ClaimRecord(
        run_id=store.run.run_id,
        claim_text="Clean accepted evidence should support this claim.",
        support_status=ClaimSupportStatus.NEEDS_REVIEW,
        source_ids=[source.source_id for source in accepted_sources],
    )
    asyncio.run(store.record_claim(claim))
    artifact = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.POST,
        title="Needs rerank post",
        uri="artifact://needs-rerank-post",
        content={
            "text": "Clean accepted evidence should support this claim.",
            "claim_ids": [str(claim.claim_id)],
        },
        source_ids=[source.source_id for source in accepted_sources],
        provenance={
            "claim_ids": [str(claim.claim_id)],
            "model_provider": "huggingface",
            "model": "google/gemma-4-E4B-it",
        },
    )
    asyncio.run(store.record_artifact(artifact))
    candidates = [
        {
            "candidate_id": f"source:{source.source_id}",
            "source_id": str(source.source_id),
            "citation_id": source.citation_id,
            "title": source.title,
            "url": str(source.url),
            "retrievers": [source.metadata["retriever"]],
            "query": source.metadata["search_query"],
            "source_type": "official_documentation",
            "fused_rank": rank,
            "rerank_score": 0.92,
            "reranker": "test_reranker",
            "rerank_reason": "clean accepted evidence",
            "accepted_for_context": True,
            "quality_status": "strong",
            "freshness_status": "current",
            "precision_risks": [],
            "recall_risks": [],
            "coverage_topics": [source.metadata["search_query"]],
        }
        for rank, source in enumerate(accepted_sources, start=1)
    ]
    candidates.append(
        {
            "candidate_id": f"source:{rejected_source.source_id}",
            "source_id": str(rejected_source.source_id),
            "citation_id": rejected_source.citation_id,
            "title": rejected_source.title,
            "url": str(rejected_source.url),
            "retrievers": ["web_search"],
            "query": "accepted source broad weak blog",
            "source_type": "web_search_result",
            "fused_rank": 3,
            "rerank_score": 0.22,
            "reranker": "test_reranker",
            "rerank_reason": "weak rejected evidence",
            "accepted_for_context": False,
            "quality_status": "weak",
            "freshness_status": "unknown",
            "precision_risks": ["weak_source_quality", "low_rerank_score"],
            "recall_risks": [],
            "coverage_topics": [],
        }
    )
    ledger = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.RETRIEVAL_QUALITY_LEDGER,
        title="Needs rerank ledger",
        uri="artifact://needs-rerank-ledger",
        content={
            "status": "needs_rerank",
            "topic": "accepted source evidence",
            "candidate_count": 3,
            "accepted_candidate_count": 2,
            "reranked_candidate_count": 3,
            "graph_node_count": 3,
            "precision_risk_count": 2,
            "recall_gap_count": 0,
            "coverage_gap_count": 0,
            "recommended_queries": ["accepted source contradictory evidence"],
            "summary": "Rejected candidates need rerank review.",
            "candidates": candidates,
            "graph_coverage": [
                {
                    "node_id": f"source:{source.source_id}",
                    "node_type": "source",
                    "label": source.title,
                    "source_ids": [str(source.source_id)],
                    "claim_ids": [],
                    "traversal_role": "evidence_anchor",
                    "coverage_status": "covered",
                    "notes": "Accepted source evidence.",
                }
                for source in accepted_sources
            ],
        },
        provenance={
            "workflow": "retrieval_quality_ledger_v1",
            "min_accepted_sources": 2,
        },
        source_ids=[source.source_id for source in accepted_sources],
    )
    asyncio.run(store.record_artifact(ledger))
    message = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="source-ledger-agent",
        recipient_agent_id="claim-verification-agent",
        task_type="verify_content_claims",
        payload={"topic": "accepted source evidence"},
    )
    asyncio.run(store.record_agent_message(message))

    worker_result = asyncio.run(
        AgentWorker(store).run(
            "claim-verification-agent",
            AgentWorkerRunRequest(
                run_id=store.run.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    assert worker_result.processed_tasks[0].generation_mode == (
        "claim_verification_worker"
    )
    assert message.result["accepted_retrieval_claim_ids"] == [str(claim.claim_id)]
    assert store.claims[0].support_status == ClaimSupportStatus.SUPPORTED

    readiness = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(open_feedback_gate=False),
        )
    )
    assert readiness.status == PublishReadinessStatus.BLOCKED
    assert "retrieval_quality_not_ready" in readiness.blocking_issues
    assert "unsupported_claims" not in readiness.blocking_issues


def test_retrieval_quality_ledger_blocks_claim_artifact_paths_without_accepted_evidence():
    from all_about_llms.orchestration.retrieval_evidence import (
        accepted_retrieval_evidence_by_source,
    )

    store = FakeStore()
    now = datetime.now(timezone.utc)
    accepted_sources = []
    for citation_id, title, url, query, retriever in (
        (
            "1",
            "Accepted architecture source",
            "https://example-a.com/voice-architecture",
            "voice agent architecture official source",
            "web_search",
        ),
        (
            "2",
            "Accepted latency source",
            "https://example-b.com/voice-latency",
            "voice agent latency benchmark primary",
            "dense_pgvector",
        ),
    ):
        source = SourceRecord(
            run_id=store.run.run_id,
            citation_id=citation_id,
            title=title,
            url=url,
            publisher="Example",
            published_at=now - timedelta(days=1),
            metadata={
                "source_type": "official_documentation",
                "search_query": query,
                "retriever": retriever,
                "search_rank": 1,
                "snippet": f"{title} supports retrieval graph coverage.",
            },
        )
        asyncio.run(store.record_source(source))
        accepted_sources.append(source)

    unaccepted_source = SourceRecord(
        run_id=store.run.run_id,
        citation_id="3",
        title="Unaccepted claim source",
        url="https://example-c.com/unaccepted-claim-source",
        publisher=None,
        published_at=None,
        metadata={
            "source_type": "web_search_result",
            "search_query": "voice agent unsupported blog",
            "retriever": "web_search",
            "search_rank": 9,
        },
    )
    asyncio.run(store.record_source(unaccepted_source))
    claim = ClaimRecord(
        run_id=store.run.run_id,
        claim_text="The voice system has verified end-to-end latency evidence.",
        support_status=ClaimSupportStatus.SUPPORTED,
        source_ids=[unaccepted_source.source_id],
        reviewer_agent_id="claim-verification-agent",
    )
    asyncio.run(store.record_claim(claim))
    artifact = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.REEL_SCRIPT,
        title="Latency reel script",
        uri="artifact://latency-reel-script",
        content={
            "claim_dependency_ids": [str(claim.claim_id)],
            "text": "The voice system has verified end-to-end latency evidence.",
        },
        source_ids=[unaccepted_source.source_id],
    )
    asyncio.run(store.record_artifact(artifact))

    result = asyncio.run(
        RetrievalQualityLedgerWorkflow(store).build(
            store.run.run_id,
            RetrievalQualityLedgerRequest(
                topic="voice agent latency evidence",
                min_accepted_sources=2,
                require_reranking=False,
                record_artifact=True,
            ),
        )
    )

    assert result.accepted_candidate_count == 2
    assert result.status == RetrievalQualityStatus.NEEDS_MORE_RECALL
    claim_gap = next(
        entry
        for entry in result.graph_coverage
        if entry.node_id == f"claim:{claim.claim_id}"
    )
    artifact_gap = next(
        entry
        for entry in result.graph_coverage
        if entry.node_id == f"artifact:{artifact.artifact_id}"
    )
    assert claim_gap.coverage_status == "gap"
    assert artifact_gap.coverage_status == "gap"
    assert "accepted retrieval evidence" in claim_gap.notes
    assert "accepted retrieval evidence" in artifact_gap.notes
    assert any(
        query == "voice agent latency evidence claims evidence verification"
        for query in result.recommended_queries
    )
    evidence = accepted_retrieval_evidence_by_source(store.artifacts)
    assert set(evidence) == {source.source_id for source in accepted_sources}


