def test_rust_retrieval_ranker_provider_maps_subprocess_contract(tmp_path):
    from all_about_llms.providers.rerank import RustRetrievalRankerProvider

    fake_ranker = tmp_path / "fake_ranker.py"
    fake_ranker.write_text(
        """#!/usr/bin/env python3
import json
import sys

payload = json.loads(sys.stdin.read())
assert payload["kind"] == "rank"
assert payload["candidates"][0]["signals"]["vector_score"] == 0.33

print(json.dumps({
    "kind": "rank",
    "request_id": payload["request_id"],
    "results": [
        {
            "id": "second",
            "rank": 1,
            "score": 0.91,
            "source_uri": "https://example.com/second",
            "metadata": {"search_rank": "2"},
            "explanation": {
                "vector_component": 0.4,
                "lexical_component": 0.2,
                "graph_component": 0.1,
                "authority_component": 0.15,
                "freshness_component": 0.06
            }
        },
        {
            "id": "first",
            "rank": 2,
            "score": 0.72,
            "source_uri": "https://example.com/first",
            "metadata": {"search_rank": "1"},
            "explanation": {
                "vector_component": 0.3,
                "lexical_component": 0.2,
                "graph_component": 0.08,
                "authority_component": 0.09,
                "freshness_component": 0.05
            }
        }
    ],
    "diagnostics": {
        "candidate_count": 2,
        "returned_count": 2,
        "scoring_version": "fake"
    }
}))
""",
        encoding="utf-8",
    )
    fake_ranker.chmod(0o755)

    provider = RustRetrievalRankerProvider(fake_ranker, timeout_seconds=1.0)
    results = asyncio.run(
        provider.rerank(
            RerankRequest(
                query="rank grounded sources",
                top_k=2,
                metadata={"request_id": "test-rust-ranker"},
                candidates=[
                    RerankCandidate(
                        candidate_id="first",
                        title="First source",
                        url="https://example.com/first",
                        snippet="A weaker candidate.",
                        rank=1,
                        metadata={"vector_score": 0.33, "search_rank": 1},
                    ),
                    RerankCandidate(
                        candidate_id="second",
                        title="Second source",
                        url="https://example.com/second",
                        snippet="A stronger candidate.",
                        rank=2,
                        metadata={"vector_score": 0.82, "search_rank": 2},
                    ),
                ],
            )
        )
    )

    assert [result.candidate_id for result in results] == ["second", "first"]
    assert results[0].rank_before == 2
    assert results[0].rank_after == 1
    assert results[0].metadata["provider_id"] == "rust_retrieval_ranker_v1"
    assert results[0].metadata["rust_diagnostics"]["scoring_version"] == "fake"
    assert "rust weighted score" in results[0].reason


def test_run_replay_ledger_reconstructs_checkpoint_delta_without_real_database():
    store = FakeStore()
    asyncio.run(
        store.append_event(
            RunEvent(
                run_id=store.run.run_id,
                event_type="initial_state_recorded",
                actor="agent-harness-engineer",
                payload={"phase": "before_checkpoint"},
            )
        )
    )

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        checkpoint_response = client.post(
            f"/api/runs/{store.run.run_id}/checkpoints",
            json={
                "checkpoint_kind": "debug_anchor",
                "created_by": "agent-harness-engineer",
                "notes": "Anchor replay ledger test.",
            },
        )
        assert checkpoint_response.status_code == 200
        checkpoint_payload = checkpoint_response.json()["checkpoint"]
        checkpoint_id = checkpoint_payload["checkpoint_id"]
        assert checkpoint_payload["event_cursor"] == 1

        artifact = ArtifactRecord(
            run_id=store.run.run_id,
            artifact_type=ArtifactType.SYSTEM_PLAN,
            title="After checkpoint plan",
            uri=f"artifact://runs/{store.run.run_id}/after-checkpoint-plan",
            content={"phase": "after_checkpoint"},
            provenance={"workflow": "test_after_checkpoint"},
        )
        asyncio.run(store.record_artifact(artifact))
        asyncio.run(
            store.append_event(
                RunEvent(
                    run_id=store.run.run_id,
                    event_type="artifact_recorded",
                    actor="artifact-librarian",
                    payload=artifact.model_dump(mode="json"),
                )
            )
        )

        replay_response = client.post(
            f"/api/runs/{store.run.run_id}/replay-ledger",
            json={
                "record_artifact": True,
                "checkpoint_id": checkpoint_id,
                "event_limit": 50,
                "include_event_payloads": False,
            },
        )

        assert replay_response.status_code == 200
        payload = replay_response.json()
        assert payload["checkpoint_id"] == checkpoint_id
        assert payload["replay_after_event_id"] == 1
        assert payload["replay_event_count"] == 2
        assert payload["event_type_counts"]["run_checkpoint_recorded"] == 1
        assert payload["event_type_counts"]["artifact_recorded"] == 1
        artifact_delta = next(
            delta for delta in payload["state_deltas"] if delta["key"] == "artifacts"
        )
        assert artifact_delta["checkpoint_value"] == 0
        assert artifact_delta["current_value"] == 1
        assert artifact_delta["delta"] == 1
        assert payload["events"][0]["event_type"] == "run_checkpoint_recorded"
        assert payload["events"][1]["payload_preview"]["artifact_id"]
        assert payload["replay_artifact_id"]
        assert store.artifacts[-1].artifact_type == ArtifactType.RUN_REPLAY_LEDGER
        assert store.artifacts[-1].provenance["workflow"] == "run_replay_ledger_v1"
        assert store.events[-1].event_type == "run_replay_ledger_built"
        assert store.events[-1].payload["replay_event_count"] == 2
    finally:
        app.dependency_overrides.clear()


