        assert payload["skipped_steps"] == [
            "research_source_refresh_unconfigured",
            "research_freshness_blocked_autonomous_pass",
            "retrieval_quality_blocked_autonomous_pass",
            "media_plan_disabled",
            "distribution_package_disabled",
            "source_ledger_disabled",
            "guardrail_audit_disabled",
            "publish_readiness_disabled",
            "work_plan_disabled",
            "sync_pulse_disabled",
            "interactive_note_disabled",
        ]

        event_types = [event.event_type for event in store.events]
        assert "autonomous_studio_pass_started" in event_types
        assert "runtime_health_ledger_built" in event_types
        assert "a2a_collaboration_graph_built" in event_types
        assert "research_freshness_ledger_built" in event_types
        assert "retrieval_quality_ledger_built" in event_types
        assert "autonomous_multimodal_followups_continued" in event_types
        assert "agent_skill_usage_ledger_built" in event_types
        assert "model_routing_ledger_built" in event_types
        assert "provider_smoke_ledger_built" in event_types
        assert "provider_operations_ledger_built" in event_types
        assert "realtime_dialogue_ledger_built" in event_types
        assert "feedback_resolution_ledger_built" in event_types
        assert "foundation_audit_built" in event_types
        assert "run_replay_ledger_built" in event_types
        assert "autonomous_studio_pass_completed" in event_types
        assert "image_generation_prompt_pack_created" in event_types
        assert event_types.count("context_packet_artifact_created") == 4
        continuation_event = next(
            event
            for event in store.events
            if event.event_type == "autonomous_multimodal_followups_continued"
        )
