def test_autonomous_pass_refreshes_blocked_research_sources(tmp_path):
    store = FakeStore()
    workflow = AutonomousStudioPassWorkflow(
        store,
        tmp_path,
        ContentWorkflowServices(search_provider=FakeSearchProvider()),
    )

    result = asyncio.run(
        workflow.run(
            store.run.run_id,
            AutonomousStudioPassRequest(
                run_worker_cycle=False,
                continue_multimodal_followups=False,
                build_missing_media_plans=False,
                build_distribution_package=False,
                refresh_source_ledger=False,
                run_guardrail_audit=False,
                check_publish_readiness=False,
                build_work_plan=False,
                record_sync_pulse=False,
                open_feedback_gate=False,
                use_gemma=False,
            ),
        )
    )

    assert result.research_refresh_cycle is not None
    assert result.research_refresh_cycle.idle is False
    assert result.research_refresh_cycle.processed_tasks[0].generation_mode == (
        "web_search_provider"
    )
    assert result.research_freshness is not None
    assert result.research_freshness.status.value == "ready"
    assert result.a2a_collaboration_graph is not None
    assert result.a2a_collaboration_graph.dependency_cycle_message_ids == []
    assert result.research_freshness.accepted_source_count == 1
    assert result.research_freshness.ledger_artifact_id is not None
    assert "research_freshness_blocked_autonomous_pass" not in result.skipped_steps
    assert "research_source_refresh_unconfigured" not in result.skipped_steps
    assert store.sources[0].metadata["source_type"] == "worker_web_search_result"

    completed_event = store.events[-1]
    assert completed_event.event_type == "autonomous_studio_pass_completed"
    assert completed_event.payload["a2a_graph_blocked"] is False
    assert completed_event.payload["research_freshness_status"] == "ready"
    assert completed_event.payload["research_refresh_processed_tasks"] == 1
    assert completed_event.payload["research_freshness_blocked"] is False
    event_types = [event.event_type for event in store.events]
    assert "agent_message_accepted" in event_types
    assert "autonomous_research_sources_refreshed" in event_types
    assert event_types.count("research_freshness_ledger_built") == 3


def test_foundation_audit_records_requirement_ledger_without_real_database():
    store = FakeStore()

    async def override_store():
        return store

    source = SourceRecord(
        run_id=store.run.run_id,
        citation_id="source-1",
        title="Foundation source",
        url="https://example.com/foundation",
        publisher="Example",
    )
    asyncio.run(store.record_source(source))
    claim = ClaimRecord(
        run_id=store.run.run_id,
        claim_text="The foundation stores durable state in Postgres.",
        support_status=ClaimSupportStatus.SUPPORTED,
        source_ids=[source.source_id],
        reviewer_agent_id="claim-verification-agent",
        notes="Supported by source-1.",
    )
    asyncio.run(store.record_claim(claim))
    content_artifact = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.POST,
        title="Source-backed post",
        uri=f"artifact://runs/{store.run.run_id}/post",
        content={
            "body": "Postgres plus pgvector stores the durable state.",
            "source_citations": ["source-1"],
            "claim_trace": [{"claim_id": str(claim.claim_id)}],
        },
        provenance={
            "workflow": "test_content_workflow",
            "model_provider": "huggingface",
            "model_id": "google/gemma-4-31b-it",
            "claim_trace": [str(claim.claim_id)],
        },
        source_ids=[source.source_id],
        reviewer_decisions=[
            {
                "reviewer_agent_id": "editor-in-chief",
                "status": ReviewDecisionStatus.APPROVED.value,
                "notes": "Foundation audit fixture is source-backed and reviewable.",
            }
        ],
        revision_history=[{"actor": "test", "note": "Initial grounded draft."}],
    )
    asyncio.run(store.record_artifact(content_artifact))
    asyncio.run(
        store.record_feedback(
            FeedbackItem(
                run_id=store.run.run_id,
                target_agent_id="forward-deployed-engineer",
                feedback_text="Keep the audit explicit.",
            )
        )
    )
    asyncio.run(
        store.record_agent_message(
            AgentMessage(
                run_id=store.run.run_id,
                sender_agent_id="product-manager",
                recipient_agent_id="guardrails-agent",
                task_type="review_foundation",
                requires_human_feedback=True,
            )
        )
    )
    for event_type, actor in [
        ("run_created", "agent-harness-engineer"),
        ("realtime_session_created", "realtime-conversation-host"),
        ("research_freshness_ledger_built", "web-research-agent"),
        ("human_feedback_gate_opened", "forward-deployed-engineer"),
        ("feedback_resolution_ledger_built", "forward-deployed-engineer"),
        ("model_routing_ledger_built", "agent-harness-engineer"),
        ("provider_operations_ledger_built", "observability-agent"),
        ("run_checkpoint_recorded", "agent-harness-engineer"),
        ("context_packet_built", "context-engineering-agent"),
        ("interactive_note_generated", "interactive-note-taking-agent"),
    ]:
        asyncio.run(
            store.append_event(
                RunEvent(run_id=store.run.run_id, event_type=event_type, actor=actor)
            )
        )

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/foundation-audit",
            json={
                "record_artifact": True,
                "event_limit": 100,
                "include_static_surface_checks": True,
            },
        )

        assert response.status_code == 200
        payload = response.json()
        assert payload["status"] == "pass"
        assert payload["fail_count"] == 0
        assert payload["check_count"] >= 14
        assert payload["completion_score"] == 1.0
        assert payload["remediation_count"] == 0
        assert payload["blocking_remediation_count"] == 0
        assert payload["remediation_items"] == []
        check_ids = {check["check_id"] for check in payload["checks"]}
        assert "agent-roster-a2a-cards" in check_ids
        assert "agent-skill-source-contracts" in check_ids
        assert "durable-postgres-pgvector" in check_ids
        assert "product-planning-boundary" in check_ids
        assert "source-grounded-artifacts" in check_ids
        assert "model-routing-ledger" in check_ids
        assert "provider-operations-ledger" in check_ids
        skill_source_check = next(
            check
            for check in payload["checks"]
            if check["check_id"] == "agent-skill-source-contracts"
        )
        assert skill_source_check["status"] == "pass"
        assert any(
            "9 skill source contract" in item
            for item in skill_source_check["evidence"]
        )
        assert payload["audit_artifact_id"]
        assert store.artifacts[-1].artifact_type == ArtifactType.FOUNDATION_AUDIT
        assert store.artifacts[-1].provenance["workflow"] == "foundation_audit_v1"
        assert store.artifacts[-1].content["status"] == "pass"
        assert store.events[-1].event_type == "foundation_audit_built"
        assert store.events[-1].payload["completion_score"] == 1.0
        assert store.events[-1].payload["remediation_count"] == 0
    finally:
        app.dependency_overrides.clear()


def test_foundation_audit_fails_when_skill_source_contracts_are_missing(tmp_path):
    store = FakeStore()

    result = asyncio.run(
        FoundationAuditWorkflow(store, project_root=tmp_path).build(
            store.run.run_id,
            FoundationAuditRequest(
                record_artifact=False,
                event_limit=100,
                include_static_surface_checks=True,
            ),
        )
    )

    checks = {check.check_id: check for check in result.checks}
    skill_source_check = checks["agent-skill-source-contracts"]
    assert skill_source_check.status.value == "fail"
    assert any(
        "SKILL.md source file is missing" in missing
        for missing in skill_source_check.missing
    )
    assert any(
        item["check_id"] == "agent-skill-source-contracts"
        and item["owner_agent_id"] == "agent-harness-engineer"
        and item["blocking"] is True
        for item in result.remediation_items
    )
    assert result.status.value == "fail"
    assert result.fail_count >= 1


def test_foundation_audit_fails_when_skill_manifest_is_malformed(tmp_path):
    store = FakeStore()
    _write_valid_skill_sources(tmp_path)
    broken_manifest = (
        tmp_path
        / "skills"
        / "agent-studio-content-production"
        / "agents"
        / "openai.yaml"
    )
    broken_manifest.write_text("interface:\n  display_name: ''\n")

    result = asyncio.run(
        FoundationAuditWorkflow(store, project_root=tmp_path).build(
            store.run.run_id,
            FoundationAuditRequest(
                record_artifact=False,
                event_limit=100,
                include_static_surface_checks=True,
            ),
        )
    )

    skill_source_check = {
        check.check_id: check for check in result.checks
    }["agent-skill-source-contracts"]
    assert skill_source_check.status.value == "fail"
    assert any(
        "OpenAI agents manifest missing required interface fields" in missing
        and "display_name" in missing
        and "short_description" in missing
        and "default_prompt" in missing
        for missing in skill_source_check.missing
    )
    assert result.status.value == "fail"


def _write_valid_skill_sources(root: Path) -> None:
    for skill in SKILL_CARDS:
        skill_dir = root / skill.source_path
        manifest_dir = skill_dir.parent / "agents"
        manifest_dir.mkdir(parents=True)
        skill_dir.write_text(
            "\n".join(
                [
                    "---",
                    f"name: {skill.id}",
                    "description: Test skill source for foundation audit.",
                    "---",
                    f"# {skill.name}",
                    "",
                ]
            )
        )
        (manifest_dir / "openai.yaml").write_text(
            "\n".join(
                [
                    "interface:",
                    f"  display_name: \"{skill.name}\"",
                    "  short_description: \"Test skill manifest.\"",
                    "  default_prompt: \"Use this skill in tests.\"",
                    "",
                ]
            )
        )


