                run_id=store.run.run_id,
                artifact_type=ArtifactType.FOUNDATION_AUDIT,
                title="Foundation requirements audit",
                uri=f"artifact://runs/{store.run.run_id}/foundation-audit",
                content={
                    "status": "needs_attention",
                    "remediation_count": 1,
                    "remediation_items": [
                        {
                            "check_id": "context-and-interactive-notes",
                            "title": "Context packets and interactive notes",
                            "status": "needs_attention",
                            "owner_agent_id": "interactive-note-taking-agent",
                            "blocking": False,
                            "missing": ["No interactive HTML note evidence yet."],
                        }
                    ],
                },
                provenance={"workflow": "foundation_audit_v1"},
