def test_cockpit_demo_run_seeds_complete_reviewable_state():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post("/api/demo/cockpit-run")
        assert response.status_code == 200
        payload = response.json()
    finally:
        app.dependency_overrides.clear()

    assert payload["run"]["status"] == "waiting_for_human"
    assert "OpenRouter DeepSeek" in payload["run"]["goal"]
    assert "Gemma" not in payload["run"]["goal"]
    assert payload["turn"]["transcript"] == (
        "Create grounded ELI5 post, reel, and Substack drafts about an "
        "OpenRouter DeepSeek LiveKit agent studio."
    )
    assert payload["turn"]["metadata"]["source"] == "cockpit_demo"
    assert payload["run"]["conversation_state"]["initial_context"]["topic"] == (
        "OpenRouter DeepSeek LiveKit agent studio"
    )
    assert len(payload["sources"]) == 3
    source_titles = {source["title"] for source in payload["sources"]}
    assert "OpenRouter provider routing documentation" in source_titles
    assert "Gemma 4 model documentation" not in source_titles
    assert len(payload["claims"]) == 2
    claim_text = " ".join(claim["claim_text"] for claim in payload["claims"])
    assert "OpenRouter DeepSeek is the active live-dialogue reasoning layer" in (
        claim_text
    )
    assert "Gemma" not in claim_text
    artifact_types = {artifact["artifact_type"] for artifact in payload["artifacts"]}
    assert {"post", "reel_script", "substack_article"}.issubset(artifact_types)
    assert payload["retrieval_quality"]["status"] == "ready"
    assert payload["retrieval_quality"]["accepted_candidate_count"] == 3
    assert payload["source_ledger"]["accepted_retrieval_source_count"] == 3
    assert payload["source_ledger"]["unsupported_claim_count"] == 0
    assert payload["source_ledger"]["claim_source_matrix_count"] >= 6
    assert payload["feedback_item"]["metadata"]["gate"] == "demo_review_gate"
    assert (
        payload["project_memory"]["memory"]["metadata"]["source"]
        == "cockpit_demo"
    )
    assert (
        payload["project_memory"]["memory"]["metadata"]["project_memory_kind"]
        == "project_decision"
    )
    event_types = [event.event_type for event in store.events]
    assert "retrieval_quality_ledger_built" in event_types
    assert "source_ledger_snapshot_built" in event_types
    assert "project_memory_recorded" in event_types
    assert "cockpit_demo_run_seeded" in event_types
    assert store.status_updates[-1] == RunStatus.WAITING_FOR_HUMAN


