def test_cockpit_walkthrough_rejects_rehearsal_as_provider_smoke():
    store = FakeStore()

    async def override_store():
        return store

    async def override_settings():
        return Settings(
            hf_token="secret-hf-token",
            gemma4_primary_endpoint_url="https://hf.test/gemma-primary",
            openai_api_key="secret-openai-key",
            tavily_api_key="secret-tavily-key",
            realtime_default_provider="openai_realtime",
            web_search_provider="tavily",
        )

    rehearsal = RealtimeSessionRecord(
        run_id=store.run.run_id,
        provider="local_realtime_rehearsal",
        provider_session_id="rehearsal-session",
        voice="marin",
        instructions="Rehearse before provider keys are used.",
        metadata={
            "dry_run": True,
            "not_provider_backed": True,
            "provider_under_test": "openai_realtime",
        },
    )
    asyncio.run(store.record_realtime_session(rehearsal))
    asyncio.run(
        store.record_artifact(
            ArtifactRecord(
                run_id=store.run.run_id,
                artifact_type=ArtifactType.REALTIME_DIALOGUE_LEDGER,
                title="Realtime dialogue ledger",
                uri="artifact://runs/test/realtime-dialogue-ledger",
                content={"status": "ready", "session_count": 1},
            )
        )
    )
    asyncio.run(
        store.append_event(
            RunEvent(
                run_id=store.run.run_id,
                event_type="realtime_turn_routed",
                actor="realtime-conversation-host",
                payload={"realtime_session_id": str(rehearsal.realtime_session_id)},
            )
        )
    )

    app.dependency_overrides[get_store] = override_store
    app.dependency_overrides[get_settings] = override_settings
    try:
        client = TestClient(app)
        rehearsal_response = client.post(
            f"/api/runs/{store.run.run_id}/cockpit-walkthrough-ledger",
            json={
                "record_artifact": False,
                "event_limit": 100,
                "include_runtime_health": False,
            },
        )
        assert rehearsal_response.status_code == 200
        rehearsal_steps = {
            step["step_id"]: step for step in rehearsal_response.json()["steps"]
        }
        realtime_step = rehearsal_steps["realtime-provider-smoke"]
        assert realtime_step["status"] == "blocked"
        assert (
            "provider_backed_realtime_session:openai_realtime"
            in realtime_step["missing_evidence"]
        )
        assert "realtime_turn_recorded_or_routed" not in realtime_step[
            "missing_evidence"
        ]
        assert any(
            evidence == "rehearsal_sessions=1"
            for evidence in realtime_step["evidence"]
        )

        provider_session = RealtimeSessionRecord(
            run_id=store.run.run_id,
            provider="openai_realtime",
            provider_session_id="provider-backed-session",
            voice="marin",
            instructions="Provider-backed smoke.",
            has_client_secret=True,
        )
        asyncio.run(store.record_realtime_session(provider_session))
        provider_response = client.post(
            f"/api/runs/{store.run.run_id}/cockpit-walkthrough-ledger",
            json={
                "record_artifact": False,
                "event_limit": 100,
                "include_runtime_health": False,
            },
        )
        assert provider_response.status_code == 200
        provider_steps = {
            step["step_id"]: step for step in provider_response.json()["steps"]
        }
        provider_realtime_step = provider_steps["realtime-provider-smoke"]
        assert provider_realtime_step["status"] == "blocked"
        assert "provider_backed_realtime_turn:openai_realtime" in provider_realtime_step[
            "missing_evidence"
        ]
        assert "realtime_turn_recorded_or_routed" not in provider_realtime_step[
            "missing_evidence"
        ]
        asyncio.run(
            store.append_event(
                RunEvent(
                    run_id=store.run.run_id,
                    event_type="realtime_turn_routed",
                    actor="realtime-conversation-host",
                    payload={
                        "realtime_session_id": str(provider_session.realtime_session_id)
                    },
                )
            )
        )
        provider_turn_response = client.post(
            f"/api/runs/{store.run.run_id}/cockpit-walkthrough-ledger",
            json={
                "record_artifact": False,
                "event_limit": 100,
                "include_runtime_health": False,
            },
        )
        assert provider_turn_response.status_code == 200
        provider_steps = {
            step["step_id"]: step for step in provider_turn_response.json()["steps"]
        }
        assert provider_steps["realtime-provider-smoke"]["status"] == "ready"

        provider_session.status = RealtimeSessionStatus.ENDED
        ended_session_response = client.post(
            f"/api/runs/{store.run.run_id}/cockpit-walkthrough-ledger",
            json={
                "record_artifact": False,
                "event_limit": 100,
                "include_runtime_health": False,
            },
        )
        assert ended_session_response.status_code == 200
        ended_session_steps = {
            step["step_id"]: step for step in ended_session_response.json()["steps"]
        }
        ended_realtime_step = ended_session_steps["realtime-provider-smoke"]
        assert ended_realtime_step["status"] == "blocked"
        assert (
            "active_provider_backed_realtime_session:openai_realtime"
            in ended_realtime_step["missing_evidence"]
        )

        provider_session.status = RealtimeSessionStatus.ACTIVE
        provider_session.expires_at_unix = int(
            (datetime.now(timezone.utc) - timedelta(minutes=1)).timestamp()
        )
        expired_session_response = client.post(
            f"/api/runs/{store.run.run_id}/cockpit-walkthrough-ledger",
            json={
                "record_artifact": False,
                "event_limit": 100,
                "include_runtime_health": False,
            },
        )
        assert expired_session_response.status_code == 200
        expired_session_steps = {
            step["step_id"]: step for step in expired_session_response.json()["steps"]
        }
        expired_realtime_step = expired_session_steps["realtime-provider-smoke"]
        assert expired_realtime_step["status"] == "blocked"
        assert (
            "unexpired_provider_backed_realtime_session:openai_realtime"
            in expired_realtime_step["missing_evidence"]
        )
    finally:
        app.dependency_overrides.clear()


def test_cockpit_walkthrough_feedback_step_holds_routed_demo_gate():
    run_id = uuid4()
    feedback = FeedbackItem(
        run_id=run_id,
        author="demo",
        target_agent_id="forward-deployed-engineer",
        feedback_text="Demo gate is routed to a specialist but still unresolved.",
        status=FeedbackStatus.ROUTED,
        metadata={"gate": "demo_review_gate", "source": "cockpit_demo"},
    )
    event = RunEvent(
        run_id=run_id,
        event_type="feedback_routed",
        actor="forward-deployed-engineer",
        payload={"feedback_id": str(feedback.feedback_id)},
    )

    step = _feedback_loop_step(feedback_items=[feedback], events=[event])

    assert step.required is True
    assert step.status == "needs_review"
    assert "unresolved_feedback_items" in step.missing_evidence
    assert any("Resolve or explicitly keep open feedback gates" in action for action in step.next_actions)
    assert "feedback_routed" in step.linked_event_types


