def test_project_memory_retrieval_uses_pgvector_and_graph_neighbors():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        first = client.post(
            f"/api/runs/{store.run.run_id}/project-memory",
            json={
                "memory_kind": "project_decision",
                "content": (
                    "Use pgvector hybrid retrieval before promoting project "
                    "memory into autonomous context."
                ),
                "agent_id": "context-engineering-agent",
                "scope": "global",
                "confidence": "high",
                "tags": ["retrieval", "memory"],
                "target_wiki_notes": [
                    "wiki/product/agent-studio-memory-layer.md"
                ],
                "embedding": [0.1, 0.2, 0.3],
            },
        )
        second = client.post(
            f"/api/runs/{store.run.run_id}/project-memory",
            json={
                "memory_kind": "project_decision",
                "content": (
                    "Always-on profiles need memory health review before "
                    "autonomous work continues."
                ),
                "agent_id": "product-manager",
                "scope": "global",
                "confidence": "high",
                "tags": ["retrieval", "memory"],
                "target_wiki_notes": [
                    "wiki/product/agent-studio-memory-layer.md"
                ],
                "embedding": [1.0, 1.0, 1.0],
            },
        )
        unrelated = client.post(
            f"/api/runs/{store.run.run_id}/project-memory",
            json={
                "memory_kind": "project_decision",
                "content": "Realtime voice providers handle interruption policy.",
                "agent_id": "audio-producer",
                "scope": "global",
                "confidence": "high",
                "tags": ["audio", "voice"],
                "target_wiki_notes": ["wiki/product/realtime-audio.md"],
                "embedding": [3.0, 3.0, 3.0],
            },
        )
        response = client.post(
            f"/api/runs/{store.run.run_id}/project-memory/retrieval",
            json={
                "query": "pgvector memory retrieval",
                "query_embedding": [0.1, 0.2, 0.3],
                "seed_limit": 1,
                "memory_limit": 5,
                "graph_depth": 1,
                "record_artifact": True,
            },
        )
    finally:
        app.dependency_overrides.clear()

    assert first.status_code == 200
    assert second.status_code == 200
    assert unrelated.status_code == 200
    assert response.status_code == 200
    payload = response.json()
    first_memory_id = first.json()["memory"]["memory_id"]
    second_memory_id = second.json()["memory"]["memory_id"]
    unrelated_memory_id = unrelated.json()["memory"]["memory_id"]
    retrieved_ids = {
        item["memory"]["memory_id"] for item in payload["memories"]
    }
    assert first_memory_id in retrieved_ids
    assert second_memory_id in retrieved_ids
    assert unrelated_memory_id not in retrieved_ids
    first_item = next(
        item for item in payload["memories"]
        if item["memory"]["memory_id"] == first_memory_id
    )
    second_item = next(
        item for item in payload["memories"]
        if item["memory"]["memory_id"] == second_memory_id
    )
    assert first_item["distance"] == 0.0
    assert first_item["is_seed"] is True
    assert second_item["is_seed"] is False
    assert second_item["graph_score"] > 0
    assert any(
        connector.startswith("tag:retrieval")
        for connector in second_item["shared_connectors"]
    )
    assert payload["artifact_id"]
    assert payload["event_id"]
    assert payload["graph_node_count"] >= 4
    assert payload["graph_edge_count"] >= 4
    assert {
        edge["relationship"] for edge in payload["graph_edges"]
    } >= {"tag", "target_wiki_note"}
    assert any(
        "Review graph-related memories" in action
        for action in payload["recommended_actions"]
    )
    assert store.artifacts[-1].artifact_type == (
        ArtifactType.PROJECT_MEMORY_RETRIEVAL_LEDGER
    )
    assert store.artifacts[-1].provenance["uses_pgvector"] is True
    assert store.events[-1].event_type == "project_memory_retrieval_completed"
    assert store.events[-1].payload["uses_graph_traversal"] is True


def test_project_memory_retrieval_evaluates_precision_recall_and_trend():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        first = client.post(
            f"/api/runs/{store.run.run_id}/project-memory",
            json={
                "memory_kind": "project_decision",
                "content": "Evaluate project memory retrieval with labeled recall.",
                "agent_id": "context-engineering-agent",
                "scope": "global",
                "confidence": "high",
                "tags": ["evaluation", "memory"],
                "target_wiki_notes": [
                    "wiki/product/agent-studio-memory-layer.md"
                ],
                "embedding": [0.1, 0.1, 0.1],
            },
        )
        second = client.post(
            f"/api/runs/{store.run.run_id}/project-memory",
            json={
                "memory_kind": "project_decision",
                "content": "Repeated retrieval runs should show recall trend deltas.",
                "agent_id": "product-manager",
                "scope": "global",
                "confidence": "high",
                "tags": ["evaluation", "memory"],
                "target_wiki_notes": [
                    "wiki/product/agent-studio-memory-layer.md"
                ],
                "embedding": [1.0, 1.0, 1.0],
            },
        )
        first_memory_id = first.json()["memory"]["memory_id"]
        second_memory_id = second.json()["memory"]["memory_id"]
        first_eval = client.post(
            f"/api/runs/{store.run.run_id}/project-memory/retrieval",
            json={
                "query": "memory retrieval evaluation",
                "query_embedding": [0.1, 0.1, 0.1],
                "relevant_memory_ids": [first_memory_id, second_memory_id],
                "seed_limit": 1,
                "memory_limit": 1,
                "graph_depth": 0,
                "record_artifact": True,
            },
        )
        second_eval = client.post(
            f"/api/runs/{store.run.run_id}/project-memory/retrieval",
            json={
                "query": "memory retrieval evaluation",
                "query_embedding": [0.1, 0.1, 0.1],
                "relevant_memory_ids": [first_memory_id, second_memory_id],
                "seed_limit": 1,
                "memory_limit": 5,
                "graph_depth": 1,
                "record_artifact": True,
            },
        )
    finally:
        app.dependency_overrides.clear()

    assert first.status_code == 200
    assert second.status_code == 200
    assert first_eval.status_code == 200
    assert second_eval.status_code == 200
    first_payload = first_eval.json()
    first_metrics = first_payload["evaluation"]
    assert first_metrics["evaluation_mode"] == "labeled"
    assert first_metrics["expected_memory_count"] == 2
    assert first_metrics["retrieved_memory_count"] == 1
    assert first_metrics["relevant_retrieved_count"] == 1
    assert first_metrics["precision"] == 1.0
    assert first_metrics["recall"] == 0.5
    assert first_metrics["recall_gap_count"] == 1
    assert first_metrics["repeated_query_count"] == 1
    assert first_metrics["trend"] == "no_prior"

    second_payload = second_eval.json()
    second_metrics = second_payload["evaluation"]
    assert second_metrics["expected_memory_count"] == 2
    assert second_metrics["retrieved_memory_count"] == 2
    assert second_metrics["precision"] == 1.0
    assert second_metrics["recall"] == 1.0
    assert second_metrics["previous_recall"] == 0.5
    assert second_metrics["recall_delta"] == 0.5
    assert second_metrics["repeated_query_count"] == 2
    assert second_metrics["trend"] == "improved"
    assert second_metrics["false_negative_memory_ids"] == []
    assert store.artifacts[-1].content["evaluation"]["trend"] == "improved"
    assert store.events[-1].payload["recall"] == 1.0
    assert store.events[-1].payload["repeated_query_count"] == 2


def test_context_packet_flags_stale_low_confidence_and_conflicting_project_memories():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        first = client.post(
            f"/api/runs/{store.run.run_id}/project-memory",
            json={
                "memory_kind": "user_preference",
                "content": "Use Obsidian before loading broad chat context.",
                "scope": "global",
                "confidence": "high",
                "tags": ["obsidian", "context"],
                "target_wiki_notes": [
                    "wiki/ops/codex-obsidian-working-memory.md"
                ],
            },
        )
        second = client.post(
            f"/api/runs/{store.run.run_id}/project-memory",
            json={
                "memory_kind": "user_preference",
                "content": "Do not use Obsidian before loading broad chat context.",
                "scope": "global",
                "confidence": "low",
                "tags": ["obsidian", "context"],
                "target_wiki_notes": [
                    "wiki/ops/codex-obsidian-working-memory.md"
                ],
                "metadata": {
                    "expires_at": "2026-01-01T00:00:00+00:00"
                },
            },
        )
        response = client.post(
            f"/api/runs/{store.run.run_id}/context-packet",
            json={
                "agent_id": "context-engineering-agent",
                "record_event": False,
                "max_manifest_items": 20,
            },
        )
    finally:
        app.dependency_overrides.clear()

    assert first.status_code == 200
    assert second.status_code == 200
    assert response.status_code == 200
    payload = response.json()
    memory_health = payload["summary"]["memory_health"]
    assert memory_health["project_memory_count"] == 2
    assert memory_health["stale_memory_count"] == 1
    assert memory_health["low_confidence_memory_count"] == 1
    assert memory_health["conflict_count"] == 1
    assert set(memory_health["conflict_pairs"][0]["terms"]) >= {
        "obsidian",
        "context",
    }
    risk_types = {risk["risk_type"] for risk in payload["context_risks"]}
    assert "stale_project_memories" in risk_types
    assert "low_confidence_project_memories" in risk_types
    assert "conflicting_project_memories" in risk_types
    memory_items = [
        item for item in payload["context_manifest"] if item["item_type"] == "memory"
    ]
    assert len(memory_items) == 2
    assert any(item["metadata"]["is_stale"] for item in memory_items)
    assert any(item["metadata"]["is_low_confidence"] for item in memory_items)
    assert all(item["metadata"]["has_conflict"] for item in memory_items)
    assert any(
        "conflicting project memories" in fetch
        for fetch in payload["recommended_fetches"]
    )


