                title="Source-backed post",
                uri="artifact://runs/test/post",
                content={"claim_ids": [str(claim.claim_id)]},
                provenance={"claim_ids": [str(claim.claim_id)]},
                source_ids=[source_a.source_id, source_b.source_id],
