def test_autonomous_pass_exports_selected_memory_summary_to_obsidian(tmp_path):
    store = FakeStore()
    vault_path = tmp_path / "obsidian-vault"
    asyncio.run(
        ProjectMemoryWorkflow(store).record(
            store.run.run_id,
            ProjectMemoryRecordRequest(
                memory_kind=ProjectMemoryKind.USER_PREFERENCE,
                content=(
                    "Use Obsidian as the project memory source of truth and "
                    "keep HTML viewers as generated companion artifacts."
                ),
                agent_id="context-engineering-agent",
                scope=ProjectMemoryScope.GLOBAL,
                confidence="high",
                tags=["obsidian", "project-memory"],
                target_wiki_notes=[
                    "wiki/ops/codex-obsidian-working-memory.md"
                ],
            ),
        )
    )

    result = asyncio.run(
        AutonomousStudioPassWorkflow(
            store,
            tmp_path,
            obsidian_vault_path=vault_path,
        ).run(
            store.run.run_id,
            AutonomousStudioPassRequest(
                run_runtime_health_check=False,
                build_a2a_collaboration_graph=False,
                run_worker_cycle=False,
                continue_multimodal_followups=False,
                build_research_freshness_ledger=False,
                build_retrieval_quality_ledger=False,
                build_missing_media_plans=False,
                build_distribution_package=False,
                refresh_source_ledger=False,
                run_guardrail_audit=False,
                check_publish_readiness=False,
                build_artifact_index=False,
                build_work_plan=False,
                record_sync_pulse=False,
                build_context_packet=True,
                context_packet_agent_id="context-engineering-agent",
                export_memory_summary_to_obsidian=True,
                memory_summary_limit=5,
                build_skill_usage_ledger=False,
                build_model_routing_ledger=False,
                build_provider_ops_ledger=False,
                build_realtime_dialogue_ledger=False,
                build_feedback_resolution_ledger=False,
                build_foundation_audit=False,
                build_run_replay_ledger=False,
                generate_interactive_note=False,
                create_checkpoint=False,
                open_feedback_gate=False,
                use_gemma=False,
            ),
        )
    )

    artifact = result.obsidian_memory_summary
    assert artifact is not None
    assert artifact.artifact_type == ArtifactType.OBSIDIAN_NOTE
    assert artifact.provenance["workflow"] == "autonomous_memory_summary_export_v1"
    assert artifact.content["note_kind"] == "autonomous_memory_summary"
    assert artifact.content["target_agent_id"] == "context-engineering-agent"
    assert artifact.content["memory_count"] == 1

    note_path = vault_path / artifact.content["relative_path"]
    assert note_path.exists()
    note = note_path.read_text()
    assert "## Selected Memories" in note
    assert "## Memory Health" in note
    assert "Use Obsidian as the project memory source of truth" in note
    assert "Kanban" not in note

    event_types = [event.event_type for event in store.events]
    assert "obsidian_memory_summary_exported" in event_types
    completed_event = store.events[-1]
    assert completed_event.event_type == "autonomous_studio_pass_completed"
    assert completed_event.payload["obsidian_memory_summary_artifact_id"] == str(
        artifact.artifact_id
    )
    assert completed_event.payload["obsidian_memory_summary_memory_count"] == 1
    assert "obsidian_memory_summary" in result.summary


def test_content_studio_orchestration_creates_durable_workflow_without_real_database():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            "/api/orchestrations/content-studio",
            json={
                "transcript": (
                    "Create an ELI5 social post, reel, and detailed Substack "
                    "about Gemma 4 agents."
                ),
                "topic": "Gemma 4 agents",
                "modality": "voice",
                "target_formats": ["post", "reel", "substack"],
                "require_human_feedback": True,
            },
        )
        assert response.status_code == 200
        payload = response.json()
        assert payload["feedback_gate_opened"] is True
        assert len(payload["task_message_ids"]) == 4
        assert len(payload["source_ids"]) == 2
        assert len(payload["claim_ids"]) == 2
        assert len(payload["artifact_ids"]) == 3
        assert len(store.agent_messages) == 4
        assert store.run.status == RunStatus.WAITING_FOR_HUMAN
        assert [artifact.artifact_type.value for artifact in store.artifacts] == [
            "post",
            "reel_script",
            "substack_article",
        ]
        for artifact in store.artifacts:
            assert artifact.content["source_citations"]
            assert artifact.content["claim_trace"]
            assert artifact.content["claims_needing_review_count"] == 2
            assert artifact.provenance["prompt_input"]["topic"] == "Gemma 4 agents"
            assert artifact.provenance["model_provider"] == "deterministic_fallback"
            assert artifact.provenance["source_citation_ids"] == ["S1", "S2"]
            assert artifact.provenance["grounding_contract"] == {
                "source_count": 2,
                "claim_count": 2,
                "requires_claim_review": True,
            }
            assert artifact.reviewer_decisions[0]["reviewer_agent_id"] == (
                "guardrails-agent"
            )
        event_types = [event.event_type for event in store.events]
        assert "orchestration_started" in event_types
        assert event_types.count("agent_message_accepted") == 4
        assert event_types.count("source_recorded") == 2
        assert event_types.count("claim_recorded") == 2
        assert event_types.count("artifact_recorded") == 3
        assert "artifact_grounding_contract_recorded" in event_types
        assert "human_feedback_gate_opened" in event_types

        media_response = client.post(
            f"/api/runs/{payload['run_id']}/media-production",
            json={
                "include_image_prompt": True,
                "include_audio_brief": True,
                "include_video_storyboard": True,
            },
        )
        assert media_response.status_code == 200
        media_payload = media_response.json()
        assert len(media_payload["source_artifact_ids"]) == 3
        assert len(media_payload["media_artifact_ids"]) == 3
        assert media_payload["image_artifact_id"]
        assert media_payload["audio_artifact_id"]
        assert media_payload["video_artifact_id"]
        assert [artifact.artifact_type.value for artifact in store.artifacts[-3:]] == [
            "image",
            "audio",
            "video",
        ]
        assert store.artifacts[-3].provenance["agent_id"] == "image-generation-agent"
        assert store.artifacts[-2].content["format"] == "audio_brief"
        assert store.artifacts[-1].content["format"] == "reel_storyboard"
        media_event_types = [event.event_type for event in store.events]
        assert media_event_types.count("artifact_recorded") == 6
        assert media_event_types[-1] == "media_production_plan_built"

        distribution_response = client.post(
            f"/api/runs/{payload['run_id']}/distribution-package",
            json={
                "platforms": ["instagram_post", "instagram_reel", "linkedin"],
                "audience": "AI builders",
                "campaign_goal": "explain source-backed agents",
                "include_outreach": True,
            },
        )
        assert distribution_response.status_code == 200
        distribution_payload = distribution_response.json()
        assert len(distribution_payload["source_artifact_ids"]) == 3
        assert distribution_payload["platforms"] == [
            "instagram_post",
            "instagram_reel",
            "linkedin",
        ]
        assert store.artifacts[-1].artifact_type == ArtifactType.SOCIAL_PACKAGE
        assert store.artifacts[-1].content["audience"] == "AI builders"
        assert len(store.artifacts[-1].content["platforms"]) == 3
        assert store.artifacts[-1].content["outreach"]["collaboration_pitch"]
        assert store.artifacts[-1].provenance["workflow"] == (
            "distribution_package_v1"
        )
        assert store.artifacts[-1].source_ids
        assert store.artifacts[-1].content["claim_ids"]
        distribution_event_types = [event.event_type for event in store.events]
        assert distribution_event_types.count("artifact_recorded") == 7
        assert distribution_event_types[-1] == "distribution_package_built"

        growth_response = client.post(
            f"/api/runs/{payload['run_id']}/growth-package",
            json={
                "platforms": ["instagram_post", "instagram_reel", "linkedin"],
                "audience": "AI builders",
                "campaign_goal": "explain source-backed agents",
                "include_outreach": True,
                "initiated_by_agent_id": "forward-deployed-engineer",
            },
        )
        assert growth_response.status_code == 200
        growth_payload = growth_response.json()
        assert growth_payload["distribution_artifact_id"] == (
            distribution_payload["distribution_artifact_id"]
        )
        assert len(growth_payload["strategy_artifact_ids"]) == 2
        assert growth_payload["influencer_strategy_artifact_id"] in (
            growth_payload["strategy_artifact_ids"]
        )
        assert growth_payload["outreach_strategy_artifact_id"] in (
            growth_payload["strategy_artifact_ids"]
        )
        assert len(growth_payload["agent_message_ids"]) == 2
        growth_artifacts = [
            artifact
            for artifact in store.artifacts
            if artifact.artifact_type == ArtifactType.GROWTH_STRATEGY
        ]
        assert len(growth_artifacts) == 2
        assert {
            artifact.provenance["workflow"] for artifact in growth_artifacts
        } == {"influencer_strategy_v1", "outreach_strategy_v1"}
        assert all(artifact.source_ids for artifact in growth_artifacts)
        growth_messages = [
            message
            for message in store.agent_messages
            if message.recipient_agent_id
            in {"influencer-strategy-agent", "outreach-agent"}
            and message.sender_agent_id == "forward-deployed-engineer"
        ]
        assert len(growth_messages) == 2
        assert all(message.status == AgentTaskStatus.COMPLETED for message in growth_messages)
        assert all(message.result["strategy_artifact_id"] for message in growth_messages)
        assert all(
            message.result["generation_mode"] == "product_growth_package_route"
            for message in growth_messages
        )
        growth_event_types = [event.event_type for event in store.events]
        assert "influencer_strategy_recorded" in growth_event_types
        assert "outreach_strategy_recorded" in growth_event_types
        assert growth_event_types[-1] == "growth_package_built"
        assert store.events[-1].actor == "forward-deployed-engineer"

        second_growth_response = client.post(
            f"/api/runs/{payload['run_id']}/growth-package",
            json={
                "platforms": ["instagram_post", "instagram_reel", "linkedin"],
                "audience": "AI builders",
                "campaign_goal": "explain source-backed agents",
                "include_outreach": True,
                "initiated_by_agent_id": "forward-deployed-engineer",
            },
        )
        assert second_growth_response.status_code == 200
        second_growth_payload = second_growth_response.json()
        assert second_growth_payload["distribution_artifact_id"] == (
            growth_payload["distribution_artifact_id"]
        )
        assert second_growth_payload["strategy_artifact_ids"] == (
            growth_payload["strategy_artifact_ids"]
        )
        assert len(
            [
                artifact
                for artifact in store.artifacts
                if artifact.artifact_type == ArtifactType.SOCIAL_PACKAGE
            ]
        ) == 1
        assert len(
            [
                artifact
                for artifact in store.artifacts
                if artifact.artifact_type == ArtifactType.GROWTH_STRATEGY
            ]
        ) == 2
        replay_event_types = [event.event_type for event in store.events]
        assert "distribution_package_reused" in replay_event_types
        assert "influencer_strategy_reused" in replay_event_types
        assert "outreach_strategy_reused" in replay_event_types

        messages_response = client.get(
            f"/api/runs/{payload['run_id']}/agent-messages"
        )
        assert messages_response.status_code == 200
        assert len(messages_response.json()["messages"]) == 6
    finally:
        app.dependency_overrides.clear()


def test_growth_package_does_not_reuse_stale_same_source_package(tmp_path):
    store = FakeStore()
    content = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.POST,
        title="Post",
        uri="artifact://runs/test/post",
        content={"topic": "stale package reuse"},
        provenance={},
    )
    asyncio.run(store.record_artifact(content))

    async def override_store():
        return store

    async def override_settings():
        return Settings(
            _env_file=None,
            artifacts_root=tmp_path,
            local_provider_config_file=None,
            hf_token=None,
            hf_token_file=None,
            openrouter_api_key=None,
            openrouter_api_key_file=None,
            openrouter_livekit_url=None,
            livekit_api_key=None,
            livekit_api_key_file=None,
            livekit_api_secret=None,
            livekit_api_secret_file=None,
            tavily_api_key=None,
            tavily_api_key_file=None,
            kokoro_tts_endpoint_url=None,
        )

    app.dependency_overrides[get_store] = override_store
    app.dependency_overrides[get_settings] = override_settings
    try:
        client = TestClient(app)
        old_response = client.post(
            f"/api/runs/{store.run.run_id}/distribution-package",
            json={
                "platforms": ["linkedin"],
                "audience": "AI builders",
                "campaign_goal": "old campaign",
                "include_outreach": True,
            },
        )
        assert old_response.status_code == 200
        old_package_id = old_response.json()["distribution_artifact_id"]

        growth_response = client.post(
            f"/api/runs/{store.run.run_id}/growth-package",
            json={
                "platforms": ["instagram_post", "instagram_reel"],
                "audience": "AI builders",
                "campaign_goal": "new campaign",
                "include_outreach": True,
                "initiated_by_agent_id": "product-manager",
            },
        )
        assert growth_response.status_code == 200
        growth_payload = growth_response.json()
        assert growth_payload["distribution_artifact_id"] != old_package_id
        assert growth_payload["platforms"] == ["instagram_post", "instagram_reel"]
        packages = [
            artifact
            for artifact in store.artifacts
            if artifact.artifact_type == ArtifactType.SOCIAL_PACKAGE
        ]
        assert len(packages) == 2
        growth_package = next(
            artifact
            for artifact in packages
            if str(artifact.artifact_id)
            == growth_payload["distribution_artifact_id"]
        )
        assert growth_package.content["campaign_goal"] == "new campaign"
        assert growth_package.provenance["created_by_agent_id"] == (
            "platform-optimization-agent"
        )
        assert growth_package.provenance["include_outreach"] is True
    finally:
        app.dependency_overrides.clear()


