def test_growth_package_platform_package_uses_idempotent_insert(tmp_path):
    class IdempotentGrowthStore(FakeStore):
        async def record_artifact(self, artifact):
            if artifact.artifact_type == ArtifactType.SOCIAL_PACKAGE:
                raise AssertionError(
                    "growth package platform artifact must be inserted idempotently"
                )
            return await super().record_artifact(artifact)

    store = IdempotentGrowthStore()
    content = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.POST,
        title="Post",
        uri="artifact://runs/test/post",
        content={"topic": "idempotent growth package"},
        provenance={},
    )
    asyncio.run(store.record_artifact(content))

    async def override_store():
        return store

    async def override_settings():
        return Settings(artifacts_root=tmp_path)

    app.dependency_overrides[get_store] = override_store
    app.dependency_overrides[get_settings] = override_settings
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/growth-package",
            json={"platforms": ["linkedin"]},
        )
        assert response.status_code == 200
        packages = [
            artifact
            for artifact in store.artifacts
            if artifact.artifact_type == ArtifactType.SOCIAL_PACKAGE
        ]
        assert len(packages) == 1

        second_response = client.post(
            f"/api/runs/{store.run.run_id}/growth-package",
            json={"platforms": ["linkedin"]},
        )
        assert second_response.status_code == 200
        assert second_response.json()["distribution_artifact_id"] == (
            response.json()["distribution_artifact_id"]
        )
        packages = [
            artifact
            for artifact in store.artifacts
            if artifact.artifact_type == ArtifactType.SOCIAL_PACKAGE
        ]
        assert len(packages) == 1
    finally:
        app.dependency_overrides.clear()


