def test_conversation_router_starts_content_run_from_one_turn():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            "/api/conversation/turns",
            json={
                "transcript": (
                    "Create a grounded ELI5 social post, reel, and Substack "
                    "about natural dialogue agents."
                ),
                "modality": "voice",
                "topic": "natural dialogue agents",
                "require_human_feedback": True,
            },
        )

        assert response.status_code == 200
        payload = response.json()
        assert payload["created_run"] is True
        assert payload["routed_intent"] == "create_content"
        assert payload["response_turn_id"]
        assert payload["feedback_gate_opened"] is True
        assert len(payload["task_message_ids"]) == 4
        assert len(payload["artifact_ids"]) == 3
        assert len(store.turns) == 2
        assert store.turns[-1].speaker == "assistant"
        assert store.turns[-1].metadata["responds_to_turn_id"] == payload["turn_id"]
        assert store.run.status == RunStatus.WAITING_FOR_HUMAN
        assert store.events[-1].event_type == "conversation_turn_routed"
        assert store.events[-1].payload["action"] == "content_workflow_started"
        assert store.events[-1].payload["response_turn_id"] == payload[
            "response_turn_id"
        ]
    finally:
        app.dependency_overrides.clear()


def test_conversation_router_routes_feedback_into_revision_loop():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        start_response = client.post(
            "/api/conversation/turns",
            json={
                "transcript": "Create source-backed content about conversational routing.",
                "topic": "conversational routing",
                "require_human_feedback": True,
            },
        )
        assert start_response.status_code == 200
        run_id = start_response.json()["run_id"]

        revision_response = client.post(
            "/api/conversation/turns",
            json={
                "run_id": run_id,
                "transcript": "Make the hook shorter, more concrete, and keep the source caveat obvious.",
                "modality": "text",
                "require_human_feedback": True,
            },
        )

        assert revision_response.status_code == 200
        payload = revision_response.json()
        assert payload["created_run"] is False
        assert payload["routed_intent"] == "revise_content"
        assert payload["response_turn_id"]
        assert payload["feedback_id"]
        assert len(payload["target_artifact_ids"]) == 1
        assert len(payload["artifact_ids"]) == 1
        assert len(payload["task_message_ids"]) == 4
        assert len(store.turns) == 4
        assert store.turns[-1].speaker == "assistant"
        assert store.turns[-1].metadata["action"] == "feedback_revision_started"
        assert len(store.feedback) == 1
        revised_artifact = next(
            artifact
            for artifact in store.artifacts
            if artifact.artifact_id == UUID(payload["artifact_ids"][0])
        )
        assert revised_artifact.artifact_type == ArtifactType.REEL_SCRIPT
        assert revised_artifact.provenance["parent_artifact_id"] == (
            payload["target_artifact_ids"][0]
        )
        assert store.events[-1].event_type == "conversation_turn_routed"
        assert store.events[-1].payload["action"] == "feedback_revision_started"
        assert store.events[-1].payload["target_artifact_ids"] == (
            payload["target_artifact_ids"]
        )
    finally:
        app.dependency_overrides.clear()


