def test_product_dialogue_turn_can_be_continued_by_worker_cycle_endpoint():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        run_response = client.post(
            "/api/runs",
            json={
                "goal": "Use product dialogue to produce source-backed content.",
                "input_mode": "text",
            },
        )
        assert run_response.status_code == 200
        run_id = run_response.json()["run_id"]

        route_response = client.post(
            "/api/conversation/turns",
            json={
                "run_id": run_id,
                "transcript": (
                    "Create a source-backed post, reel, and Substack about "
                    "Gemma 4 inference engineering."
                ),
                "target_formats": ["post", "reel", "substack"],
                "require_human_feedback": True,
            },
        )
        assert route_response.status_code == 200
        assert route_response.json()["routed_intent"] == "route_task"

        cycle_response = client.post(
            "/api/a2a/workers/run-cycle",
            json={
                "run_id": run_id,
                "agent_ids": [],
                "max_tasks_per_agent": 3,
                "max_rounds": 3,
                "use_gemma": False,
            },
        )

        assert cycle_response.status_code == 200
        cycle_payload = cycle_response.json()
        assert cycle_payload["total_processed_tasks"] >= 3
        assert any(
            artifact.artifact_type == ArtifactType.INTENT_ROUTE_PLAN
            for artifact in store.artifacts
        )
        seed_artifacts = [
            artifact
            for artifact in store.artifacts
            if artifact.provenance.get("workflow")
            == "content_strategy_seed_artifact_v1"
        ]
        assert {artifact.artifact_type for artifact in seed_artifacts} == {
            ArtifactType.POST,
            ArtifactType.REEL_SCRIPT,
            ArtifactType.SUBSTACK_ARTICLE,
        }
        assert all(artifact.content["publishable"] is False for artifact in seed_artifacts)
        assert any(
            artifact.provenance.get("workflow") == "content_writer_worker_v1"
            for artifact in store.artifacts
        )
        assert store.events[-1].event_type == "agent_worker_cycle_completed"
    finally:
        app.dependency_overrides.clear()


def test_agent_worker_intent_router_records_route_plan_and_specialist_handoffs():
    store = FakeStore()
    route_result = asyncio.run(
        ConversationRouter(store).route(
            ConversationRouteRequest(
                run_id=store.run.run_id,
                transcript=(
                    "Plan a reel with voiceover, source checks, thumbnail, "
                    "and hashtags for agent reels."
                ),
                topic="agent reels",
                target_formats=["reel", "post"],
                intent=ConversationRouteIntent.ROUTE_TASK,
                require_human_feedback=False,
            )
        )
    )
    inbound_message = store.agent_messages[-1]

    result = asyncio.run(
        AgentWorker(store).run(
            "intent-router",
            AgentWorkerRunRequest(
                run_id=store.run.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    assert route_result.routed_intent == ConversationRouteIntent.ROUTE_TASK
    assert inbound_message.recipient_agent_id == "intent-router"
    assert result.processed_tasks[0].generation_mode == "intent_router_worker"
    assert inbound_message.result["route_plan_artifact_id"]
    route_plans = [
        artifact
        for artifact in store.artifacts
        if artifact.provenance.get("workflow") == "intent_router_worker_v1"
    ]
    assert len(route_plans) == 1
    route_plan = route_plans[0]
    assert route_plan.artifact_type == ArtifactType.INTENT_ROUTE_PLAN
    assert route_plan.content["format"] == "intent_route_plan"
    assert route_plan.content["requested_intent"] == "route_task"
    assert route_plan.content["routed_intent"] == "route_task"
    target_agent_ids = set(route_plan.content["target_agent_ids"])
    assert {
        "content-strategist",
        "web-research-agent",
        "source-ledger-agent",
        "visual-director",
        "image-generation-agent",
        "audio-producer",
        "video-reel-producer",
        "platform-optimization-agent",
        "influencer-strategy-agent",
    } <= target_agent_ids
    child_messages = [
        message
        for message in store.agent_messages
        if message.sender_agent_id == "intent-router"
        and message.payload.get("parent_message_id") == str(inbound_message.message_id)
    ]
    assert len(child_messages) == len(route_plan.content["created_task_message_ids"])
    assert {message.recipient_agent_id for message in child_messages} == target_agent_ids
    assert all(
        message.payload["route_plan_artifact_id"] == str(route_plan.artifact_id)
        for message in child_messages
    )
    event_types = [event.event_type for event in store.events]
    assert "intent_route_plan_created" in event_types
    assert "agent_message_accepted" in event_types
    assert "artifact_recorded" in event_types


def test_agent_worker_realtime_host_records_conversation_brief():
    store = FakeStore()
    session = asyncio.run(
        store.record_realtime_session(
            RealtimeSessionRecord(
                run_id=store.run.run_id,
                provider="openai_realtime",
                provider_session_id="rt-worker-test",
                voice="alloy",
                audio_mode="speech_to_speech",
                instructions="Keep dialogue natural and route specialist work.",
                has_client_secret=True,
                has_websocket_url=True,
            )
        )
    )
    asyncio.run(
        store.record_conversation_turn(
            ConversationTurn(
                run_id=store.run.run_id,
                speaker="user",
                modality="voice",
                transcript="Pause that voiceover and make the next spoken reply shorter.",
                metadata={
                    "realtime_session_id": str(session.realtime_session_id),
                    "interrupted": True,
                },
            )
        )
    )
    control_event = asyncio.run(
        store.append_event(
            RunEvent(
                run_id=store.run.run_id,
                event_type="realtime_session_control_recorded",
                actor="realtime-conversation-host",
                payload={
                    "realtime_session_id": str(session.realtime_session_id),
                    "provider": session.provider,
                    "provider_session_id": session.provider_session_id,
                    "audio_mode": session.audio_mode,
                    "voice": session.voice,
                    "action": "interrupt",
                    "reason": "User clicked the cockpit interrupt control.",
                    "followup_task_message_id": None,
                },
            )
        )
    )
    feedback = asyncio.run(
        store.record_feedback(
            FeedbackItem(
                run_id=store.run.run_id,
                author="user",
                target_agent_id="realtime-conversation-host",
                feedback_text="The spoken reply should stop immediately when I interrupt.",
                status=FeedbackStatus.ROUTED,
                metadata={"focus": "voice"},
            )
        )
    )
    message = asyncio.run(
        store.record_agent_message(
            AgentMessage(
                run_id=store.run.run_id,
                sender_agent_id="forward-deployed-engineer",
                recipient_agent_id="realtime-conversation-host",
                task_type="summarize_realtime_voice_feedback",
                payload={
                    "topic": "voice interruption handling",
                    "feedback_id": str(feedback.feedback_id),
                },
            )
        )
    )

    result = asyncio.run(
        AgentWorker(store).run(
            "realtime-conversation-host",
            AgentWorkerRunRequest(
                run_id=store.run.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    assert result.processed_tasks[0].generation_mode == (
        "realtime_conversation_host_worker"
    )
    assert message.result["brief_artifact_id"]
    briefs = [
        artifact
        for artifact in store.artifacts
        if artifact.provenance.get("workflow")
        == "realtime_conversation_host_worker_v1"
    ]
    assert len(briefs) == 1
    brief = briefs[0]
    assert brief.artifact_type == ArtifactType.REALTIME_CONVERSATION_BRIEF
    assert brief.content["format"] == "realtime_conversation_brief"
    assert brief.content["session_inventory"]["session_count"] == 1
    assert brief.content["session_inventory"]["active_session_count"] == 1
    assert brief.content["turn_inventory"]["voice_user_turn_count"] == 1
    assert brief.content["turn_inventory"]["interrupted_turn_count"] == 1
    assert brief.content["control_event_inventory"]["control_event_count"] == 1
    assert brief.content["control_event_inventory"]["control_action_counts"][
        "interrupt"
    ] == 1
    assert brief.content["control_event_inventory"][
        "unresolved_control_event_ids"
    ] == [control_event.event_id]
    assert brief.content["voice_feedback_count"] == 1
    handoff_agents = {
        handoff["target_agent_id"]
        for handoff in brief.content["recommended_handoffs"]
    }
    assert "forward-deployed-engineer" in handoff_agents
    assert "audio-producer" in handoff_agents
    assert "product-manager" in handoff_agents
    assert "intent-router" in handoff_agents
    assert {
        (handoff["target_agent_id"], handoff["task_type"])
        for handoff in brief.content["recommended_handoffs"]
        if handoff["target_agent_id"] == "audio-producer"
    } == {
        ("audio-producer", "review_interruption_and_resume"),
        ("audio-producer", "review_realtime_control_audio_state"),
    }
    child_messages = [
        child
        for child in store.agent_messages
        if child.payload.get("parent_message_id") == str(message.message_id)
        and child.payload.get("workflow") == "realtime_conversation_handoff_v1"
    ]
    assert {child.recipient_agent_id for child in child_messages} == {
        "forward-deployed-engineer",
        "audio-producer",
        "product-manager",
        "intent-router",
    }
    assert len(child_messages) == 5
    assert all(
        child.sender_agent_id == "realtime-conversation-host"
        and child.payload["brief_artifact_id"] == str(brief.artifact_id)
        and child.payload["transcript"]
        and child.payload["control_event_inventory"]["unresolved_control_event_ids"]
        == [control_event.event_id]
        for child in child_messages
    )
    assert set(brief.content["created_task_message_ids"]) == {
        str(child.message_id) for child in child_messages
    }
    assert set(brief.content["created_target_agent_ids"]) == {
        child.recipient_agent_id for child in child_messages
    }
    assert brief.content["skipped_duplicate_handoff_task_count"] == 0

    duplicate_result = asyncio.run(
        AgentWorker(store)._execute_realtime_conversation_brief(
            message=message,
            context_summary={},
        )
    )
    assert duplicate_result["created_task_message_ids"] == []
    assert duplicate_result["skipped_duplicate_handoff_task_count"] == 5
    assert len(
        [
            child
            for child in store.agent_messages
            if child.payload.get("parent_message_id") == str(message.message_id)
            and child.payload.get("workflow") == "realtime_conversation_handoff_v1"
        ]
    ) == 5
    event_types = [event.event_type for event in store.events]
    assert "realtime_conversation_brief_created" in event_types
    assert "artifact_recorded" in event_types
    assert event_types.count("agent_message_accepted") == 5


