def test_revision_loop_routes_feedback_into_revised_artifacts_without_real_database():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        orchestration_response = client.post(
            "/api/orchestrations/content-studio",
            json={
                "transcript": (
                    "Create a source-backed social post, reel, and Substack "
                    "about voice agents."
                ),
                "topic": "voice agents",
                "require_human_feedback": True,
            },
        )
        assert orchestration_response.status_code == 200
        run_id = orchestration_response.json()["run_id"]

        revision_response = client.post(
            f"/api/runs/{run_id}/revision-loop",
            json={
                "feedback_text": "Make the hook more concrete and add a clearer caveat.",
                "require_human_feedback": True,
            },
        )
        assert revision_response.status_code == 200
        payload = revision_response.json()
        assert payload["feedback_gate_opened"] is True
        assert len(payload["task_message_ids"]) == 4
        assert len(payload["revised_artifact_ids"]) == 3
        assert len(payload["review_decisions"]) == 6
        assert len(store.agent_messages) == 8
        assert store.run.status == RunStatus.WAITING_FOR_HUMAN

        revised_artifacts = [
            artifact
            for artifact in store.artifacts
            if artifact.provenance.get("workflow") == "feedback_revision_v1"
        ]
        assert len(revised_artifacts) == 3
        assert revised_artifacts[0].content["revision_feedback"].startswith(
            "Make the hook"
        )
        assert revised_artifacts[0].provenance["parent_artifact_id"]

        replay_response = client.post(
            f"/api/runs/{run_id}/revision-loop",
            json={
                "feedback_text": "Make the hook more concrete and add a clearer caveat.",
                "require_human_feedback": True,
            },
        )
        assert replay_response.status_code == 200
        replay_payload = replay_response.json()
        assert replay_payload["feedback_id"] == payload["feedback_id"]
        assert replay_payload["task_message_ids"] == payload["task_message_ids"]
        assert replay_payload["revised_artifact_ids"] == (
            payload["revised_artifact_ids"]
        )
        assert len(store.feedback) == 1
        assert len(store.agent_messages) == 8
        assert len(
            [
                artifact
                for artifact in store.artifacts
                if artifact.provenance.get("workflow") == "feedback_revision_v1"
            ]
        ) == 3

        event_types = [event.event_type for event in store.events]
        assert "revision_loop_started" in event_types
        assert "feedback_recorded" in event_types
        assert event_types.count("revision_loop_started") == 1
        assert event_types.count("feedback_recorded") == 1
        assert event_types.count("artifact_revised") == 3
        assert event_types.count("review_decision_recorded") == 6
        assert event_types.count("human_feedback_gate_opened") == 2

        editor_inbox = client.get(
            f"/api/runs/{run_id}/agent-messages"
            "?agent_id=editor-in-chief&direction=inbox"
        )
        assert editor_inbox.status_code == 200
        assert len(editor_inbox.json()["messages"]) == 1
    finally:
        app.dependency_overrides.clear()


def test_revision_loop_feedback_event_redacts_feedback_payload_without_real_database():
    store = FakeStore()
    bearer_value = "Bearer revision-secret-token-1234567890"
    hf_value = "hf_" + "c" * 24
    feedback_text = (
        f"Rewrite the hook but remove {bearer_value} and rotate {hf_value}."
    )

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        orchestration_response = client.post(
            "/api/orchestrations/content-studio",
            json={
                "transcript": "Create source-backed artifacts about voice agents.",
                "topic": "voice agents",
                "require_human_feedback": True,
            },
        )
        assert orchestration_response.status_code == 200
        run_id = orchestration_response.json()["run_id"]

        revision_response = client.post(
            f"/api/runs/{run_id}/revision-loop",
            json={
                "author": f"user {bearer_value}",
                "feedback_text": feedback_text,
                "require_human_feedback": True,
            },
        )
        assert revision_response.status_code == 200
        assert store.feedback[0].feedback_text == feedback_text

        feedback_event = next(
            event for event in store.events if event.event_type == "feedback_recorded"
        )
        event_payload = json.dumps(feedback_event.payload, sort_keys=True)
        assert bearer_value not in event_payload
        assert hf_value not in event_payload
        assert "Bearer [redacted]" in event_payload
        assert "hf_[redacted]" in event_payload
    finally:
        app.dependency_overrides.clear()


def test_revision_loop_replay_repairs_missing_proof_events_after_partial_persistence():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        orchestration_response = client.post(
            "/api/orchestrations/content-studio",
            json={
                "transcript": (
                    "Create a source-backed post, reel, and Substack about "
                    "low-latency voice agents."
                ),
                "topic": "low-latency voice agents",
                "require_human_feedback": True,
            },
        )
        assert orchestration_response.status_code == 200
        run_id = orchestration_response.json()["run_id"]

        revision_request = {
            "feedback_text": "Make the latency caveat easier to understand.",
            "require_human_feedback": True,
        }
        revision_response = client.post(
            f"/api/runs/{run_id}/revision-loop",
            json=revision_request,
        )
        assert revision_response.status_code == 200
        payload = revision_response.json()
        feedback_id = payload["feedback_id"]
        removed_message_id = payload["task_message_ids"][0]
        removed_artifact_id = payload["revised_artifact_ids"][0]

        def should_remove(event):
            if event.event_type in {
                "feedback_recorded",
                "revision_loop_started",
                "human_feedback_gate_opened",
            }:
                return str(event.payload.get("feedback_id")) == feedback_id
            if event.event_type == "agent_message_accepted":
                return str(event.payload.get("message_id")) == removed_message_id
            if event.event_type in {
                "artifact_revised",
                "review_decision_recorded",
            }:
                return str(event.payload.get("artifact_id")) == removed_artifact_id
            return False

        store.events = [event for event in store.events if not should_remove(event)]
        assert not [
            event
            for event in store.events
            if event.event_type == "artifact_revised"
            and str(event.payload.get("artifact_id")) == removed_artifact_id
        ]

        replay_response = client.post(
            f"/api/runs/{run_id}/revision-loop",
            json=revision_request,
        )
        assert replay_response.status_code == 200
        replay_payload = replay_response.json()
        assert replay_payload["feedback_id"] == feedback_id
        assert replay_payload["task_message_ids"] == payload["task_message_ids"]
        assert replay_payload["revised_artifact_ids"] == payload["revised_artifact_ids"]
        assert len(store.feedback) == 1
        assert len(store.agent_messages) == 8
        assert len(
            [
                artifact
                for artifact in store.artifacts
                if artifact.provenance.get("workflow") == "feedback_revision_v1"
            ]
        ) == 3

        revision_events = [
            event
            for event in store.events
            if str(event.payload.get("feedback_id")) == feedback_id
        ]
        assert [
            event.event_type for event in revision_events
        ].count("feedback_recorded") == 1
        assert [
            event.event_type for event in revision_events
        ].count("revision_loop_started") == 1
        assert [
            event.event_type for event in revision_events
        ].count("human_feedback_gate_opened") == 1
        assert len(
            [
                event
                for event in store.events
                if event.event_type == "agent_message_accepted"
                and str(event.payload.get("message_id")) == removed_message_id
            ]
        ) == 1
        assert len(
            [
                event
                for event in store.events
                if event.event_type == "artifact_revised"
                and str(event.payload.get("artifact_id")) == removed_artifact_id
            ]
        ) == 1
        assert len(
            [
                event
                for event in store.events
                if event.event_type == "review_decision_recorded"
                and str(event.payload.get("artifact_id")) == removed_artifact_id
            ]
        ) == 2
        assert len(
            [
                event
                for event in store.events
                if event.event_type == "review_decision_recorded"
                and str(event.payload.get("feedback_id")) == feedback_id
            ]
        ) == 6
    finally:
        app.dependency_overrides.clear()


def test_revision_loop_rejects_explicit_non_content_artifact_targets():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        orchestration_response = client.post(
            "/api/orchestrations/content-studio",
            json={
                "transcript": "Create grounded content about voice agents.",
                "topic": "voice agents",
                "require_human_feedback": True,
            },
        )
        assert orchestration_response.status_code == 200
        run_id = UUID(orchestration_response.json()["run_id"])
        system_plan = ArtifactRecord(
            run_id=run_id,
            artifact_type=ArtifactType.SYSTEM_PLAN,
            title="Operator-only system plan",
            uri=f"artifact://runs/{run_id}/system-plan",
            content={"scope": "planning only"},
            provenance={"workflow": "system_plan_v1"},
        )
        store.artifacts.append(system_plan)
        store.run.artifact_ids.append(system_plan.artifact_id)

        revision_response = client.post(
            f"/api/runs/{run_id}/revision-loop",
            json={
                "feedback_text": "Revise this operational plan as if it were content.",
                "target_artifact_ids": [str(system_plan.artifact_id)],
                "require_human_feedback": True,
            },
        )
        assert revision_response.status_code == 400
        assert revision_response.json()["detail"] == (
            "No content artifacts available for revision"
        )
        assert not [
            feedback
            for feedback in store.feedback
            if feedback.metadata.get("workflow") == "feedback_revision_v1"
        ]
    finally:
        app.dependency_overrides.clear()


def test_revision_loop_replay_ignores_legacy_non_content_feedback_targets():
    store = FakeStore()
    content_result = asyncio.run(
        ContentStudioWorkflow(store).run(
            OrchestrationRequest(
                transcript="Create grounded content about revision safety.",
                topic="revision safety",
                require_human_feedback=False,
            )
        )
    )
    system_plan = ArtifactRecord(
        run_id=content_result.run_id,
        artifact_type=ArtifactType.SYSTEM_PLAN,
        title="Operator-only system plan",
        uri=f"artifact://runs/{content_result.run_id}/system-plan",
        content={"scope": "planning only"},
        provenance={"workflow": "system_plan_v1"},
    )
    asyncio.run(store.record_artifact(system_plan))
    legacy_feedback = FeedbackItem(
        run_id=content_result.run_id,
        author="user",
        target_agent_id="content-strategist",
        feedback_text="Make the revision safer.",
        metadata={
            "workflow": "feedback_revision_v1",
            "target_artifact_ids": [str(system_plan.artifact_id)],
            "require_human_feedback": True,
        },
    )
    asyncio.run(store.record_feedback(legacy_feedback))

    result = asyncio.run(
        RevisionWorkflow(store).run(
            content_result.run_id,
            RevisionRequest(
                feedback_text="Make the revision safer.",
                require_human_feedback=True,
            ),
        )
    )
    assert result.feedback_id == legacy_feedback.feedback_id
    revised_artifacts = [
        artifact
        for artifact in store.artifacts
        if artifact.provenance.get("feedback_id") == str(legacy_feedback.feedback_id)
    ]
    assert len(revised_artifacts) == 3
    assert all(
        artifact.artifact_type
        in {
            ArtifactType.POST,
            ArtifactType.REEL_SCRIPT,
            ArtifactType.SUBSTACK_ARTICLE,
        }
        for artifact in revised_artifacts
    )
    assert all(
        artifact.provenance.get("parent_artifact_id")
        != str(system_plan.artifact_id)
        for artifact in revised_artifacts
    )
    first_revised_artifact_ids = [artifact.artifact_id for artifact in revised_artifacts]
    first_revision_event_count = len(
        [
            event
            for event in store.events
            if event.event_type == "artifact_revised"
            and str(event.payload.get("feedback_id")) == str(legacy_feedback.feedback_id)
        ]
    )

    replay_result = asyncio.run(
        RevisionWorkflow(store).run(
            content_result.run_id,
            RevisionRequest(
                feedback_text="Make the revision safer.",
                require_human_feedback=True,
            ),
        )
    )
    replayed_revised_artifacts = [
        artifact
        for artifact in store.artifacts
        if artifact.provenance.get("feedback_id") == str(legacy_feedback.feedback_id)
    ]
    assert replay_result.revised_artifact_ids == first_revised_artifact_ids
    assert [artifact.artifact_id for artifact in replayed_revised_artifacts] == (
        first_revised_artifact_ids
    )
    assert len(replayed_revised_artifacts) == 3
    assert len(
        [
            event
            for event in store.events
            if event.event_type == "artifact_revised"
            and str(event.payload.get("feedback_id")) == str(legacy_feedback.feedback_id)
        ]
    ) == first_revision_event_count


def test_revision_loop_redacts_provider_failure_reasons_before_events():
    class LeakyGemmaProvider:
        async def complete(self, request):
            hf_token = "hf_" + ("A" * 24)
            tavily_key = "tvly-" + ("B" * 28)
            raise ProviderConfigurationError(
                f"Bearer abc.DEF_123 failed with {hf_token} and {tavily_key}"
            )

    store = FakeStore()
    content_result = asyncio.run(
        ContentStudioWorkflow(store).run(
            OrchestrationRequest(
                transcript="Create grounded content about provider redaction.",
                topic="provider redaction",
                require_human_feedback=False,
            )
        )
    )
    result = asyncio.run(
        RevisionWorkflow(
            store,
            ContentWorkflowServices(gemma_provider=LeakyGemmaProvider()),
        ).run(
            content_result.run_id,
            RevisionRequest(
                feedback_text="Make the provider fallback safer.",
                require_human_feedback=False,
            ),
        )
    )
    assert len(result.revised_artifact_ids) == 3
    fallback_events = [
        event
        for event in store.events
        if event.event_type == "provider_fallback"
        and event.payload.get("provider") == "gemma"
    ]
    assert fallback_events
    for event in fallback_events:
        reason = event.payload["reason"]
        assert "Bearer [redacted]" in reason
        assert "hf_[redacted]" in reason
        assert "tvly-[redacted]" in reason
        assert "abc.DEF_123" not in reason
        assert "A" * 24 not in reason
        assert "B" * 28 not in reason


def test_guardrail_audit_marks_artifacts_that_still_need_claim_review():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        orchestration_response = client.post(
            "/api/orchestrations/content-studio",
            json={
                "transcript": (
                    "Create a grounded social post, reel, and Substack about "
                    "claim audits."
                ),
                "topic": "claim audits",
                "require_human_feedback": True,
            },
        )
        assert orchestration_response.status_code == 200
        run_id = orchestration_response.json()["run_id"]

        audit_response = client.post(
            f"/api/runs/{run_id}/guardrail-audit",
            json={"open_feedback_gate": True},
        )
        assert audit_response.status_code == 200
        payload = audit_response.json()
        assert payload["status"] == "needs_revision"
        assert payload["feedback_gate_opened"] is True
        assert len(payload["audits"]) == 3
        assert len(store.guardrail_audits) == 3
        assert all(audit.status.value == "needs_revision" for audit in store.guardrail_audits)
        assert store.events[-1].event_type == "human_feedback_gate_opened"

        audits_response = client.get(f"/api/runs/{run_id}/guardrail-audits")
        assert audits_response.status_code == 200
        assert len(audits_response.json()["audits"]) == 3
    finally:
        app.dependency_overrides.clear()


def test_guardrail_and_publish_gates_flag_incomplete_artifact_provenance():
    store = FakeStore()
    source = SourceRecord(
        run_id=store.run.run_id,
        citation_id="S1",
        title="Verified provenance source",
        url="https://example.com/provenance-source",
        publisher="Verified source",
        metadata={
            "source_type": "web_search_result",
            "published_at": datetime.now(timezone.utc).isoformat(),
        },
    )
    asyncio.run(store.record_source(source))
    claim = ClaimRecord(
        run_id=store.run.run_id,
        claim_text="Generated artifacts need durable provenance before publishing.",
        support_status=ClaimSupportStatus.SUPPORTED,
        source_ids=[source.source_id],
    )
    asyncio.run(store.record_claim(claim))
    artifact = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.POST,
        title="Incomplete provenance draft",
        uri="artifact://runs/test/incomplete-provenance",
        content={
            "body": "A grounded draft with incomplete provenance metadata.",
            "claim_ids": [str(claim.claim_id)],
            "source_citations": ["S1"],
        },
        provenance={"claim_ids": [str(claim.claim_id)]},
        source_ids=[source.source_id],
    )
    asyncio.run(store.record_artifact(artifact))

    audit = asyncio.run(
        GuardrailAuditWorkflow(store).run(
            store.run.run_id,
            GuardrailAuditRequest(open_feedback_gate=False),
        )
    )
    assert audit.status.value == "needs_revision"
    assert audit.audits[0].blocking_issues == [
        "missing_artifact_revision_history",
        "missing_artifact_reviewer_decisions",
        "missing_artifact_generation_provenance",
    ]

    readiness = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(open_feedback_gate=False),
        )
    )
    assert readiness.status.value == "needs_review"
    assert "missing_artifact_revision_history" in readiness.blocking_issues
    assert "missing_artifact_reviewer_decisions" in readiness.blocking_issues
    assert "missing_artifact_generation_provenance" in readiness.blocking_issues
    assert "guardrail_audit_needs_revision" in readiness.blocking_issues


def test_publish_readiness_blocks_deterministic_fallback_after_quality_gates():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        orchestration_response = client.post(
            "/api/orchestrations/content-studio",
            json={
                "transcript": "Create a grounded post, reel, and Substack about readiness.",
                "topic": "readiness",
                "require_human_feedback": False,
            },
        )
        assert orchestration_response.status_code == 200
        run_id = orchestration_response.json()["run_id"]

        first_check = client.post(
            f"/api/runs/{run_id}/publish-readiness",
            json={"open_feedback_gate": True},
        )
        assert first_check.status_code == 200
        first_payload = first_check.json()
        assert first_payload["ready"] is False
        assert first_payload["status"] == "blocked"
        assert "weak_source_records" in first_payload["blocking_issues"]
        assert "artifact_references_weak_sources" in first_payload["blocking_issues"]
        assert "claims_need_review" in first_payload["blocking_issues"]
        assert "missing_guardrail_audit" in first_payload["blocking_issues"]
        assert first_payload["feedback_gate_opened"] is True
        assert first_payload["feedback_id"]
        assert len(store.feedback) == 1
        assert store.run.status == RunStatus.WAITING_FOR_HUMAN

        resolve_response = client.post(
            f"/api/feedback/{first_payload['feedback_id']}/resolve",
            json={
                "status": "resolved",
                "resolver": "user",
                "resolution_notes": "Readiness feedback acknowledged.",
            },
        )
        assert resolve_response.status_code == 200
        for claim in store.claims:
            claim.support_status = ClaimSupportStatus.SUPPORTED
        for source in store.sources:
            source.metadata = {
                "source_type": "web_search_result",
                "published_at": datetime.now(timezone.utc).isoformat(),
            }
            source.publisher = source.publisher or "Verified source"

        audit_response = client.post(
            f"/api/runs/{run_id}/guardrail-audit",
            json={"open_feedback_gate": False},
        )
        assert audit_response.status_code == 200
        assert audit_response.json()["status"] == "approved"

        ready_check = client.post(
            f"/api/runs/{run_id}/publish-readiness",
            json={
                "open_feedback_gate": True,
                "mark_run_completed_if_ready": True,
            },
        )
        assert ready_check.status_code == 200
        ready_payload = ready_check.json()
        assert ready_payload["ready"] is False
        assert ready_payload["status"] == "blocked"
        assert ready_payload["blocking_issues"] == [
            "deterministic_fallback_content_not_publishable"
        ]
        assert ready_payload["feedback_gate_opened"] is True
        assert ready_payload["feedback_id"]
        assert store.run.status == RunStatus.WAITING_FOR_HUMAN
        event_types = [event.event_type for event in store.events]
        assert event_types.count("publish_readiness_checked") == 2
    finally:
        app.dependency_overrides.clear()


def test_publish_readiness_events_redact_feedback_and_channel_payloads():
    store = FakeStore()
    bearer_value = "Bearer publish-secret-token-1234567890"
    hf_value = "hf_" + "e" * 24
    artifact = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.POST,
        title=f"Publish channel {hf_value}",
        uri="artifact://runs/test/publish-channel-redaction",
        content={
            "body": "Draft needs publication checks.",
            "platforms": [bearer_value, hf_value],
        },
        provenance={"workflow": "test", "platforms": [bearer_value, hf_value]},
    )
    asyncio.run(store.record_artifact(artifact))

    readiness = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(
                open_feedback_gate=True,
                check_publish_channel_readiness=True,
            ),
        )
    )

    assert readiness.status == PublishReadinessStatus.BLOCKED
    assert store.feedback
    assert any(
        check.platform == bearer_value.lower()
        for check in readiness.publish_channel_checks
    )
    durable_payloads = [
        json.dumps(event.payload, sort_keys=True)
        for event in store.events
        if event.event_type
        in {
            "feedback_recorded",
            "human_feedback_gate_opened",
            "publish_readiness_checked",
        }
    ]
    assert durable_payloads
    for payload_text in durable_payloads:
        assert bearer_value not in payload_text
        assert bearer_value.lower() not in payload_text
        assert hf_value not in payload_text
    assert any("Bearer [redacted]" in payload_text for payload_text in durable_payloads)
    assert any("hf_[redacted]" in payload_text for payload_text in durable_payloads)


def test_publish_readiness_channel_smoke_distinguishes_credentials_from_policy(
    tmp_path: Path,
    monkeypatch,
):
    for env_name in (
        "INSTAGRAM_ACCESS_TOKEN",
        "INSTAGRAM_ACCESS_TOKEN_FILE",
        "LINKEDIN_ACCESS_TOKEN",
        "LINKEDIN_ACCESS_TOKEN_FILE",
        "X_ACCESS_TOKEN",
        "X_ACCESS_TOKEN_FILE",
        "X_API_KEY",
        "X_API_KEY_FILE",
        "SUBSTACK_API_TOKEN",
        "SUBSTACK_API_TOKEN_FILE",
    ):
        monkeypatch.delenv(env_name, raising=False)
    store = FakeStore()
    now = datetime.now(timezone.utc)
    source = SourceRecord(
        run_id=store.run.run_id,
        citation_id="S1",
        title="Official publishing policy source",
        url="https://example.com/publishing-policy",
        publisher="Example",
        published_at=now,
        metadata={"source_type": "official_documentation"},
    )
    claim = ClaimRecord(
        run_id=store.run.run_id,
        claim_text="Publishing channel smoke separates credentials from policy.",
        support_status=ClaimSupportStatus.SUPPORTED,
        source_ids=[source.source_id],
    )
    artifact = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.SOCIAL_PACKAGE,
        title="Distribution package",
        uri="artifact://distribution-package",
        content={
            "platforms": [
                {"platform": "instagram_post"},
                {"platform": "linkedin"},
            ],
            "claim_ids": [str(claim.claim_id)],
            "source_dependencies": [{"source_id": str(source.source_id)}],
        },
        provenance={
            "workflow": "distribution_package_v1",
            "model_provider": "huggingface",
            "model_id": "google/gemma-4-E4B-it",
            "prompt_input": "Create a source-backed channel package.",
            "claim_ids": [str(claim.claim_id)],
        },
        source_ids=[source.source_id],
        reviewer_decisions=[
            {
                "reviewer_agent_id": "editor-in-chief",
                "status": ReviewDecisionStatus.APPROVED.value,
            }
        ],
        revision_history=[
            {"actor": "platform-optimization-agent", "note": "Created package."}
        ],
    )
    store.sources = [source]
    store.claims = [claim]
    store.artifacts = [artifact]
    store.guardrail_audits = [
        GuardrailAuditRecord(
            run_id=store.run.run_id,
            artifact_id=artifact.artifact_id,
            status=GuardrailAuditStatus.APPROVED,
            source_coverage=1.0,
            claim_count=1,
            supported_claim_ids=[claim.claim_id],
            notes="Approved for channel smoke testing.",
        )
    ]

    missing_credentials = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(
                open_feedback_gate=False,
                check_publish_channel_readiness=True,
            ),
        )
    )
    assert missing_credentials.status == PublishReadinessStatus.BLOCKED
    assert "missing_publish_channel_credentials" in (
        missing_credentials.blocking_issues
    )
    assert {
        check.platform: check.credential_status
        for check in missing_credentials.publish_channel_checks
    } == {"instagram_post": "missing", "linkedin": "missing"}
    assert all(
        "INSTAGRAM_ACCESS_TOKEN" in check.credential_envs
        or "LINKEDIN_ACCESS_TOKEN" in check.credential_envs
        for check in missing_credentials.publish_channel_checks
    )

    manual_publication_ready = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(
                open_feedback_gate=False,
                check_publish_channel_readiness=True,
                acknowledge_publish_channel_policy=True,
                manual_publication_mode=True,
            ),
        )
    )
    assert manual_publication_ready.status == PublishReadinessStatus.READY
    assert manual_publication_ready.ready is True
    assert manual_publication_ready.blocking_issues == []
    assert {
        check.platform: check.credential_status
        for check in manual_publication_ready.publish_channel_checks
    } == {
        "instagram_post": "manual_not_required",
        "linkedin": "manual_not_required",
    }

    invalid_instagram_file = tmp_path / "invalid_instagram_access_token"
    invalid_instagram_file.write_bytes(b"\xff\xfe\xfd")
    monkeypatch.setenv("INSTAGRAM_ACCESS_TOKEN_FILE", str(invalid_instagram_file))
    invalid_file_credentials = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(
                open_feedback_gate=False,
                check_publish_channel_readiness=True,
            ),
        )
    )
    assert invalid_file_credentials.status == PublishReadinessStatus.BLOCKED
    assert "missing_publish_channel_credentials" in (
        invalid_file_credentials.blocking_issues
    )
    monkeypatch.delenv("INSTAGRAM_ACCESS_TOKEN_FILE", raising=False)

    instagram_file = tmp_path / "instagram_access_token"
    linkedin_file = tmp_path / "linkedin_access_token"
    instagram_file.write_text("file-instagram-token-must-not-echo\n", encoding="utf-8")
    linkedin_file.write_text("file-linkedin-token-must-not-echo\n", encoding="utf-8")
    monkeypatch.setenv("INSTAGRAM_ACCESS_TOKEN_FILE", str(instagram_file))
    monkeypatch.setenv("LINKEDIN_ACCESS_TOKEN_FILE", str(linkedin_file))
    policy_review_from_files = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(
                open_feedback_gate=False,
                check_publish_channel_readiness=True,
            ),
        )
    )
    assert policy_review_from_files.status == PublishReadinessStatus.NEEDS_REVIEW
    assert policy_review_from_files.blocking_issues == [
        "publish_channel_policy_review_required"
    ]
    assert {
        check.platform: check.credential_status
        for check in policy_review_from_files.publish_channel_checks
    } == {"instagram_post": "configured", "linkedin": "configured"}
    assert "file-instagram-token-must-not-echo" not in (
        policy_review_from_files.model_dump_json()
    )
    assert "file-linkedin-token-must-not-echo" not in (
        policy_review_from_files.model_dump_json()
    )

    monkeypatch.setenv("INSTAGRAM_ACCESS_TOKEN", "test-instagram-token")
    monkeypatch.setenv("LINKEDIN_ACCESS_TOKEN", "test-linkedin-token")
    policy_review = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(
                open_feedback_gate=False,
                check_publish_channel_readiness=True,
            ),
        )
    )
    assert policy_review.status == PublishReadinessStatus.NEEDS_REVIEW
    assert policy_review.blocking_issues == [
        "publish_channel_policy_review_required"
    ]
    assert {
        check.platform: check.policy_status
        for check in policy_review.publish_channel_checks
    } == {"instagram_post": "needs_review", "linkedin": "needs_review"}

    ready = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(
                open_feedback_gate=False,
                check_publish_channel_readiness=True,
                acknowledge_publish_channel_policy=True,
            ),
        )
    )
    assert ready.ready is True
    assert ready.status == PublishReadinessStatus.READY
    assert ready.blocking_issues == []
    assert {
        check.platform: check.credential_status
        for check in ready.publish_channel_checks
    } == {"instagram_post": "configured", "linkedin": "configured"}
    event_payloads = [
        event.payload
        for event in store.events
        if event.event_type == "publish_readiness_checked"
    ]
    for secret_value in ("test-instagram-token", "test-linkedin-token"):
        assert secret_value not in policy_review.model_dump_json()
        assert secret_value not in ready.model_dump_json()
        assert secret_value not in str(event_payloads)


def test_publish_readiness_channel_smoke_covers_direct_post_and_reel(
    monkeypatch,
):
    for env_name in (
        "INSTAGRAM_ACCESS_TOKEN",
        "LINKEDIN_ACCESS_TOKEN",
        "X_ACCESS_TOKEN",
        "X_API_KEY",
        "SUBSTACK_API_TOKEN",
    ):
        monkeypatch.delenv(env_name, raising=False)
    store = FakeStore()
    now = datetime.now(timezone.utc)
    source = SourceRecord(
        run_id=store.run.run_id,
        citation_id="S1",
        title="Official direct artifact publishing policy",
        url="https://example.com/direct-publishing-policy",
        publisher="Example",
        published_at=now,
        metadata={"source_type": "official_documentation"},
    )
    claim = ClaimRecord(
        run_id=store.run.run_id,
        claim_text="Direct post and reel artifacts require channel readiness.",
        support_status=ClaimSupportStatus.SUPPORTED,
        source_ids=[source.source_id],
    )
    post = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.POST,
        title="LinkedIn post",
        uri="artifact://linkedin-post",
        content={
            "platforms": ["linkedin"],
            "claim_ids": [str(claim.claim_id)],
            "source_dependencies": [{"source_id": str(source.source_id)}],
            "body": "A sourced LinkedIn post."
        },
        provenance={
            "workflow": "writer_v1",
            "model_provider": "huggingface",
            "model_id": "google/gemma-4-E4B-it",
            "prompt_input": "Write a direct post.",
            "claim_ids": [str(claim.claim_id)],
            "platforms": ["linkedin"],
        },
        source_ids=[source.source_id],
        reviewer_decisions=[
            {
                "reviewer_agent_id": "editor-in-chief",
                "status": ReviewDecisionStatus.APPROVED.value,
            }
        ],
    )
    reel = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.REEL_SCRIPT,
        title="Instagram reel script",
        uri="artifact://instagram-reel",
        content={
            "platforms": ["instagram_reel"],
            "claim_ids": [str(claim.claim_id)],
            "source_dependencies": [{"source_id": str(source.source_id)}],
            "script": "A sourced Instagram reel script."
        },
        provenance={
            "workflow": "script_writer_v1",
            "model_provider": "huggingface",
            "model_id": "google/gemma-4-E4B-it",
            "prompt_input": "Write a direct reel script.",
            "claim_ids": [str(claim.claim_id)],
        },
        source_ids=[source.source_id],
        reviewer_decisions=[
            {
                "reviewer_agent_id": "editor-in-chief",
                "status": ReviewDecisionStatus.APPROVED.value,
            }
        ],
    )
    store.sources = [source]
    store.claims = [claim]
    store.artifacts = [post, reel]
    store.guardrail_audits = [
        GuardrailAuditRecord(
            run_id=store.run.run_id,
            artifact_id=artifact.artifact_id,
            status=GuardrailAuditStatus.APPROVED,
            source_coverage=1.0,
            claim_count=1,
            supported_claim_ids=[claim.claim_id],
            notes="Approved for direct artifact channel smoke testing.",
        )
        for artifact in (post, reel)
    ]

    readiness = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(
                target_artifact_ids=[post.artifact_id, reel.artifact_id],
                open_feedback_gate=False,
                check_publish_channel_readiness=True,
                acknowledge_publish_channel_policy=True,
            ),
        )
    )

    assert readiness.status == PublishReadinessStatus.BLOCKED
    assert "missing_publish_channel_credentials" in readiness.blocking_issues
    assert {
        check.platform: check.credential_status
        for check in readiness.publish_channel_checks
    } == {"linkedin": "missing", "instagram_reel": "missing"}


def test_publish_readiness_channel_smoke_blocks_unknown_platform(monkeypatch):
    monkeypatch.setenv("INSTAGRAM_ACCESS_TOKEN", "test-instagram-token")
    store = FakeStore()
    now = datetime.now(timezone.utc)
    source = SourceRecord(
        run_id=store.run.run_id,
        citation_id="S1",
        title="Official publishing policy source",
        url="https://example.com/publishing-policy",
        publisher="Example",
        published_at=now,
        metadata={"source_type": "official_documentation"},
    )
    claim = ClaimRecord(
        run_id=store.run.run_id,
        claim_text="Unknown publish channels must not pass readiness.",
        support_status=ClaimSupportStatus.SUPPORTED,
        source_ids=[source.source_id],
    )
    artifact = ArtifactRecord(
        run_id=store.run.run_id,
        artifact_type=ArtifactType.SOCIAL_PACKAGE,
        title="Distribution package",
        uri="artifact://distribution-package",
        content={
            "platforms": [
                {"platform": "instagram"},
                {"platform": "mystery_platform"},
            ],
            "claim_ids": [str(claim.claim_id)],
            "source_dependencies": [{"source_id": str(source.source_id)}],
        },
        provenance={
            "workflow": "distribution_package_v1",
            "model_provider": "huggingface",
            "model_id": "google/gemma-4-E4B-it",
            "prompt_input": "Create a source-backed channel package.",
            "claim_ids": [str(claim.claim_id)],
        },
        source_ids=[source.source_id],
        reviewer_decisions=[
            {
                "reviewer_agent_id": "editor-in-chief",
                "status": ReviewDecisionStatus.APPROVED.value,
            }
        ],
        revision_history=[
            {"actor": "platform-optimization-agent", "note": "Created package."}
        ],
    )
    store.sources = [source]
    store.claims = [claim]
    store.artifacts = [artifact]
    store.guardrail_audits = [
        GuardrailAuditRecord(
            run_id=store.run.run_id,
            artifact_id=artifact.artifact_id,
            status=GuardrailAuditStatus.APPROVED,
            source_coverage=1.0,
            claim_count=1,
            supported_claim_ids=[claim.claim_id],
            notes="Approved for channel smoke testing.",
        )
    ]

    readiness = asyncio.run(
        PublishReadinessWorkflow(store).run(
            store.run.run_id,
            PublishReadinessRequest(
                open_feedback_gate=False,
                check_publish_channel_readiness=True,
                acknowledge_publish_channel_policy=True,
            ),
        )
    )

    assert readiness.status == PublishReadinessStatus.BLOCKED
    assert "unsupported_publish_channel" in readiness.blocking_issues
    checks = {check.platform: check for check in readiness.publish_channel_checks}
    assert checks["instagram_post"].credential_status == "configured"
    assert checks["mystery_platform"].credential_status == "unsupported"
    assert checks["mystery_platform"].credential_envs == []
    assert "unsupported_publish_channel" in checks["mystery_platform"].blocking_issues


