class ReversePrecisionRerankerProvider:
    provider_id = "test_precision_reranker_v1"

    def __init__(self):
        self.requests = []

    async def rerank(self, request):
        self.requests.append(request)
        generic, official = request.candidates
        return [
            RerankResult(
                candidate_id=official.candidate_id,
                rank_before=official.rank,
                rank_after=1,
                relevance_score=0.97,
                reason="official provider documentation beats the broad blog",
                metadata={"provider_id": self.provider_id},
            ),
            RerankResult(
                candidate_id=generic.candidate_id,
                rank_before=generic.rank,
                rank_after=2,
                relevance_score=0.42,
                reason="broad overview is lower precision",
                metadata={"provider_id": self.provider_id},
            ),
        ]


