def test_content_studio_orchestration_uses_provider_backed_execution():
    store = FakeStore()
    gemma_provider = FakeGemmaProvider()
    workflow = ContentStudioWorkflow(
        store,
        ContentWorkflowServices(
            search_provider=FakeSearchProvider(),
            gemma_provider=gemma_provider,
        ),
    )

    result = asyncio.run(
        workflow.run(
            OrchestrationRequest(
                transcript="Make a grounded post about Gemma 4 context engineering.",
                topic="Gemma 4 context engineering",
                require_human_feedback=False,
            )
        )
    )

    assert result.feedback_gate_opened is False
    assert len(store.sources) == 1
    assert store.sources[0].metadata["source_type"] == "web_search_result"
    assert store.sources[0].metadata["retriever"] == "web_search"
    assert store.sources[0].metadata["snippet"] == (
        "HF supports chat completion style inference provider calls."
    )
    assert store.sources[0].metadata["search_rank"] == 1
    assert store.sources[0].published_at is not None
    assert store.sources[0].retrieved_at.isoformat().startswith("2026-05-15")
    assert len(store.artifacts) == 3
    assert store.artifacts[0].content["generation_mode"] == "gemma_provider"
    assert "Gemma-created draft" in store.artifacts[0].content["draft"]
    assert store.claims[0].support_status == ClaimSupportStatus.SUPPORTED
    assert store.claims[0].source_ids == [store.sources[0].source_id]
    assert store.claims[0].notes == "Live source grounding was recorded."
    assert store.claims[1].support_status == ClaimSupportStatus.NEEDS_REVIEW
    assert store.claims[1].source_ids == [store.sources[0].source_id]
    for artifact in store.artifacts:
        assert artifact.content["claims_needing_review_count"] == 1
        assert artifact.content["unsupported_claim_count"] == 0
    assert store.artifacts[0].content["source_citations"][0]["citation_id"] == "S1"
    assert store.artifacts[0].content["source_citations"][0]["published_at"]
    assert store.artifacts[0].content["claim_trace"][0]["support_status"] == "supported"
    assert store.artifacts[0].content["claim_trace"][1]["support_status"] == "needs_review"
    assert store.artifacts[0].provenance["model_provider"] == "huggingface"
    assert store.artifacts[0].provenance["model_id"] == "google/gemma-4-31b-it"
    assert store.artifacts[0].provenance["provider_usage"] == {
        "input_tokens": 10,
        "output_tokens": 12,
    }
    assert store.artifacts[0].provenance["prompt_input"]["source_titles"] == [
        "Gemma 4 provider source"
    ]
    source_evidence = store.artifacts[0].provenance["prompt_input"][
        "source_evidence"
    ]
    assert source_evidence[0]["citation_id"] == "S1"
    assert source_evidence[0]["snippet"] == (
        "HF supports chat completion style inference provider calls."
    )
    assert source_evidence[0]["published_at"]
    assert "Source evidence JSON" in gemma_provider.requests[0].user_input
    assert "HF supports chat completion style inference provider calls." in (
        gemma_provider.requests[0].user_input
    )
    event_types = [event.event_type for event in store.events]
    research_event = next(
        event for event in store.events if event.event_type == "web_research_completed"
    )
    assert research_event.payload["provider_result_count"] == 1
    assert research_event.payload["accepted_source_count"] == 1
    assert research_event.payload["deduplicated_result_count"] == 0
    assert research_event.payload["citation_ids"] == ["S1"]
    assert "gemma_synthesis_completed" in event_types
    assert "artifact_grounding_contract_recorded" in event_types
    assert "provider_fallback" not in event_types
    assert store.run.status == RunStatus.COMPLETED

    for claim in store.claims:
        claim.support_status = ClaimSupportStatus.SUPPORTED
    audit = asyncio.run(
        GuardrailAuditWorkflow(store).run(
            result.run_id,
            GuardrailAuditRequest(open_feedback_gate=False),
        )
    )
    assert audit.status.value == "approved"
    readiness = asyncio.run(
        PublishReadinessWorkflow(store).run(
            result.run_id,
            PublishReadinessRequest(open_feedback_gate=False),
        )
    )
    assert readiness.ready is True
    assert readiness.status.value == "ready"
    assert readiness.blocking_issues == []


def test_content_studio_initial_search_failure_is_blocked_and_redacted():
    class InitialLeakySearchProvider:
        async def search(self, request):
            del request
            raise ProviderConfigurationError(
                "Initial Tavily failed with Bearer abc.DEF_123, "
                + "hf_"
                + ("c" * 24)
                + " and "
                + "tvly-"
                + ("d" * 24)
            )

    store = FakeStore()
    workflow = ContentStudioWorkflow(
        store,
        ContentWorkflowServices(search_provider=InitialLeakySearchProvider()),
    )

    result = asyncio.run(
        workflow.run(
            OrchestrationRequest(
                transcript="Make a grounded post about provider redaction.",
                topic="initial search redaction",
                require_human_feedback=False,
            )
        )
    )

    assert result.run_id == store.run.run_id
    assert [source.metadata["source_type"] for source in store.sources] == [
        "search_query_seed",
        "provider_reference",
    ]
    assert store.claims[0].support_status == ClaimSupportStatus.NEEDS_REVIEW
    assert "not accepted evidence" in store.claims[0].notes
    assert store.artifacts[0].content["claims_needing_review_count"] == 2

    fallback_event = next(
        event
        for event in store.events
        if event.event_type == "provider_fallback"
        and event.payload.get("provider") == "web_search"
    )
    blocked_event = next(
        event for event in store.events if event.event_type == "web_research_blocked"
    )
    reason = fallback_event.payload["reason"]
    assert reason == blocked_event.payload["reason"]
    assert "Bearer [redacted]" in reason
    assert "hf_[redacted]" in reason
    assert "tvly-[redacted]" in reason
    assert "c" * 24 not in str(store.events)
    assert "d" * 24 not in str(store.events)
    durable_payload = (
        f"{store.run} {store.events} {store.claims} {store.artifacts} "
        f"{store.agent_messages} {store.sources} {result}"
    )
    assert "abc.DEF_123" not in durable_payload
    assert "c" * 24 not in durable_payload
    assert "d" * 24 not in durable_payload
    for artifact in store.artifacts:
        assert "Bearer [redacted]" not in str(artifact.content)
        assert "hf_[redacted]" not in str(artifact.content)
        assert "tvly-[redacted]" not in str(artifact.content)
    assert blocked_event.payload["blocker"] == "web_search_provider_configuration"
    assert blocked_event.payload["accepted_source_count"] == 0
    assert blocked_event.payload["seed_source_count"] == 1
    assert blocked_event.payload["fallback_source_count"] == 2


