def test_agent_worker_blocks_exhausted_retry_task_before_claiming():
    store = FakeStore()
    message = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="agent-harness-engineer",
        recipient_agent_id="principal-software-engineer",
        task_type="review_poison_retry",
        payload={"topic": "poison task retry cap"},
        attempt_count=3,
        max_attempts=3,
    )
    asyncio.run(store.record_agent_message(message))

    claim = asyncio.run(
        store.try_claim_agent_message(
            message.message_id,
            agent_id="principal-software-engineer",
        )
    )
    assert claim is None

    result = asyncio.run(
        AgentWorker(store).run(
            "principal-software-engineer",
            AgentWorkerRunRequest(
                run_id=store.run.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    assert result.idle is True
    assert result.blocked_exhausted_tasks == 1
    assert result.processed_tasks == []
    assert message.status == AgentTaskStatus.BLOCKED
    assert message.error == "A2A task exhausted retry attempts."
    assert message.result["retry_policy"]["attempt_count"] == 3
    assert message.result["retry_policy"]["max_attempts"] == 3
    assert store.run.status == RunStatus.WAITING_FOR_HUMAN
    assert store.status_updates == [RunStatus.WAITING_FOR_HUMAN]
    event_types = [event.event_type for event in store.events]
    assert event_types == ["agent_message_retry_exhausted"]
    assert store.events[0].payload["attempt_count"] == 3
    assert store.events[0].payload["max_attempts"] == 3


def test_worker_control_events_redact_dependency_waiting_and_retry_exhausted_metadata():
    store = FakeStore()
    fake_hf_token = "hf_" + ("w" * 30)
    fake_tavily_key = "tvly-" + ("x" * 30)
    bearer = "Bearer " + ("y" * 30)
    upstream = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="content-strategist",
        recipient_agent_id="web-research-agent",
        task_type="dependency source",
        status=AgentTaskStatus.ACCEPTED,
    )
    dependency_waiting = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="web-research-agent",
        recipient_agent_id="claim-verification-agent",
        task_type=f"waiting dependency task {fake_hf_token}",
        payload={"topic": "dependency waiting redaction"},
        depends_on_message_ids=[upstream.message_id],
        status=AgentTaskStatus.ACCEPTED,
    )
    retry_exhausted = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="agent-harness-engineer",
        recipient_agent_id="claim-verification-agent",
        task_type=f"retry exhausted task {fake_tavily_key} {bearer}",
        payload={"topic": "retry exhausted redaction"},
        status=AgentTaskStatus.ACCEPTED,
        attempt_count=3,
        max_attempts=3,
    )
    asyncio.run(store.record_agent_message(upstream))
    asyncio.run(store.record_agent_message(dependency_waiting))
    asyncio.run(store.record_agent_message(retry_exhausted))

    result = asyncio.run(
        AgentWorker(store).run(
            "claim-verification-agent",
            AgentWorkerRunRequest(
                run_id=store.run.run_id,
                max_tasks=10,
                use_gemma=False,
            ),
        )
    )

    dependency_event = next(
        event
        for event in store.events
        if event.event_type == "agent_message_dependency_waiting"
    )
    exhausted_event = next(
        event
        for event in store.events
        if event.event_type == "agent_message_retry_exhausted"
    )
    serialized_events = json.dumps([dependency_event.payload, exhausted_event.payload])

    assert result.dependency_blocked_tasks == 1
    assert result.blocked_exhausted_tasks == 1
    assert dependency_event.payload["message_id"] == str(
        dependency_waiting.message_id
    )
    assert dependency_event.payload["depends_on_message_ids"] == [
        str(upstream.message_id)
    ]
    assert dependency_event.payload["unmet_dependency_message_ids"] == [
        str(upstream.message_id)
    ]
    assert exhausted_event.payload["message_id"] == str(retry_exhausted.message_id)
    assert exhausted_event.payload["attempt_count"] == 3
    assert exhausted_event.payload["max_attempts"] == 3
    assert fake_hf_token not in serialized_events
    assert fake_tavily_key not in serialized_events
    assert bearer not in serialized_events
    assert "hf_[redacted]" in serialized_events
    assert "tvly-[redacted]" in serialized_events
    assert "Bearer [redacted]" in serialized_events


def test_agent_message_retry_authorization_resets_exhausted_task_for_worker():
    store = FakeStore()
    message = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="agent-harness-engineer",
        recipient_agent_id="principal-software-engineer",
        task_type="review_retry_authorization",
        payload={"topic": "human authorized retry"},
        status=AgentTaskStatus.BLOCKED,
        claimed_by_agent_id="principal-software-engineer",
        attempt_count=3,
        max_attempts=3,
        result={"retry_policy": {"attempt_count": 3, "max_attempts": 3}},
        error="A2A task exhausted retry attempts.",
    )
    asyncio.run(store.record_agent_message(message))

    def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/a2a/messages/{message.message_id}/retry",
            json={
                "agent_id": "agent-harness-engineer",
                "reason": "Human reviewed the poison task and approved one retry.",
                "reset_attempt_count": True,
                "max_attempts": 4,
            },
        )
    finally:
        app.dependency_overrides.clear()

    assert response.status_code == 200
    payload = response.json()
    assert payload["message"]["status"] == AgentTaskStatus.ACCEPTED.value
    assert payload["message"]["attempt_count"] == 0
    assert payload["message"]["max_attempts"] == 4
    assert payload["message"]["error"] is None
    assert payload["message"]["result"]["retry_authorization"]["authorized_by"] == (
        "agent-harness-engineer"
    )
    assert [
        entry["action"] for entry in payload["message"]["handoff_trace"]
    ] == ["accepted", "retry_authorized"]
    assert store.run.status == RunStatus.RUNNING
    assert store.events[-1].event_type == "agent_message_retry_authorized"
    assert store.events[-1].payload["previous_attempt_count"] == 3
    assert store.events[-1].payload["attempt_count"] == 0

    worker_result = asyncio.run(
        AgentWorker(store).run(
            "principal-software-engineer",
            AgentWorkerRunRequest(
                run_id=store.run.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    assert worker_result.idle is False
    assert worker_result.processed_tasks[0].status == AgentTaskStatus.COMPLETED
    assert message.status == AgentTaskStatus.COMPLETED
    assert message.attempt_count == 1
    assert message.claimed_by_agent_id == "principal-software-engineer"
    assert [
        entry["action"] for entry in message.handoff_trace
    ] == [
        "accepted",
        "retry_authorized",
        "claimed",
        "status_updated",
        "status_updated",
    ]


def test_agent_worker_cycle_message_targeting_runs_retried_message_not_older_inbox_task():
    store = FakeStore()
    older_message = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="agent-harness-engineer",
        recipient_agent_id="principal-software-engineer",
        task_type="review_older_queue_item",
        payload={"topic": "older accepted work"},
    )
    retried_message = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="agent-harness-engineer",
        recipient_agent_id="principal-software-engineer",
        task_type="review_retry_target",
        payload={"topic": "the retried task should run first"},
        status=AgentTaskStatus.BLOCKED,
        claimed_by_agent_id="principal-software-engineer",
        attempt_count=3,
        max_attempts=3,
        result={"retry_policy": {"attempt_count": 3, "max_attempts": 3}},
        error="A2A task exhausted retry attempts.",
    )
    asyncio.run(store.record_agent_message(older_message))
    asyncio.run(store.record_agent_message(retried_message))
    asyncio.run(
        store.authorize_agent_message_retry(
            retried_message.message_id,
            agent_id="agent-harness-engineer",
            reason="Creator approved a targeted retry.",
            reset_attempt_count=True,
            max_attempts=4,
        )
    )

    cycle_result = asyncio.run(
        AgentWorker(store).run_cycle(
            AgentWorkerCycleRequest(
                run_id=store.run.run_id,
                agent_ids=["principal-software-engineer"],
                message_ids=[retried_message.message_id],
                max_tasks_per_agent=1,
                max_rounds=1,
                use_gemma=False,
            )
        )
    )

    assert cycle_result.total_processed_tasks == 1
    assert cycle_result.worker_results[0].processed_tasks[0].message_id == (
        retried_message.message_id
    )
    assert retried_message.status == AgentTaskStatus.COMPLETED
    assert retried_message.attempt_count == 1
    assert older_message.status == AgentTaskStatus.ACCEPTED
    assert older_message.attempt_count == 0
    cycle_event = next(
        event
        for event in reversed(store.events)
        if event.event_type == "agent_worker_cycle_completed"
    )
    assert cycle_event.payload["message_ids"] == [str(retried_message.message_id)]


