    assert plan.blocked_reasons == ["retry_exhausted_agent_tasks"]
    assert any(
        str(message.message_id) in action and "Authorize retry" in action
        for action in plan.recommended_next_actions
    )
    assert plan.pending_agent_messages[0].attempt_count == 3


