def test_context_packet_surfaces_retry_exhausted_task_risk():
    store = FakeStore()
    message = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="agent-harness-engineer",
        recipient_agent_id="principal-software-engineer",
        task_type="review_retry_exhausted_context",
        payload={"topic": "retry exhausted context packet"},
        status=AgentTaskStatus.BLOCKED,
        claimed_by_agent_id="principal-software-engineer",
        attempt_count=3,
        max_attempts=3,
        result={"retry_policy": {"attempt_count": 3, "max_attempts": 3}},
        error="A2A task exhausted retry attempts.",
    )
    asyncio.run(store.record_agent_message(message))

    def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/context-packet",
            json={
                "agent_id": "agent-harness-engineer",
                "record_event": False,
                "max_manifest_items": 10,
            },
        )
    finally:
        app.dependency_overrides.clear()

    assert response.status_code == 200
    payload = response.json()
    retry_items = [
        item
        for item in payload["context_manifest"]
        if item["item_type"] == "retry_exhausted_agent_task"
    ]
    assert retry_items
    assert retry_items[0]["metadata"]["retry_exhausted"] is True
    assert retry_items[0]["metadata"]["attempt_count"] == 3
    assert any(
        risk["risk_type"] == "retry_exhausted_agent_tasks"
        for risk in payload["context_risks"]
    )
    assert any(
        str(message.message_id) in fetch and "Authorize retry" in fetch
        for fetch in payload["recommended_fetches"]
    )


