def test_a2a_dependencies_surface_in_work_plan_context_and_sync_pulse():
    store = FakeStore()
    upstream = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="content-strategist",
        recipient_agent_id="web-research-agent",
        task_type="research_dependency_source",
        payload={"topic": "dependency source"},
        status=AgentTaskStatus.ACCEPTED,
    )
    dependent = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="web-research-agent",
        recipient_agent_id="claim-verification-agent",
        task_type="verify_after_research",
        payload={"topic": "dependency source"},
        depends_on_message_ids=[upstream.message_id],
        status=AgentTaskStatus.ACCEPTED,
    )
    asyncio.run(store.record_agent_message(upstream))
    asyncio.run(store.record_agent_message(dependent))

    def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        work_plan_response = client.post(
            f"/api/runs/{store.run.run_id}/work-plan",
            json={"record_artifact": False},
        )
        context_response = client.post(
            f"/api/runs/{store.run.run_id}/context-packet",
            json={"record_event": False, "max_manifest_items": 10},
        )
        sync_response = client.post(
            f"/api/runs/{store.run.run_id}/sync-pulse",
            json={"record_artifact": False},
        )
    finally:
        app.dependency_overrides.clear()

    assert work_plan_response.status_code == 200
    plan_payload = work_plan_response.json()
    dependency_items = [
        item
        for item in plan_payload["plan_items"]
        if item["item_type"] == "dependency_waiting_task"
    ]
    assert dependency_items
    assert dependency_items[0]["source_message_id"] == str(dependent.message_id)
    assert dependency_items[0]["metadata"]["unmet_dependency_message_ids"] == [
        str(upstream.message_id)
    ]
    assert dependency_items[0]["blocking"] is True

    assert context_response.status_code == 200
    context_payload = context_response.json()
    manifest_items = [
        item
        for item in context_payload["context_manifest"]
        if item["item_type"] == "dependency_waiting_agent_task"
    ]
    assert manifest_items
    assert manifest_items[0]["metadata"]["depends_on_message_ids"] == [
        str(upstream.message_id)
    ]
    assert any(
        risk["risk_type"] == "agent_task_dependency_waiting"
        for risk in context_payload["context_risks"]
    )
    assert any(
        "upstream A2A dependency" in fetch
        for fetch in context_payload["recommended_fetches"]
    )

    assert sync_response.status_code == 200
    sync_payload = sync_response.json()
    claim_state = next(
        state
        for state in sync_payload["agent_states"]
        if state["agent_id"] == "claim-verification-agent"
    )
    assert claim_state["current_focus"] == "dependency_waiting"
    assert any("upstream dependencies" in blocker for blocker in sync_payload["blockers"])


def test_work_plan_sync_pulse_and_resume_surface_dependency_cycles():
    store = FakeStore()
    first = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="content-strategist",
        recipient_agent_id="web-research-agent",
        task_type="cycle_research_for_plan",
        payload={"topic": "cycle one"},
        status=AgentTaskStatus.ACCEPTED,
    )
    second = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="web-research-agent",
        recipient_agent_id="claim-verification-agent",
        task_type="cycle_verify_for_plan",
        payload={"topic": "cycle two"},
        depends_on_message_ids=[first.message_id],
        status=AgentTaskStatus.ACCEPTED,
    )
    first.depends_on_message_ids = [second.message_id]
    asyncio.run(store.record_agent_message(first))
    asyncio.run(store.record_agent_message(second))

    work_plan = asyncio.run(
        RunWorkPlanWorkflow(store).build(
            store.run.run_id,
            RunWorkPlanRequest(record_artifact=False),
        )
    )
    cycle_items = [
        item
        for item in work_plan.plan_items
        if item.item_type == "dependency_cycle_task"
    ]
    assert len(cycle_items) == 2
    assert all(item.owner_agent_id == "agent-harness-engineer" for item in cycle_items)
    assert all(item.blocking for item in cycle_items)
    assert all(item.metadata["in_dependency_cycle"] is True for item in cycle_items)
    assert any("circular" in item.recommended_action for item in cycle_items)

    sync_pulse = asyncio.run(
        RunSyncPulseWorkflow(store).build(
            store.run.run_id,
            RunSyncPulseRequest(record_artifact=False, build_work_plan=True),
        )
    )
    claim_state = next(
        state
        for state in sync_pulse.agent_states
        if state.agent_id == "claim-verification-agent"
    )
    assert claim_state.current_focus == "dependency_cycle"
    assert "circular A2A dependencies" in claim_state.recommended_next_action
    assert any("circular dependencies" in blocker for blocker in sync_pulse.blockers)
    assert sync_pulse.work_plan.blocked_item_count >= 2

    resume_plan = asyncio.run(
        RunResumeWorkflow(store).build_resume_plan(
            store.run.run_id,
            RunResumePlanRequest(
                agent_id="agent-harness-engineer",
                create_checkpoint=False,
            ),
        )
    )
    assert resume_plan.resume_allowed is False
    assert "dependency_cycle_agent_tasks" in resume_plan.blocked_reasons
    assert resume_plan.context_summary["dependency_cycle_agent_tasks"] == 2
    assert any(
        "Break circular A2A dependencies" in action
        for action in resume_plan.recommended_next_actions
    )


def test_worker_does_not_claim_a2a_task_until_dependencies_complete():
    store = FakeStore()
    upstream = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="content-strategist",
        recipient_agent_id="web-research-agent",
        task_type="research_before_claim_review",
        payload={"topic": "dependency claim review"},
        status=AgentTaskStatus.ACCEPTED,
    )
    dependent = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="web-research-agent",
        recipient_agent_id="claim-verification-agent",
        task_type="verify_after_research",
        payload={"topic": "dependency claim review"},
        depends_on_message_ids=[upstream.message_id],
        status=AgentTaskStatus.ACCEPTED,
    )
    asyncio.run(store.record_agent_message(upstream))
    asyncio.run(store.record_agent_message(dependent))

    worker = AgentWorker(store)
    blocked_result = asyncio.run(
        worker.run(
            "claim-verification-agent",
            AgentWorkerRunRequest(
                run_id=store.run.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    assert blocked_result.idle is True
    assert blocked_result.dependency_blocked_tasks == 1
    assert store.agent_messages[1].status == AgentTaskStatus.ACCEPTED
    assert store.agent_messages[1].attempt_count == 0
    assert store.events[-1].event_type == "agent_message_dependency_waiting"
    assert [
        entry["action"] for entry in store.agent_messages[1].handoff_trace
    ] == ["accepted", "dependency_waiting"]

    store.agent_messages[0].status = AgentTaskStatus.COMPLETED
    processed_result = asyncio.run(
        worker.run(
            "claim-verification-agent",
            AgentWorkerRunRequest(
                run_id=store.run.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    assert processed_result.idle is False
    assert processed_result.dependency_blocked_tasks == 0
    assert processed_result.processed_tasks[0].status == AgentTaskStatus.COMPLETED
    assert store.agent_messages[1].status == AgentTaskStatus.COMPLETED
    assert store.agent_messages[1].attempt_count == 1
    assert [
        entry["action"] for entry in store.agent_messages[1].handoff_trace
    ] == [
        "accepted",
        "dependency_waiting",
        "claimed",
        "status_updated",
        "status_updated",
    ]


def test_a2a_collaboration_graph_maps_dependencies_traces_and_ready_work():
    store = FakeStore()
    upstream = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="content-strategist",
        recipient_agent_id="web-research-agent",
        task_type="research_for_graph",
        payload={"topic": "graph dependencies"},
        status=AgentTaskStatus.ACCEPTED,
    )
    dependent = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="web-research-agent",
        recipient_agent_id="claim-verification-agent",
        task_type="verify_after_graph_research",
        payload={"topic": "graph dependencies"},
        depends_on_message_ids=[upstream.message_id],
        status=AgentTaskStatus.ACCEPTED,
    )
    retry_blocked = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="agent-harness-engineer",
        recipient_agent_id="principal-software-engineer",
        task_type="review_graph_retry_blocker",
        payload={"topic": "graph retry blocker"},
        status=AgentTaskStatus.BLOCKED,
        claimed_by_agent_id="principal-software-engineer",
        attempt_count=3,
        max_attempts=3,
        result={"retry_policy": {"attempt_count": 3, "max_attempts": 3}},
        error="A2A task exhausted retry attempts.",
    )
    asyncio.run(store.record_agent_message(upstream))
    append_handoff_trace(
        upstream,
        actor="web-research-agent",
        action="status_updated",
        status=AgentTaskStatus.IN_PROGRESS,
        notes=(
            "Graph trace included Bearer live-graph-token-123, "
            "hf_abcdefghijklmnopqrstuvwxyz, and "
            "tvly-abcdefghijklmnopqrstuvwx."
        ),
    )
    upstream.handoff_trace.append(
        {
            "actor": "hf_traceactorabcdefghijklmnopqrstuv",
            "action": "Bearer trace-action-token-1234567890",
            "status": "tvly-tracestatusabcdefghijklmnop",
            "at": datetime.now(timezone.utc).isoformat(),
            "notes": "Synthetic trace identity fields should be redacted.",
        }
    )
    asyncio.run(store.record_agent_message(dependent))
    asyncio.run(store.record_agent_message(retry_blocked))

    def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/a2a-collaboration-graph",
            json={
                "record_artifact": True,
                "include_completed_tasks": True,
                "max_messages": 100,
            },
        )
    finally:
        app.dependency_overrides.clear()

    assert response.status_code == 200
    graph = response.json()
    assert graph["task_count"] == 3
    assert graph["agent_count"] >= 5
    assert upstream.message_id in {
        UUID(message_id) for message_id in graph["ready_task_ids"]
    }
    assert graph["dependency_waiting_task_ids"] == [str(dependent.message_id)]
    assert graph["retry_exhausted_task_ids"] == [str(retry_blocked.message_id)]
    assert graph["trace_gap_task_ids"] == []
    assert graph["dependency_cycle_message_ids"] == []
    assert graph["dependency_cycles"] == []
    assert any(edge["edge_type"] == "depends_on" for edge in graph["edges"])
    assert any(edge["edge_type"] == "trace:accepted" for edge in graph["edges"])
    serialized_graph = json.dumps(graph)
    serialized_artifact = json.dumps(store.artifacts[-1].content)
    for serialized in [serialized_graph, serialized_artifact]:
        assert "live-graph-token-123" not in serialized
        assert "hf_abcdefghijklmnopqrstuvwxyz" not in serialized
        assert "tvly-abcdefghijklmnopqrstuvwx" not in serialized
        assert "hf_traceactorabcdefghijklmnopqrstuv" not in serialized
        assert "trace-action-token-1234567890" not in serialized
        assert "tvly-tracestatusabcdefghijklmnop" not in serialized
        assert "Bearer [redacted]" in serialized
        assert "hf_[redacted]" in serialized
        assert "tvly-[redacted]" in serialized
    assert any("Run workers for ready agents" in action for action in graph["recommended_actions"])
    assert graph["artifact_id"]
    assert store.artifacts[-1].artifact_type == ArtifactType.A2A_COLLABORATION_GRAPH
    assert store.events[-1].event_type == "a2a_collaboration_graph_built"
    assert store.events[-1].payload["dependency_waiting_task_count"] == 1
    assert store.events[-1].payload["dependency_cycle_count"] == 0


def test_a2a_collaboration_graph_detects_dependency_cycles():
    store = FakeStore()
    first = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="content-strategist",
        recipient_agent_id="web-research-agent",
        task_type="cyclic_research_dependency",
        payload={"topic": "cycle one"},
        status=AgentTaskStatus.ACCEPTED,
    )
    second = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="web-research-agent",
        recipient_agent_id="claim-verification-agent",
        task_type="cyclic_claim_dependency",
        payload={"topic": "cycle two"},
        depends_on_message_ids=[first.message_id],
        status=AgentTaskStatus.ACCEPTED,
    )
    first.depends_on_message_ids = [second.message_id]
    asyncio.run(store.record_agent_message(first))
    asyncio.run(store.record_agent_message(second))

    def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/a2a-collaboration-graph",
            json={
                "record_artifact": True,
                "include_completed_tasks": True,
                "max_messages": 100,
            },
        )
    finally:
        app.dependency_overrides.clear()

    assert response.status_code == 200
    graph = response.json()
    assert {UUID(message_id) for message_id in graph["dependency_cycle_message_ids"]} == {
        first.message_id,
        second.message_id,
    }
    assert len(graph["dependency_cycles"]) == 1
    assert {UUID(message_id) for message_id in graph["dependency_cycles"][0]} == {
        first.message_id,
        second.message_id,
    }
    cycle_edges = [
        edge for edge in graph["edges"] if edge["edge_type"] == "depends_on"
    ]
    assert len(cycle_edges) == 2
    assert {edge["status"] for edge in cycle_edges} == {"cycle"}
    assert all(edge["metadata"]["in_dependency_cycle"] for edge in cycle_edges)
    cycle_nodes = [
        node
        for node in graph["nodes"]
        if node["node_type"] == "task"
        and node["message_id"] in {str(first.message_id), str(second.message_id)}
    ]
    assert all(node["metadata"]["in_dependency_cycle"] for node in cycle_nodes)
    assert any(
        "Break A2A dependency cycles" in action
        for action in graph["recommended_actions"]
    )
    assert store.artifacts[-1].content["dependency_cycles"]
    assert store.events[-1].payload["dependency_cycle_count"] == 1
    assert store.events[-1].payload["dependency_cycle_message_count"] == 2


def test_authorized_dependency_repair_breaks_a2a_cycle_and_reopens_progress():
    store = FakeStore()
    first = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="content-strategist",
        recipient_agent_id="web-research-agent",
        task_type="cyclic_research_dependency_repair",
        payload={"topic": "repair cycle one"},
        status=AgentTaskStatus.ACCEPTED,
    )
    second = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="web-research-agent",
        recipient_agent_id="claim-verification-agent",
        task_type="cyclic_claim_dependency_repair",
        payload={"topic": "repair cycle two"},
        depends_on_message_ids=[first.message_id],
        status=AgentTaskStatus.ACCEPTED,
    )
    first.depends_on_message_ids = [second.message_id]
    asyncio.run(store.record_agent_message(first))
    asyncio.run(store.record_agent_message(second))

    def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        initial_graph_response = client.post(
            f"/api/runs/{store.run.run_id}/a2a-collaboration-graph",
            json={"record_artifact": False, "include_completed_tasks": True},
        )
        repair_response = client.post(
            f"/api/a2a/messages/{first.message_id}/dependencies/repair",
            json={
                "agent_id": "agent-harness-engineer",
                "remove_dependency_message_ids": [str(second.message_id)],
                "reason": "Break circular dependency after graph audit.",
            },
        )
        repaired_graph_response = client.post(
            f"/api/runs/{store.run.run_id}/a2a-collaboration-graph",
            json={"record_artifact": False, "include_completed_tasks": True},
        )
    finally:
        app.dependency_overrides.clear()

    assert initial_graph_response.status_code == 200
    initial_graph = initial_graph_response.json()
    assert len(initial_graph["dependency_cycles"]) == 1
    assert {UUID(message_id) for message_id in initial_graph["dependency_cycles"][0]} == {
        first.message_id,
        second.message_id,
    }

    assert repair_response.status_code == 200
    payload = repair_response.json()
    assert payload["removed_dependency_message_ids"] == [str(second.message_id)]
    assert payload["remaining_dependency_message_ids"] == []
    assert payload["message"]["depends_on_message_ids"] == []
    assert payload["message"]["claimed_by_agent_id"] is None
    assert payload["message"]["result"]["dependency_repair"]["repaired_by"] == (
        "agent-harness-engineer"
    )
    assert payload["message"]["result"]["dependency_repair"][
        "removed_dependency_message_ids"
    ] == [str(second.message_id)]
    assert [
        entry["action"] for entry in payload["message"]["handoff_trace"]
    ] == ["accepted", "dependencies_repaired"]
    assert store.run.status == RunStatus.RUNNING
    repair_event = next(
        event
        for event in store.events
        if event.event_type == "agent_message_dependencies_repaired"
    )
    assert repair_event.actor == "agent-harness-engineer"
    assert repair_event.payload["message_id"] == str(first.message_id)
    assert repair_event.payload["removed_dependency_message_ids"] == [
        str(second.message_id)
    ]
    assert repair_event.payload["remaining_dependency_message_ids"] == []

    assert repaired_graph_response.status_code == 200
    repaired_graph = repaired_graph_response.json()
    assert repaired_graph["dependency_cycles"] == []
    assert repaired_graph["dependency_cycle_message_ids"] == []
    assert str(first.message_id) in repaired_graph["ready_task_ids"]
    assert repaired_graph["dependency_waiting_task_ids"] == [str(second.message_id)]
    assert store.events[-1].event_type == "a2a_collaboration_graph_built"
    assert store.events[-1].payload["dependency_cycle_count"] == 0
    assert store.events[-1].payload["ready_task_count"] >= 1


def test_skill_usage_ledger_audits_worker_skill_evidence():
    store = FakeStore()
    content_workflow = ContentStudioWorkflow(store)
    content_result = asyncio.run(
        content_workflow.run(
            OrchestrationRequest(
                transcript="Create source-backed content about skill-audited agents.",
                topic="skill-audited agents",
                require_human_feedback=False,
            )
        )
    )
    worker = AgentWorker(
        store,
        ContentWorkflowServices(gemma_provider=FakeGemmaProvider()),
    )
    asyncio.run(
        worker.run(
            "web-research-agent",
            AgentWorkerRunRequest(run_id=content_result.run_id, max_tasks=1),
        )
    )

    def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        response = client.post(
            f"/api/runs/{store.run.run_id}/skill-usage-ledger",
            json={
                "record_artifact": True,
                "include_pending_tasks": True,
                "max_messages": 100,
                "max_events": 200,
            },
        )
    finally:
        app.dependency_overrides.clear()

    assert response.status_code == 200
    ledger = response.json()
    assert ledger["processed_task_count"] == 1
    assert ledger["skill_invocation_count"] == 1
    assert ledger["missing_skill_usage_message_ids"] == []
    assert ledger["skill_source_contract_issue_count"] == 0
    assert len(ledger["skill_source_contracts"]) == 9
    assert all(
        entry["frontmatter_matches_card"] and entry["agents_manifest_exists"]
        for entry in ledger["skill_source_contracts"]
    )
    assert "agent-studio-research-grounding" in ledger["entries"][0]["skill_ids"]
    assert ledger["entries"][0]["has_result_skill_usage"] is True
    assert ledger["entries"][0]["has_invocation_event"] is True
    assert ledger["entries"][0]["skill_source_paths"] == {
        "agent-studio-research-grounding": (
            "skills/agent-studio-research-grounding/SKILL.md"
        ),
        "agent-studio-retrieval-intelligence": (
            "skills/agent-studio-retrieval-intelligence/SKILL.md"
        ),
    }
    assert ledger["artifact_id"]
    assert store.artifacts[-1].artifact_type == ArtifactType.SKILL_USAGE_LEDGER
    assert store.artifacts[-1].content["skill_source_contract_issue_count"] == 0
    assert store.events[-1].event_type == "agent_skill_usage_ledger_built"
    assert store.events[-1].payload["missing_skill_usage_count"] == 0
    assert store.events[-1].payload["skill_source_contract_issue_count"] == 0


def test_agent_worker_research_executor_records_provider_sources():
    store = FakeStore()
