    assert store.sources[-1].retrieved_at.isoformat().startswith("2026-05-15")
    assert store.agent_messages[0].result["source_ids"] == [
        str(store.sources[-1].source_id)
    ]
    assert store.agent_messages[0].result["web_research"][
        "accepted_source_count"
    ] == 1
    assert store.agent_messages[0].result["web_research"]["citation_ids"] == ["S3"]
    assert store.agent_messages[0].result["source_repair"]["claim_count"] == 1
    assert store.agent_messages[0].result["source_repair"]["artifact_count"] == 3
    assert store.agent_messages[0].result["claim_verification_followup"]["status"] == (
        "existing_runnable_task"
    )
    assert store.agent_messages[0].result["retrieval_quality_ledger"]["status"] in {
        "ready",
        "needs_more_recall",
    }
    assert store.agent_messages[0].result["retrieval_quality_ledger"][
        "ledger_artifact_id"
    ]
    assert store.agent_messages[0].result["retrieval_quality_ledger"][
        "accepted_candidate_count"
    ] >= 1
    assert store.agent_messages[0].result["research_freshness_ledger"]["status"] == (
        "needs_refresh"
    )
    assert store.agent_messages[0].result["research_freshness_ledger"][
        "ledger_artifact_id"
    ]
    assert store.claims[0].source_ids == [store.sources[-1].source_id]
    assert store.claims[0].support_status == ClaimSupportStatus.NEEDS_REVIEW
    publishable_artifacts = [
        artifact
        for artifact in store.artifacts
        if artifact.artifact_type
        in {
            ArtifactType.POST,
            ArtifactType.REEL_SCRIPT,
            ArtifactType.SUBSTACK_ARTICLE,
        }
    ]
    assert all(
        store.sources[-1].source_id in artifact.source_ids
        for artifact in publishable_artifacts
    )
    assert all(
        "source_grounding_repairs" in artifact.provenance
        for artifact in publishable_artifacts
    )
    assert any(
        artifact.artifact_type == ArtifactType.RESEARCH_FRESHNESS_LEDGER
        for artifact in store.artifacts
    )
    assert any(
        artifact.artifact_type == ArtifactType.RETRIEVAL_QUALITY_LEDGER
        for artifact in store.artifacts
    )
    event_types = [event.event_type for event in store.events]
    assert "agent_tool_use_approved" in event_types
    assert "web_research_completed" in event_types
    assert "source_grounding_repaired" in event_types
    assert "research_freshness_ledger_built" in event_types
    assert "retrieval_quality_ledger_built" in event_types
    research_event = next(
        event for event in store.events if event.event_type == "web_research_completed"
    )
    assert research_event.payload["provider_result_count"] == 1
    assert research_event.payload["accepted_source_count"] == 1
    assert research_event.payload["deduplicated_result_count"] == 0
    assert research_event.payload["citation_ids"] == ["S3"]
    assert research_event.payload["source_ids"] == [str(store.sources[-1].source_id)]
    tool_event = next(
        event for event in store.events if event.event_type == "agent_tool_use_approved"
    )
    assert tool_event.payload["agent_id"] == "web-research-agent"
    assert tool_event.payload["tool_name"] == "web_search"


