def test_agent_worker_research_executor_falls_back_when_reranker_fails():
    store = FakeStore()
    content_result = asyncio.run(
        ContentStudioWorkflow(store).run(
            OrchestrationRequest(
                transcript="Create a grounded reel about resilient reranking.",
                topic="resilient reranking",
                require_human_feedback=False,
            )
        )
    )
    web_message = next(
        message
        for message in store.agent_messages
        if message.recipient_agent_id == "web-research-agent"
    )
    web_message.payload["search_queries"] = ["resilient reranking"]

    result = asyncio.run(
        AgentWorker(
            store,
            ContentWorkflowServices(
                search_provider=MultiResultSearchProvider(),
                reranker_provider=FailingRerankerProvider(),
            ),
        ).run(
            "web-research-agent",
            AgentWorkerRunRequest(run_id=content_result.run_id, max_tasks=1),
        )
    )

    assert result.processed_tasks[0].generation_mode == "web_search_provider"
    recorded_search_sources = [
        source
        for source in store.sources
        if source.metadata.get("source_type") == "worker_web_search_result"
    ]
    assert recorded_search_sources
    assert all(
        source.metadata["reranker"] == "deterministic_source_quality_v1"
        for source in recorded_search_sources
    )
    fallback_events = [
        event
        for event in store.events
        if event.event_type == "provider_fallback"
        and event.payload.get("provider") == "retrieval_reranker"
    ]
    assert fallback_events
    assert fallback_events[-1].payload["reason"].count("[redacted]") == 2
    assert "a" * 24 not in fallback_events[-1].payload["reason"]
    assert "b" * 24 not in fallback_events[-1].payload["reason"]
    assert web_message.result["web_research"]["reranker"] == (
        "deterministic_source_quality_v1"
    )
    assert web_message.result["web_research"]["reranker_fallback_reason"].count(
        "[redacted]"
    ) == 2


