def test_agent_worker_research_executor_queues_claim_verification_after_source_repair():
    store = FakeStore()
    content_result = asyncio.run(
        ContentStudioWorkflow(store).run(
            OrchestrationRequest(
                transcript="Create a grounded reel about source repair handoff.",
                topic="source repair handoff",
                require_human_feedback=False,
            )
        )
    )
    asyncio.run(
        AgentWorker(store).run(
            "claim-verification-agent",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    worker = AgentWorker(
        store,
        ContentWorkflowServices(search_provider=FakeSearchProvider()),
    )
    result = asyncio.run(
        worker.run(
            "web-research-agent",
            AgentWorkerRunRequest(run_id=content_result.run_id, max_tasks=1),
        )
    )

    assert result.processed_tasks[0].generation_mode == "web_search_provider"
    web_message = next(
        message
        for message in store.agent_messages
        if message.recipient_agent_id == "web-research-agent"
    )
    followup = web_message.result["claim_verification_followup"]
    assert followup["status"] == "created"
    claim_followup = next(
        message
        for message in store.agent_messages
        if message.recipient_agent_id == "claim-verification-agent"
        and message.task_type == "verify_source_refresh_claims"
    )
    assert str(claim_followup.message_id) == followup["message_id"]
    assert claim_followup.sender_agent_id == "web-research-agent"
    assert claim_followup.status == AgentTaskStatus.ACCEPTED
    assert claim_followup.depends_on_message_ids == [web_message.message_id]
    assert claim_followup.payload["workflow"] == (
        "source_refresh_claim_verification_handoff_v1"
    )
    assert claim_followup.payload["claim_ids"] == web_message.result["source_repair"][
        "claim_ids"
    ]
    assert claim_followup.payload["source_ids"] == web_message.result["source_ids"]
    assert claim_followup.payload["source_repair"]["replacement_source_ids"] == (
        web_message.result["source_repair"]["replacement_source_ids"]
    )
    assert claim_followup.payload["freshness_ledger_artifact_id"] == (
        web_message.result["research_freshness_ledger"]["ledger_artifact_id"]
    )
    assert claim_followup.payload["retrieval_quality_ledger_artifact_id"] == (
        web_message.result["retrieval_quality_ledger"]["ledger_artifact_id"]
    )
    assert claim_followup.payload["retrieval_quality_status"] == (
        web_message.result["retrieval_quality_ledger"]["status"]
    )
    assert "context_summary" not in claim_followup.payload
    accepted_events = [
        event
        for event in store.events
        if event.event_type == "agent_message_accepted"
        and event.actor == "web-research-agent"
    ]
    assert accepted_events[-1].payload["message_id"] == str(claim_followup.message_id)


