def test_agent_worker_claim_verification_requires_accepted_retrieval_evidence():
    store = FakeStore()
    content_result = asyncio.run(
        ContentStudioWorkflow(store).run(
            OrchestrationRequest(
                transcript="Create source-backed content about accepted evidence gates.",
                topic="accepted evidence gates",
                require_human_feedback=False,
            )
        )
    )
    _record_test_retrieval_quality_ledger(
        store,
        accepted_source_ids=[store.sources[1].source_id],
        rejected_source_ids=[store.sources[0].source_id],
        topic="accepted evidence gates",
    )

    result = asyncio.run(
        AgentWorker(store).run(
            "claim-verification-agent",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    assert result.processed_tasks[0].generation_mode == "claim_verification_worker"
    assert store.claims[0].support_status == ClaimSupportStatus.UNSUPPORTED
    assert "accepted retrieval evidence" in store.claims[0].notes
    assert store.claims[1].support_status == ClaimSupportStatus.SUPPORTED
    assert "accepted retrieval evidence" in store.claims[1].notes
    claim_task = next(
        message
        for message in store.agent_messages
        if message.recipient_agent_id == "claim-verification-agent"
    )
    assert claim_task.result["retrieval_evidence_required"] is True
    assert claim_task.result["accepted_retrieval_claim_ids"] == [
        str(store.claims[1].claim_id)
    ]
    assert claim_task.result["missing_accepted_retrieval_claim_ids"] == [
        str(store.claims[0].claim_id)
    ]
    assert claim_task.result["claim_revision_plan_artifact_id"]
    claim_revision_plan = next(
        artifact
        for artifact in store.artifacts
        if artifact.artifact_type == ArtifactType.CLAIM_REVISION_PLAN
    )
    assert claim_revision_plan.provenance["workflow"] == "claim_revision_plan_v1"
    assert claim_revision_plan.content["status"] == "revision_required"
    assert claim_revision_plan.content["held_claims"][0]["claim_id"] == str(
        store.claims[0].claim_id
    )
    assert claim_revision_plan.content["held_claims"][0]["rewrite_action"] == (
        "rewrite_against_accepted_retrieval_evidence_or_hold"
    )
    assert claim_revision_plan.content["accepted_source_alternatives"][0][
        "source_id"
    ] == str(store.sources[1].source_id)
    assert claim_revision_plan.content["writer_instructions"]
    event = next(
        event
        for event in reversed(store.events)
        if event.event_type == "claim_verification_completed"
    )
    assert event.payload["missing_accepted_retrieval_claims"] == 1
    assert event.payload["accepted_retrieval_claims"] == 1
    assert event.payload["claim_revision_plan_artifact_id"] == str(
        claim_revision_plan.artifact_id
    )
    event_types = [event.event_type for event in store.events]
    assert "claim_revision_plan_created" in event_types
    assert "claim_revision_followups_materialized" in event_types
    followups = [
        message
        for message in store.agent_messages
        if message.payload.get("workflow") == "claim_revision_followup_v1"
    ]
    assert [message.recipient_agent_id for message in followups] == [
        "eli5-short-form-writer",
        "substack-essay-writer",
        "script-doctor",
        "editor-in-chief",
    ]
    assert all(
        str(claim_revision_plan.artifact_id)
        == message.payload["claim_revision_plan_artifact_id"]
        for message in followups
    )
    assert all(
        str(store.claims[0].claim_id) in message.payload["held_claim_ids"]
        for message in followups
    )
    editor_followup = followups[-1]
    assert editor_followup.depends_on_message_ids == [
        message.message_id for message in followups[:-1]
    ]
    assert claim_task.result["created_followup_message_ids"] == [
        str(message.message_id) for message in followups
    ]

    duplicate = AgentMessage(
        run_id=content_result.run_id,
        sender_agent_id="intent-router",
        recipient_agent_id="claim-verification-agent",
        task_type="verify_content_claims_again",
        payload={"topic": "accepted evidence gates"},
    )
    asyncio.run(store.record_agent_message(duplicate))
    duplicate_result = asyncio.run(
        AgentWorker(store).run(
            "claim-verification-agent",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )
    assert duplicate_result.processed_tasks[0].generation_mode == (
        "claim_verification_worker"
    )
    assert duplicate.result["created_followup_message_ids"] == []
    assert duplicate.result["skipped_duplicate_followups"] == 4
    assert len(
        [
            message
            for message in store.agent_messages
            if message.payload.get("workflow") == "claim_revision_followup_v1"
        ]
    ) == 4


