def test_agent_tool_and_model_policy_records_denials():
    store = FakeStore()

    try:
        asyncio.run(
            require_tool_allowed(
                store,
                run_id=store.run.run_id,
                agent_id="content-strategist",
                tool_name="web_search",
                reason="unit_test_denial",
            )
        )
    except AgentToolPolicyError as exc:
        assert "content-strategist" in str(exc)
    else:
        raise AssertionError("Expected web_search tool policy denial.")

    try:
        asyncio.run(
            require_model_allowed(
                store,
                run_id=store.run.run_id,
                agent_id="audio-producer",
                model_id="google/gemma-4-e4b-it",
                reason="unit_test_model_denial",
            )
        )
    except AgentModelPolicyError as exc:
        assert "audio-producer" in str(exc)
    else:
        raise AssertionError("Expected Gemma model policy denial.")

    event_types = [event.event_type for event in store.events]
    assert event_types == ["agent_tool_use_denied", "agent_model_use_denied"]
    assert store.events[0].payload["allowed_tools"] == []
    assert store.events[1].payload["allowed_models"] == [
        "gemma-4-26b-a4b-it",
        "gemma-4-31b-it",
    ]


