def test_editorial_and_publish_readiness_block_missing_accepted_retrieval_evidence():
    store = FakeStore()
    content_result = asyncio.run(
        ContentStudioWorkflow(store).run(
            OrchestrationRequest(
                transcript="Create content that must honor accepted evidence.",
                topic="accepted evidence editorial gate",
                require_human_feedback=False,
            )
        )
    )
    _record_test_retrieval_quality_ledger(
        store,
        accepted_source_ids=[store.sources[1].source_id],
        rejected_source_ids=[store.sources[0].source_id],
        topic="accepted evidence editorial gate",
    )
    asyncio.run(
        AgentWorker(store).run(
            "content-strategist",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    editor_result = asyncio.run(
        AgentWorker(store).run(
            "editor-in-chief",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    assert editor_result.processed_tasks[0].generation_mode == (
        "editorial_review_worker"
    )
    editor_message = next(
        message
        for message in store.agent_messages
        if message.recipient_agent_id == "editor-in-chief"
        and message.payload.get("parent_message_id")
    )
    assert editor_message.result["reviewed_artifact_ids"]
    publishable_artifacts = [
        artifact
        for artifact in store.artifacts
        if artifact.artifact_type
        in {
            ArtifactType.POST,
            ArtifactType.REEL_SCRIPT,
            ArtifactType.SUBSTACK_ARTICLE,
        }
    ]
    for artifact in publishable_artifacts:
        editor_decision = next(
            decision
            for decision in artifact.reviewer_decisions
            if decision.get("reviewer_agent_id") == "editor-in-chief"
            and decision.get("workflow") == "editorial_review_worker_v1"
        )
        assert editor_decision["status"] == ReviewDecisionStatus.NEEDS_REVISION.value
        assert "claim_missing_accepted_retrieval_evidence" in editor_decision[
            "blocking_issues"
        ]
        assert editor_decision["accepted_retrieval_source_ids"] == [
            str(store.sources[1].source_id)
        ]

    readiness = asyncio.run(
        PublishReadinessWorkflow(store).run(
            content_result.run_id,
            PublishReadinessRequest(open_feedback_gate=False),
        )
    )
    assert readiness.status == PublishReadinessStatus.BLOCKED
    assert "claim_missing_accepted_retrieval_evidence" in readiness.blocking_issues
    assert "weak_source_records" in readiness.blocking_issues
    assert any(
        "accepted retrieval evidence" in action
        for action in readiness.recommended_next_actions
    )


