def test_agent_worker_context_summary_includes_project_memory_policy():
    store = FakeStore()
    for content in [
        "Memory retrieval evaluation should guide agent-specific context policy.",
        "Graph-neighbor context needs review before it changes policy.",
    ]:
        asyncio.run(
            ProjectMemoryWorkflow(store).record(
                store.run.run_id,
                ProjectMemoryRecordRequest(
                    memory_kind=ProjectMemoryKind.PROJECT_DECISION,
                    content=content,
                    agent_id="knowledge-graph-curator-agent",
                    scope=ProjectMemoryScope.GLOBAL,
                    confidence="high",
                    tags=["agent-context-policy"],
                ),
            )
        )
    message = AgentMessage(
        run_id=store.run.run_id,
        sender_agent_id="product-manager",
        recipient_agent_id="knowledge-graph-curator-agent",
        task_type="audit_memory_policy",
        payload={"topic": "memory retrieval evaluation"},
    )
    asyncio.run(store.record_agent_message(message))

    result = asyncio.run(
        AgentWorker(store).run(
            "knowledge-graph-curator-agent",
            AgentWorkerRunRequest(
                run_id=store.run.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    assert result.processed_tasks[0].generation_mode == "knowledge_graph_curator_worker"
    assert message.result["knowledge_graph"]["node_count"] == 1
    assert message.result["knowledge_graph"]["coverage_gap_count"] == 1
    assert message.result["retrieval_quality_ledger"]["status"] == "blocked"
    context_summary = message.result["context_summary"]
    retrieval = context_summary["project_memory_retrieval"]
    policy = context_summary["project_memory_policy"]
    assert retrieval["memory_count"] == 2
    assert retrieval["seed_memory_count"] == 1
    assert retrieval["related_memory_count"] == 1
    assert retrieval["evaluation"]["precision_risk_count"] == 1
    assert policy["status"] == "needs_precision_review"
    assert policy["graph_neighbors_require_review"] is True
    assert policy["apply_seed_memories_as_policy"] is False
    context_event = next(
        event for event in store.events if event.event_type == "context_packet_built"
    )
    assert context_event.payload["project_memory_policy"]["status"] == (
        "needs_precision_review"
    )


def test_agent_worker_growth_executors_record_distinct_specialist_artifacts():
    store = FakeStore()
    content_result = asyncio.run(
        ContentStudioWorkflow(store).run(
            OrchestrationRequest(
                transcript=(
                    "Create an ELI5 post, reel, and Substack about growth "
                    "packaging."
                ),
                topic="growth packaging",
                require_human_feedback=False,
            )
        )
    )
    asyncio.run(
        AgentWorker(store).run(
            "content-strategist",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )

    platform_result = asyncio.run(
        AgentWorker(store).run(
            "platform-optimization-agent",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )
    assert platform_result.processed_tasks[0].generation_mode == (
        "distribution_package_worker"
    )
    assert platform_result.processed_tasks[0].status == AgentTaskStatus.COMPLETED
    package_artifacts = [
        artifact
        for artifact in store.artifacts
        if artifact.artifact_type == ArtifactType.SOCIAL_PACKAGE
    ]
    assert len(package_artifacts) == 1
    assert package_artifacts[0].provenance["created_by_agent_id"] == (
        "platform-optimization-agent"
    )
    assert package_artifacts[0].content["outreach"]["collaboration_pitch"]
    platform_message = next(
        message
        for message in store.agent_messages
        if message.recipient_agent_id == "platform-optimization-agent"
    )
    assert platform_message.result["distribution_artifact_id"] == str(
        package_artifacts[0].artifact_id
    )

    event_types = [event.event_type for event in store.events]
    assert "distribution_package_built" in event_types

    influencer_result = asyncio.run(
        AgentWorker(store).run(
            "influencer-strategy-agent",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )
    assert influencer_result.processed_tasks[0].generation_mode == (
        "influencer_strategy_worker"
    )
    influencer_message = next(
        message
        for message in store.agent_messages
        if message.recipient_agent_id == "influencer-strategy-agent"
    )
    influencer_strategy = next(
        artifact
        for artifact in store.artifacts
        if artifact.artifact_type == ArtifactType.GROWTH_STRATEGY
        and artifact.provenance["workflow"] == "influencer_strategy_v1"
    )
    assert influencer_message.result["strategy_artifact_id"] == str(
        influencer_strategy.artifact_id
    )
    assert influencer_message.result["distribution_artifact_id"] == str(
        package_artifacts[0].artifact_id
    )
    assert influencer_strategy.provenance["created_by_agent_id"] == (
        "influencer-strategy-agent"
    )
    assert influencer_strategy.content["distribution_artifact_id"] == str(
        package_artifacts[0].artifact_id
    )
    assert influencer_strategy.content["audience_segments"]
    assert influencer_strategy.content["hashtag_strategy"]["primary"]
    assert influencer_strategy.content["keyword_strategy"]["primary"]
    assert influencer_strategy.content["creator_packaging"]["hook_angles"]
    assert influencer_strategy.content["do_not_say"]
    assert influencer_strategy.source_ids

    outreach_result = asyncio.run(
        AgentWorker(store).run(
            "outreach-agent",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )
    assert outreach_result.processed_tasks[0].generation_mode == (
        "outreach_strategy_worker"
    )
    outreach_message = next(
        message
        for message in store.agent_messages
        if message.recipient_agent_id == "outreach-agent"
    )
    outreach_strategy = next(
        artifact
        for artifact in store.artifacts
        if artifact.artifact_type == ArtifactType.GROWTH_STRATEGY
        and artifact.provenance["workflow"] == "outreach_strategy_v1"
    )
    assert outreach_message.result["strategy_artifact_id"] == str(
        outreach_strategy.artifact_id
    )
    assert outreach_message.result["distribution_artifact_id"] == str(
        package_artifacts[0].artifact_id
    )
    assert outreach_strategy.provenance["created_by_agent_id"] == "outreach-agent"
    assert outreach_strategy.content["community_targets"]
    assert outreach_strategy.content["collaboration_pitches"]
    assert outreach_strategy.content["engagement_prompts"]
    assert outreach_strategy.content["risk_checks"]
    assert outreach_strategy.source_ids
    assert len(
        [
            artifact
            for artifact in store.artifacts
            if artifact.artifact_type == ArtifactType.SOCIAL_PACKAGE
            and artifact.provenance["workflow"] == "distribution_package_v1"
        ]
    ) == 1
    assert len(
        [
            artifact
            for artifact in store.artifacts
            if artifact.artifact_type == ArtifactType.GROWTH_STRATEGY
        ]
    ) == 2

    asyncio.run(
        store.authorize_agent_message_retry(
            influencer_message.message_id,
            agent_id="agent-harness-engineer",
            reason="Verify growth strategy artifact replay is idempotent.",
        )
    )
    influencer_replay = asyncio.run(
        AgentWorker(store).run(
            "influencer-strategy-agent",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )
    assert influencer_replay.processed_tasks[0].generation_mode == (
        "influencer_strategy_worker"
    )
    influencer_replay_message = asyncio.run(
        store.get_agent_message(influencer_message.message_id)
    )
    assert influencer_replay_message.result["reused_existing"] is True
    assert len(
        [
            artifact
            for artifact in store.artifacts
            if artifact.artifact_type == ArtifactType.GROWTH_STRATEGY
            and artifact.provenance["workflow"] == "influencer_strategy_v1"
        ]
    ) == 1
    event_types = [event.event_type for event in store.events]
    assert "influencer_strategy_recorded" in event_types
    assert "outreach_strategy_recorded" in event_types


