def test_source_repair_updates_growth_strategy_source_dependencies():
    store = FakeStore()
    content_result = asyncio.run(
        ContentStudioWorkflow(store).run(
            OrchestrationRequest(
                transcript="Create source-backed content about growth repair.",
                topic="growth repair",
                require_human_feedback=False,
            )
        )
    )
    asyncio.run(
        AgentWorker(store).run(
            "content-strategist",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )
    asyncio.run(
        AgentWorker(store).run(
            "influencer-strategy-agent",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )
    growth_strategy = next(
        artifact
        for artifact in store.artifacts
        if artifact.artifact_type == ArtifactType.GROWTH_STRATEGY
    )
    original_strategy_source_ids = set(growth_strategy.source_ids)

    worker = AgentWorker(
        store,
        ContentWorkflowServices(search_provider=FakeSearchProvider()),
    )
    research_result = asyncio.run(
        worker.run(
            "web-research-agent",
            AgentWorkerRunRequest(
                run_id=content_result.run_id,
                max_tasks=1,
                use_gemma=False,
            ),
        )
    )
    repaired_strategy = next(
        artifact
        for artifact in store.artifacts
        if artifact.artifact_id == growth_strategy.artifact_id
    )
    web_message = next(
        message
        for message in store.agent_messages
        if message.recipient_agent_id == "web-research-agent"
    )

    assert research_result.processed_tasks[0].generation_mode == "web_search_provider"
    assert str(growth_strategy.artifact_id) in web_message.result["source_repair"][
        "artifact_ids"
    ]
    assert set(repaired_strategy.source_ids) != original_strategy_source_ids
    assert repaired_strategy.provenance["source_ids"] == [
        str(source_id) for source_id in repaired_strategy.source_ids
    ]
    assert repaired_strategy.content["source_ids"] == [
        str(source_id) for source_id in repaired_strategy.source_ids
    ]
    assert repaired_strategy.content["source_dependencies"]


