        launch_response = client.post(
            f"/api/runs/{run_id}/autopilot-launch",
            json={
                "profile_name": "Autopilot API smoke",
                "agent_ids": ["web-research-agent"],
                "max_tasks_per_agent": 1,
                "max_rounds": 1,
                "run_first_heartbeat": True,
                "record_artifact": True,
            },
        )

        assert launch_response.status_code == 200
        payload = launch_response.json()
        profile_id = payload["profile"]["profile_id"]
        assert payload["created_profile"] is True
        assert payload["reused_profile"] is False
        assert payload["started_profile"] is True
        assert payload["profile"]["status"] == WorkerProfileStatus.ACTIVE.value
        assert payload["profile"]["execution_mode"] == "autonomous_pass"
        assert payload["heartbeat_result"]["skipped"] is False
        assert payload["heartbeat_result"]["autonomous_pass_result"]["event_id"]
        assert payload["heartbeat_result"]["heartbeat_ledger_artifact"]["artifact_id"]
        assert payload["launch_ledger_artifact"]["artifact_type"] == (
            ArtifactType.AUTOPILOT_LAUNCH_LEDGER.value
        )
        assert payload["launch_ledger_artifact"]["content"]["heartbeat"][
            "state"
        ] == "completed"
        assert payload["launch_ledger_artifact"]["content"]["linked_artifacts"][
            "heartbeat_ledger_artifact_id"
        ] == payload["heartbeat_result"]["heartbeat_ledger_artifact"]["artifact_id"]
        assert payload["event_id"]

        event_types = [event.event_type for event in store.events]
        assert "worker_profile_created" in event_types
        assert "worker_profile_heartbeat" in event_types
        assert store.events[-1].event_type == "autopilot_launch_recorded"
        assert store.events[-1].payload["profile_id"] == profile_id
        assert store.events[-1].payload["heartbeat_state"] == "completed"

        reuse_response = client.post(
            f"/api/runs/{run_id}/autopilot-launch",
            json={
                "profile_name": "Autopilot API smoke",
                "run_first_heartbeat": False,
                "record_artifact": True,
            },
        )

        assert reuse_response.status_code == 200
        reuse_payload = reuse_response.json()
        assert reuse_payload["profile"]["profile_id"] == profile_id
        assert reuse_payload["created_profile"] is False
        assert reuse_payload["reused_profile"] is True
        assert reuse_payload["started_profile"] is False
        assert reuse_payload["heartbeat_result"] is None
        assert reuse_payload["launch_ledger_artifact"]["content"]["heartbeat"][
            "state"
        ] == "not_run"
