def test_worker_profile_heartbeat_opens_project_memory_policy_gate():
    store = FakeStore()

    async def override_store():
        return store

    app.dependency_overrides[get_store] = override_store
    try:
        client = TestClient(app)
        orchestration_response = client.post(
            "/api/orchestrations/content-studio",
            json={
                "transcript": "Create content about realtime studio cockpit.",
                "topic": "realtime studio cockpit",
                "require_human_feedback": False,
            },
        )
        assert orchestration_response.status_code == 200
        run_id = UUID(orchestration_response.json()["run_id"])
        for content in [
            "Realtime studio cockpit requires seed confirmation before always-on execution.",
            "Neighbor outreach heuristics require review before autonomous continuation.",
        ]:
            asyncio.run(
                ProjectMemoryWorkflow(store).record(
                    run_id,
                    ProjectMemoryRecordRequest(
                        memory_kind=ProjectMemoryKind.PROJECT_DECISION,
                        content=content,
                        agent_id="agent-harness-engineer",
                        scope=ProjectMemoryScope.GLOBAL,
                        confidence="high",
                        tags=["shared-context"],
                    ),
                )
            )
        create_response = client.post(
            f"/api/runs/{run_id}/worker-profiles",
            json={
                "name": "Project memory gated profile",
                "agent_ids": ["web-research-agent"],
                "max_tasks_per_agent": 1,
                "max_rounds": 1,
                "status": "active",
            },
        )
        assert create_response.status_code == 200
        profile_id = create_response.json()["profile_id"]

        heartbeat_response = client.post(
            f"/api/worker-profiles/{profile_id}/heartbeat"
        )

        assert heartbeat_response.status_code == 200
        payload = heartbeat_response.json()
        assert payload["skipped"] is True
        assert payload["skipped_reason"] == (
            "project_memory_policy_confirmation_required"
        )
        assert payload["resume_plan"]["resume_allowed"] is False
        assert payload["resume_plan"]["blocked_reasons"] == [
            "waiting_for_human",
            "open_human_feedback",
        ]
        assert payload["cycle_result"] is None
        assert payload["autonomous_pass_result"] is None
        assert payload["feedback_resolution_ledger"]["status"] == "blocked"
        assert payload["feedback_resolution_ledger"]["open_feedback_count"] == 1
        blocked_reasons = [
            "project_memory_policy_confirmation_required",
            "project_memory_policy_needs_precision_review",
        ]
        assert payload["heartbeat_ledger_artifact"]["content"][
            "blocked_reasons"
        ] == blocked_reasons
        project_memory_metrics = payload["heartbeat_ledger_artifact"]["content"][
            "metrics"
        ]["project_memory_retrieval"]
        assert project_memory_metrics["memory_count"] == 2
        assert project_memory_metrics["precision_risk_count"] == 1
        assert project_memory_metrics["policy_status"] == "needs_precision_review"
        assert store.run.status == RunStatus.WAITING_FOR_HUMAN
        assert len(store.feedback) == 1
        feedback = store.feedback[0]
        assert feedback.metadata["gate"] == "project_memory_policy_confirmation"
        assert feedback.metadata["profile_id"] == profile_id
        assert feedback.metadata["project_memory_policy_status"] == (
            "needs_precision_review"
        )
        assert feedback.metadata["precision_risk_count"] == 1

        event_types = [event.event_type for event in store.events]
        assert "agent_worker_task_completed" not in event_types
        assert "human_feedback_gate_opened" in event_types
        assert store.events[-1].event_type == "worker_profile_heartbeat_blocked"
        assert store.events[-1].payload["skipped_reason"] == (
            "project_memory_policy_confirmation_required"
        )
        assert store.events[-1].payload["blocked_reasons"] == blocked_reasons
        assert store.events[-1].payload["project_memory_policy_status"] == (
            "needs_precision_review"
        )

        second_heartbeat_response = client.post(
            f"/api/worker-profiles/{profile_id}/heartbeat"
        )

        assert second_heartbeat_response.status_code == 200
        assert second_heartbeat_response.json()["skipped"] is True
        assert second_heartbeat_response.json()["skipped_reason"] == (
            "resume_plan_blocked"
        )
        assert len(store.feedback) == 1
    finally:
        app.dependency_overrides.clear()


