def test_revision_loop_uses_gemma_provider_when_configured():
    store = FakeStore()
    content_workflow = ContentStudioWorkflow(store)
    content_result = asyncio.run(
        content_workflow.run(
            OrchestrationRequest(
                transcript=(
                    "Draft a grounded post, reel, and Substack about agent "
                    "feedback loops."
                ),
                topic="agent feedback loops",
                require_human_feedback=True,
            )
        )
    )

    revision_workflow = RevisionWorkflow(
        store,
        ContentWorkflowServices(gemma_provider=FakeGemmaProvider()),
    )
    revision_result = asyncio.run(
        revision_workflow.run(
            content_result.run_id,
            RevisionRequest(
                feedback_text="Make the revision sound more conversational.",
                require_human_feedback=False,
            ),
        )
    )

    assert revision_result.feedback_gate_opened is False
    revised_artifacts = [
        artifact
        for artifact in store.artifacts
        if artifact.provenance.get("workflow") == "feedback_revision_v1"
    ]
    assert len(revised_artifacts) == 3
    assert revised_artifacts[0].content["generation_mode"] == "gemma_provider"
    assert "Gemma-created draft" in revised_artifacts[0].content["draft"]
    event_types = [event.event_type for event in store.events]
    assert event_types.count("gemma_revision_completed") == 3
    assert "revision_loop_completed" in event_types
    assert store.run.status == RunStatus.COMPLETED


def _write_fake_voice_edge_for_runtime_readiness(tmp_path):
    fake_binary = tmp_path / "voice-edge"
    fake_binary.write_text(
        """#!/usr/bin/env python3
import json
import sys

def response(payload):
    response_id = payload.get("response_id") or "voice-edge-preflight"
    ack = {
        "response_id": response_id,
        "reason": payload.get("reason") or "startup preflight",
        "drop_outbound_audio": True,
        "cancel_gemma": True,
        "clear_kokoro_buffers": True,
        "stop_livekit_audio": True,
    }
    return {
        "request_id": payload.get("request_id"),
        "session_id": payload["session_id"],
        "events": [{
            "event_type": "voice_edge_cancellation_acknowledged",
            "response_id": response_id,
            "cancellation": ack,
        }],
        "final_state": {"cancellation_acknowledged": True},
    }

for line in sys.stdin:
    if line.strip():
        print(json.dumps(response(json.loads(line))), flush=True)
""",
        encoding="utf-8",
    )
    os.chmod(fake_binary, 0o755)
    return fake_binary
